def brand_logo_html() -> str:
    try:
        data = BRAND_LOGO_PATH.read_bytes()
    except OSError:
        return ROXY_LOGO_SVG.strip()
    encoded = base64.b64encode(data).decode("ascii")
    return f'<img class="brand-logo-img" src="data:image/png;base64,{encoded}" alt="Grau Service LLC logo"/>'


def roxy_avatar_html(state: str = "ready", variant: str = "mini", label: str = "Roxy AI") -> str:
    path = ROXY_AVATAR_VARIANT_PATHS.get(variant, ROXY_AVATAR_PATH)
    try:
        data = path.read_bytes()
    except OSError:
        return ROXY_LOGO_SVG.strip()
    encoded = base64.b64encode(data).decode("ascii")
    safe_state = html.escape(str(state or "ready"))
    safe_label = html.escape(str(label or "Roxy AI"))
    return (
        f'<div class="roxy-avatar roxy-avatar-{safe_state}" title="{safe_label}">'
        f'<img src="data:image/jpeg;base64,{encoded}" alt="{safe_label}"/>'
        f'<span>{safe_state}</span>'
        f"</div>"
    )


