def run_video_learning_ingest(limit: int = 1, transcribe: bool = False) -> tuple[bool, str]:
    script = project_path("tools/video_learning_ingest.py")
    if not script.exists():
        return False, "No encuentro `tools/video_learning_ingest.py`."
    cmd = [sys.executable, str(script), "--limit", str(max(1, int(limit))), "--idle-review"]
    archive_dir = Path("/Volumes/RoxyData/RoxyVideosAnalizados")
    if archive_dir.parent.exists():
        cmd.extend(["--archive-dir", str(archive_dir)])
    if transcribe:
        cmd.extend(["--transcribe", "--model-size", "tiny"])
    try:
        proc = subprocess.run(
            cmd,
            cwd=str(project_path(".")),
            text=True,
            capture_output=True,
            timeout=60 * 20,
        )
    except subprocess.TimeoutExpired:
        return False, "El escaneo tomo demasiado tiempo. Roxy lo deja para el proceso automatico."
    except Exception as exc:
        return False, f"No se pudo ejecutar el escaneo: {exc}"
    output = "\n".join(part for part in [proc.stdout.strip(), proc.stderr.strip()] if part).strip()
    return proc.returncode == 0, output or "Escaneo terminado sin salida."


