def normalize_roxy_module(value: Any, default: str = "acciones-operar") -> str:
    text = safe_key(value).replace("_", "-")
    aliases = {
        "accion": "acciones-operar",
        "acciones": "acciones-operar",
        "acciones-operar": "acciones-operar",
        "stock": "acciones-operar",
        "stocks": "acciones-operar",
        "crypto": "crypto-20m",
        "cripto": "crypto-20m",
        "crypto-trabajar": "crypto-20m",
        "criptomonedas": "crypto-20m",
        "crypto-20": "crypto-20m",
        "crypto-20m": "crypto-20m",
        "20m": "crypto-20m",
        "20-minutos": "crypto-20m",
        "crypto-2h": "crypto-2h",
        "2h": "crypto-2h",
        "crypto-daily": "crypto-daily",
        "daily": "crypto-daily",
        "class": "classroom",
        "classes": "classroom",
        "classes-room": "classroom",
        "classroom": "classroom",
    }
    valid = {item["slug"] for item in ROXY_COMMAND_MODULES}
    return aliases.get(text, text if text in valid else default)


def roxy_module_by_slug(slug: Any) -> dict[str, str]:
    normalized = normalize_roxy_module(slug)
    for item in ROXY_COMMAND_MODULES:
        if item["slug"] == normalized:
            return item
    return ROXY_COMMAND_MODULES[0]


def apply_roxy_text_command(command: Any) -> bool:
    text = normalize_roxy_command_text(command)
    if not text:
        return False
    symbol = symbol_from_roxy_command(command)
    if symbol:
        apply_roxy_navigation_target(
            page="Activo",
            symbol=symbol,
            market="crypto" if "/" in symbol else "stock",
            message=f"Roxy cargo {symbol} en la grafica.",
        )
        return True
    if any(term in text for term in ["crypto", "cripto", "bitcoin", "btc"]):
        st.session_state["roxy_active_module"] = "crypto-trabajar"
        apply_roxy_navigation_target(
            page="Dashboard",
            symbol="BTC/USD",
            market="crypto",
            budget_scope="Crypto",
            message="Roxy abrio oportunidades de crypto.",
        )
        return True
    if any(term in text for term in ["accion", "acciones", "stock", "stocks", "oportunidad", "oportunidades"]):
        st.session_state["roxy_active_module"] = "acciones-operar"
        apply_roxy_navigation_target(
            page="Dashboard",
            symbol=st.session_state.get("command_symbol") or "AAPL",
            market="stock",
            budget_scope="Acciones",
            message="Roxy abrio oportunidades de acciones.",
        )
        return True
    if "opcion" in text or "opciones" in text:
        st.session_state["roxy_active_module"] = "acciones-operar"
        apply_roxy_navigation_target(page="Dashboard", budget_scope="Acciones", message="Roxy abrio acciones.")
        return True
    if "capital" in text or "riesgo" in text:
        st.session_state["roxy_active_module"] = "capital-riesgo"
        apply_roxy_navigation_target(page="Dashboard", message="Roxy abrio capital y riesgo.")
        return True
    if "estudio" in text or "manual" in text:
        apply_roxy_navigation_target(page="Estudios", message="Roxy abrio estudios.")
        return True
    if "roxy" in text or "voz" in text or "ia" in text:
        apply_roxy_navigation_target(page="Roxy IA", message="Roxy abrio su panel IA.")
        return True
    return False


def command_state_from_query_params(
    params: Any,
    default_symbol: str = "AAPL",
    *,
    persisted_state: dict[str, Any] | None = None,
) -> dict[str, str]:
    persisted_state = persisted_state or {}
    symbol = (
        first_query_param_value(params, "symbol")
        or str(persisted_state.get("symbol") or "").strip()
        or str(default_symbol or "AAPL").strip()
        or "AAPL"
    )
    symbol = symbol.upper()
    market = normalize_command_market(
        first_query_param_value(params, "market") or persisted_state.get("market"), symbol
    )
    timeframe = normalize_command_timeframe(first_query_param_value(params, "tf") or persisted_state.get("timeframe"))
    page = normalize_focused_page(first_query_param_value(params, "view") or persisted_state.get("page"))
    return {"symbol": symbol, "market": market, "timeframe": timeframe, "page": page}


def sync_dashboard_query_params(
    params: Any,
    *,
    symbol: Any,
    market: Any,
    timeframe: Any,
    page: Any,
) -> bool:
    symbol_value = str(symbol or "").strip().upper() or "AAPL"
    desired = {
        "symbol": symbol_value,
        "market": normalize_command_market(market, symbol_value),
        "tf": normalize_command_timeframe(timeframe),
        "view": normalize_focused_page(page),
    }
    changed = False
    for key, value in desired.items():
        if first_query_param_value(params, key) != value:
            params[key] = value
            changed = True
    return changed


def hydrate_focused_page_state(params: Any, session_state: Any, default_symbol: str = "AAPL") -> str:
    query_state = command_state_from_query_params(params, default_symbol, persisted_state=read_dashboard_ui_state())
    session_page = normalize_focused_page(
        getattr(session_state, "get", lambda _key, default=None: default)("roxy_focused_page", ""),
        default="",
    )
    query_page = normalize_focused_page(query_state["page"])
    page = session_page or query_page
    if session_page == "Dashboard" and query_page != "Dashboard":
        page = query_page
    session_state["roxy_focused_page"] = page
    session_state["roxy_last_selected_page"] = page
    return page


def current_focused_page_state(params: Any, session_state: Any, default_symbol: str = "AAPL") -> str:
    query_state = command_state_from_query_params(params, default_symbol, persisted_state=read_dashboard_ui_state())
    session_get = getattr(session_state, "get", lambda _key, default=None: default)
    session_page = normalize_focused_page(session_get("roxy_focused_page", ""), default="")
    last_page = normalize_focused_page(session_get("roxy_last_selected_page", ""), default="")
    query_page = normalize_focused_page(query_state["page"])
    page = session_page or last_page or query_page
    if page == "Dashboard" and query_page != "Dashboard":
        page = query_page
    return page


def hydrate_command_state_from_query_params(
    params: Any, session_state: Any, default_symbol: str = "AAPL"
) -> dict[str, str]:
    query_state = command_state_from_query_params(params, default_symbol, persisted_state=read_dashboard_ui_state())
    signature = (
        query_state["symbol"],
        query_state["market"],
        query_state["timeframe"],
        query_state["page"],
    )
    previous_signature = getattr(session_state, "get", lambda _key, default=None: default)(
        "command_query_signature",
        None,
    )
    if previous_signature != signature:
        session_state["command_symbol"] = query_state["symbol"]
        session_state["command_market"] = query_state["market"]
        session_state["command_timeframe"] = query_state["timeframe"]
        session_state["command_query_signature"] = signature
    else:
        session_state.setdefault("command_symbol", query_state["symbol"])
        session_state.setdefault("command_market", query_state["market"])
        session_state.setdefault("command_timeframe", query_state["timeframe"])
    return query_state


def persist_focused_page_query_param() -> None:
    page = normalize_focused_page(
        st.session_state.get("roxy_focused_page") or st.session_state.get("roxy_last_selected_page") or "Dashboard"
    )
    st.session_state["roxy_last_selected_page"] = page
    if first_query_param_value(st.query_params, "view") != page:
        st.query_params["view"] = page
    symbol = st.session_state.get("command_symbol", first_query_param_value(st.query_params, "symbol") or "AAPL")
    write_dashboard_ui_state(
        symbol=symbol,
        market=st.session_state.get(
            "command_market",
            normalize_command_market(first_query_param_value(st.query_params, "market"), symbol),
        ),
        timeframe=st.session_state.get("command_timeframe", first_query_param_value(st.query_params, "tf") or "1h"),
        page=page,
    )


def persist_command_query_params() -> None:
    symbol = str(st.session_state.get("command_symbol", "AAPL") or "AAPL").strip() or "AAPL"
    st.session_state["command_symbol"] = symbol
    market = normalize_command_market(st.session_state.get("command_market"), symbol)
    timeframe = normalize_command_timeframe(st.session_state.get("command_timeframe", "1h"))
    page = (
        str(
            st.session_state.get(
                "roxy_focused_page",
                first_query_param_value(st.query_params, "view") or "Dashboard",
            )
            or "Dashboard"
        ).strip()
        or "Dashboard"
    )
    st.session_state["command_market"] = market
    st.session_state["command_timeframe"] = timeframe
    sync_dashboard_query_params(
        st.query_params,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        page=page,
    )
    state = command_state_from_query_params(st.query_params, symbol)
    st.session_state["command_query_signature"] = (
        state["symbol"],
        state["market"],
        state["timeframe"],
        state["page"],
    )
    write_dashboard_ui_state(
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        page=page,
    )


def persist_command_symbol_query_params() -> None:
    symbol = str(st.session_state.get("command_symbol", "AAPL") or "AAPL").strip().upper()
    st.session_state["command_symbol"] = symbol
    if "/" in symbol:
        st.session_state["command_market"] = "crypto"
    else:
        st.session_state["command_market"] = "stock"
    persist_command_query_params()


def apply_pending_command_state() -> bool:
    changed = False
    pending_symbol = st.session_state.pop("command_symbol_pending", None)
    if pending_symbol:
        st.session_state["command_symbol"] = str(pending_symbol).strip().upper()
        changed = True
    pending_market = st.session_state.pop("command_market_pending", None)
    if pending_market:
        st.session_state["command_market"] = normalize_command_market(
            pending_market, st.session_state.get("command_symbol")
        )
        changed = True
    pending_timeframe = st.session_state.pop("command_timeframe_pending", None)
    if pending_timeframe:
        st.session_state["command_timeframe"] = normalize_command_timeframe(pending_timeframe)
        changed = True
    if changed:
        persist_command_query_params()
    return changed


def resolve_study_strategy_choice(
    strategy_names: list[str],
    preferred: str,
    *,
    requested: str | None = None,
    current: str | None = None,
) -> str:
    if requested in strategy_names:
        return str(requested)
    if current in strategy_names:
        return str(current)
    if preferred in strategy_names:
        return preferred
    return strategy_names[0] if strategy_names else "-"


def chart_strategy_summary(
    setup: dict,
    confluence: dict | None,
    brief: dict | None,
    chart_df: pd.DataFrame,
) -> dict[str, str]:
    confluence = confluence or {}
    brief = brief or {}
    setup_name = text_display(setup.get("setup") or confluence.get("trigger_setup"))
    family = strategy_family_from_setup(setup_name, trend_setup=confluence.get("trend_setup"))
    action = human_trade_action(brief) if brief else action_label(confluence.get("signal"))
    tone = "buy" if action in {"Operar", "Comprar"} else "avoid" if action in {"No operar", "Evitar"} else "watch"
    latest = chart_df.iloc[-1].to_dict() if not chart_df.empty else {}
    sma20 = safe_float(latest.get("sma20") or setup.get("sma20"))
    sma40 = safe_float(latest.get("sma40") or setup.get("sma40"))
    sma200 = safe_float(latest.get("sma200") or setup.get("sma200"))
    risk = safe_float(brief.get("risk_pct") or confluence.get("risk_pct")) or setup_risk_pct(setup)
    target = safe_float(brief.get("recommended_target_pct") or confluence.get("recommended_target_pct"))

    watch_plan = brief.get("watch_plan") if isinstance(brief, dict) else {}
    movement = text_display((watch_plan or {}).get("movement"))
    if movement == "-":
        if family == "Pullback":
            movement = f"Esperar rebote en SMA20/SMA40 ({num_display(sma20)} - {num_display(sma40)}) con vela verde."
        elif family == "Cruce de medias":
            movement = "Esperar que SMA20 cruce y sostenga sobre SMA40 con confirmacion 1h."
        elif family == "Canal alcista":
            movement = "Esperar continuacion sobre SMA20 sin perder estructura 20/40/100/200."
        elif family == "Canal lateral":
            movement = "Esperar rebote en soporte o ruptura de resistencia con volumen."
        elif family == "Tendencia bajista":
            movement = f"No buscar calls hasta recuperar SMA200 {num_display(sma200)}."
        else:
            movement = "Esperar 15m en BUY, 1h confirmando, volumen y riesgo medible."

    if action in {"Operar", "Comprar"}:
        decision_note = "Setup listo si respeta entrada, stop y volumen."
    elif action in {"No operar", "Evitar"}:
        decision_note = "No entrar hasta que cambie la estructura."
    else:
        decision_note = "Vigilar sin ejecutar; falta una confirmacion."

    return {
        "family": family,
        "setup": setup_name,
        "action": action,
        "tone": tone,
        "movement": movement,
        "decision_note": decision_note,
        "risk": pct_display(risk),
        "target": pct_display(target),
    }


def render_chart_strategy_summary(
    setup: dict,
    confluence: dict | None,
    brief: dict | None,
    chart_df: pd.DataFrame,
) -> None:
    summary = chart_strategy_summary(setup, confluence, brief, chart_df)
    tone = summary["tone"] if summary["tone"] in {"buy", "watch", "avoid"} else "neutral"
    st.markdown(
        f"""
        <div class="chart-context chart-context-{tone}">
            <div>
                <div class="chart-context-kicker">Lectura de estrategia</div>
                <div class="chart-context-title">{html.escape(summary["family"])} · {html.escape(summary["action"])}</div>
                <div class="chart-context-text">{html.escape(summary["movement"])}</div>
            </div>
            <div class="chart-context-grid">
                <span>Setup <strong>{html.escape(summary["setup"])}</strong></span>
                <span>Riesgo <strong>{html.escape(summary["risk"])}</strong></span>
                <span>Target <strong>{html.escape(summary["target"])}</strong></span>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )


def compact_score_display(value: Any) -> str:
    score = safe_float(value)
    if score is None:
        return "-"
    if 0 <= score <= 1:
        return pct_display(score)
    if 1 < score <= 100:
        return f"{score:.0f}/100"
    return num_display(score, 2)


def render_operational_trade_snapshot(
    setup: dict,
    confluence: dict | None,
    brief: dict | None,
    chart_df: pd.DataFrame,
    live_price: dict[str, Any] | None = None,
) -> None:
    summary = chart_strategy_summary(setup, confluence, brief, chart_df)
    brief = brief or {}
    confluence = confluence or {}
    targets = command_center_target_prices(brief)
    confidence = (
        brief.get("confidence")
        or brief.get("readiness")
        or brief.get("alert_readiness_score")
        or brief.get("score")
        or brief.get("ai_score")
        or confluence.get("readiness")
        or confluence.get("score")
    )
    live_price = live_price or {}
    live_value = safe_float(live_price.get("price"))
    live_freshness = text_display(live_price.get("freshness"))
    live_age = safe_float(live_price.get("age_seconds"))
    live_label = price_display(live_value) if live_value is not None else live_freshness
    regular_price = safe_float(live_price.get("regular_market_price"))
    post_price = safe_float(live_price.get("post_market_price"))
    pre_price = safe_float(live_price.get("pre_market_price"))
    if regular_price is not None or post_price is not None or pre_price is not None:
        session_parts = []
        if regular_price is not None:
            session_parts.append(f"reg {price_display(regular_price)}")
        if post_price is not None:
            session_parts.append(f"post {price_display(post_price)}")
        if pre_price is not None:
            session_parts.append(f"pre {price_display(pre_price)}")
        live_detail = f"{text_display(live_price.get('source'))} · " + " / ".join(session_parts)
    else:
        live_detail = (
            f"{text_display(live_price.get('source'))} · {int(live_age)}s"
            if live_age is not None
            else text_display(live_price.get("source") or live_price.get("error") or "sin tick")
        )
    live_tone = "buy" if live_freshness == "LIVE" else "watch" if live_freshness == "FRESH" else "avoid"
    pills = [
        ("Tick live", f"{live_label} · {live_detail}", live_tone),
        ("Decisión", summary["action"], summary["tone"]),
        ("Canal / estrategia", summary["family"], summary["tone"]),
        ("Entrada", num_display(brief.get("entry") or confluence.get("entry")), "buy"),
        ("Stop", num_display(brief.get("stop") or confluence.get("stop")), "avoid"),
        ("Salida", num_display(targets.get("target_2")), "watch"),
        ("Riesgo", summary["risk"], "neutral"),
        ("Confianza", compact_score_display(confidence), "neutral"),
    ]
    html_pills = []
    for label, value, tone in pills:
        tone = tone if tone in {"buy", "watch", "avoid", "neutral"} else "neutral"
        html_pills.append(
            f'<span class="ops-snapshot-pill ops-snapshot-{html.escape(tone)}">'
            f"<small>{html.escape(str(label))}</small>"
            f"<strong>{html.escape(text_display(value))}</strong>"
            "</span>"
        )
    st.markdown(
        '<div class="ops-snapshot">' + "".join(html_pills) + "</div>",
        unsafe_allow_html=True,
    )
    session_notice = render_live_price_session_notice(live_price)
    if session_notice:
        st.markdown(session_notice, unsafe_allow_html=True)
    exact_plan = render_exact_entry_plan_panel(brief, confluence, live_price=live_price)
    if exact_plan:
        st.markdown(exact_plan, unsafe_allow_html=True)


def live_price_session_comparison(snapshot: dict[str, Any] | None) -> list[dict[str, Any]]:
    snapshot = snapshot or {}
    primary = safe_float(snapshot.get("price"))
    if primary is None or primary <= 0:
        return []
    rows: list[dict[str, Any]] = []
    for label, key in (
        ("Regular/current", "regular_market_price"),
        ("Post-market", "post_market_price"),
        ("Pre-market", "pre_market_price"),
    ):
        value = safe_float(snapshot.get(key))
        if value is None or value <= 0:
            continue
        diff_pct = (value - primary) / primary
        abs_diff = abs(diff_pct)
        if abs_diff >= 0.002:
            tone = "avoid"
        elif abs_diff >= 0.0005:
            tone = "watch"
        else:
            tone = "buy"
        rows.append(
            {
                "label": label,
                "key": key,
                "price": value,
                "diff_pct": diff_pct,
                "tone": tone,
                "matches_primary": abs_diff < 0.0005,
            }
        )
    return rows


def render_live_price_session_notice(snapshot: dict[str, Any] | None) -> str:
    rows = live_price_session_comparison(snapshot)
    if not rows:
        return ""
    primary = safe_float((snapshot or {}).get("price"))
    source = text_display((snapshot or {}).get("source"))
    has_gap = any(not row["matches_primary"] for row in rows)
    tone = "watch" if has_gap else "buy"
    headline = "Chequeo de precio: Roxy usa el quote principal"
    detail = "Regular/current, pre-market y post-market quedan visibles para detectar diferencias antes de operar."
    if has_gap:
        detail = "Hay diferencia entre sesiones; Roxy no oculta el precio alternativo para evitar operar con una lectura equivocada."
    cards = [
        (
            '<div class="price-session-card price-session-card-neutral">'
            "<span>Precio principal</span>"
            f"<strong>{html.escape(price_display(primary))}</strong>"
            f"<small>{html.escape(source)}</small>"
            "</div>"
        )
    ]
    for row in rows:
        diff_text = "igual al principal" if row["matches_primary"] else f"{row['diff_pct']:+.2%} vs principal"
        cards.append(
            f'<div class="price-session-card price-session-card-{html.escape(row["tone"])}">'
            f"<span>{html.escape(row['label'])}</span>"
            f"<strong>{html.escape(price_display(row['price']))}</strong>"
            f"<small>{html.escape(diff_text)}</small>"
            "</div>"
        )
    return (
        f'<section class="price-session-check price-session-check-{html.escape(tone)}">'
        f"<header><strong>{html.escape(headline)}</strong><span>{html.escape(detail)}</span></header>"
        f'<div>{"".join(cards)}</div>'
        "</section>"
    )


def render_exact_entry_plan_panel(
    brief: dict[str, Any] | None,
    confluence: dict[str, Any] | None = None,
    *,
    live_price: dict[str, Any] | None = None,
) -> str:
    source_row: dict[str, Any] = {}
    if isinstance(confluence, dict):
        source_row.update(confluence)
    if isinstance(brief, dict):
        source_row.update(brief)
    live_value = safe_float((live_price or {}).get("price"))
    if live_value is not None:
        source_row["current_price"] = live_value
        source_row["price"] = live_value
    plan = entry_exit_plan_engine(source_row)
    entry = safe_float(plan.get("entry"))
    stop = safe_float(plan.get("stop"))
    target_2 = safe_float(plan.get("target_2"))
    if entry is None and stop is None and target_2 is None:
        return ""
    tone = text_display(plan.get("tone") or "watch")
    status_label = {
        "READY": "Entrar solo si confirma",
        "WAIT_CONFIRMATION": "Esperar gatillo",
        "BLOCKED": "No operar ahora",
    }.get(text_display(plan.get("plan_status")), text_display(plan.get("plan_status")))
    latest = safe_float(plan.get("latest"))
    distance = safe_float(plan.get("chase_distance_pct"))
    distance_text = f"{distance:+.2%}" if distance is not None else "-"
    rr = safe_float(plan.get("rr_to_2"))
    blockers = plan.get("blockers") if isinstance(plan.get("blockers"), list) else []
    blocker_text = ", ".join(str(item) for item in blockers[:3]) if blockers else "Sin bloqueos criticos medibles."
    cards = [
        ("Ahora", price_display(latest), distance_text),
        ("Entrada", price_display(entry), f"{price_display(plan.get('entry_zone_low'))} - {price_display(plan.get('entry_zone_high'))}"),
        ("Stop", price_display(stop), text_display(plan.get("invalidation_rule"))),
        ("Target 2%", price_display(target_2), f"R:R {rr:.2f}R" if rr is not None else "R:R -"),
        ("Target 5%", price_display(plan.get("target_5")), "salida parcial"),
        ("Target 10%", price_display(plan.get("target_10")), "runner"),
    ]
    card_html = "".join(
        '<div class="exact-entry-card">'
        f"<span>{html.escape(label)}</span>"
        f"<strong>{html.escape(value)}</strong>"
        f"<small>{html.escape(detail)}</small>"
        "</div>"
        for label, value, detail in cards
    )
    return (
        f'<section class="exact-entry-plan exact-entry-plan-{html.escape(tone)}">'
        f"<header><strong>Entrada exacta</strong><span>{html.escape(status_label)} · {html.escape(blocker_text)}</span></header>"
        f'<div class="exact-entry-grid">{card_html}</div>'
        f'<p>{html.escape(text_display(plan.get("confirmation_rule")))} {html.escape(text_display(plan.get("do_not_chase_rule")))}</p>'
        "</section>"
    )


def command_center_target_prices(row: dict[str, Any]) -> dict[str, float | None]:
    entry = safe_float(row.get("entry"))
    targets = {
        "target_2": safe_float(row.get("target_2pct_price") or row.get("target_2")),
        "target_5": safe_float(row.get("target_5pct_price") or row.get("target_5")),
        "target_10": safe_float(row.get("target_10pct_price") or row.get("target_10")),
    }
    ladder = row.get("target_ladder") or []
    for item in ladder if isinstance(ladder, list) else []:
        label = str(item.get("target") or "")
        price = safe_float(item.get("target_price"))
        if price is None:
            continue
        if label == "2%":
            targets["target_2"] = price
        elif label == "5%":
            targets["target_5"] = price
        elif label == "10%":
            targets["target_10"] = price
    if entry is not None:
        targets["target_2"] = targets["target_2"] if targets["target_2"] is not None else entry * 1.02
        targets["target_5"] = targets["target_5"] if targets["target_5"] is not None else entry * 1.05
        targets["target_10"] = targets["target_10"] if targets["target_10"] is not None else entry * 1.10
    return targets


def command_center_checklist_rows(row: dict[str, Any]) -> list[dict[str, str]]:
    checks = row.get("condition_checks")
    rows: list[dict[str, str]] = []

    def add(label: str, passed: bool | None, detail: Any = "-") -> None:
        if passed is True:
            status = "OK"
            tone = "buy"
        elif passed is False:
            status = "Falta"
            tone = "avoid"
        else:
            status = "Pendiente"
            tone = "watch"
        rows.append(
            {
                "label": label,
                "status": status,
                "tone": tone,
                "detail": text_display(detail),
            }
        )

    if isinstance(checks, list) and checks:
        for item in checks[:7]:
            passed_value = item.get("passed")
            add(
                str(item.get("label") or "Condicion"),
                passed_value if isinstance(passed_value, bool) else None,
                item.get("detail"),
            )
        return rows

    signal = str(row.get("signal") or "").upper()
    decision = str(row.get("decision") or row.get("trade_decision") or "").upper()
    trade_ready = opportunity_is_trade_ready(row)
    risk = safe_float(row.get("risk_pct"))
    target = safe_float(row.get("recommended_target_pct") or row.get("target_pct"))
    relative_volume = safe_float(row.get("relative_volume") or row.get("relative_volume_15m"))
    backtest = row.get("backtest_eligible")

    add("1h confirma", True if trade_ready else None, row.get("trend") or row.get("trend_setup") or "Esperando 1h")
    add("15m da entrada", trade_ready if signal else None, decision or signal or "Sin gatillo")
    add(
        "Volumen acompana",
        None if relative_volume is None else relative_volume >= 0.8,
        f"{relative_volume:.2f}x" if relative_volume is not None else "No disponible",
    )
    add("Riesgo bajo", None if risk is None else risk <= 0.035, pct_display(risk))
    add("Target 2% viable", None if target is None else target >= 0.02, pct_display(target))
    if backtest is not None:
        add("Filtro historico", bool(backtest), "Backtest elegible" if bool(backtest) else "No validado")
    return rows


def build_command_center_summary(row: dict[str, Any]) -> dict[str, Any]:
    action = str(row.get("action") or row.get("ai_action") or "").upper()
    signal = str(row.get("signal") or "").upper()
    decision_raw = str(row.get("decision") or row.get("trade_decision") or "").upper()
    if action in {"BUY_STOCK", "WATCH_CALL"} or opportunity_is_trade_ready(row):
        status = "Operar"
        tone = "buy"
    elif action == "NO_TRADE" or signal == "AVOID" or decision_raw.startswith("NO_TRADE"):
        status = "No operar"
        tone = "avoid"
    else:
        status = "Esperar"
        tone = "watch"

    decision = text_display(row.get("decision"))
    if decision == "-":
        decision = human_trade_action(row)
    strategy = text_display(row.get("strategy_family"))
    if strategy == "-":
        strategy = strategy_family_for_row(row)
    reason = text_display(
        (row.get("decision_reason") or {}).get("summary") if isinstance(row.get("decision_reason"), dict) else None
    )
    if reason == "-":
        reason = human_alert_reason(row) or opportunity_reason_label(row)
    movement = text_display(
        (row.get("watch_plan") or {}).get("movement") if isinstance(row.get("watch_plan"), dict) else None
    )
    if movement == "-":
        movement = watch_movement_label(row)
    memory = row.get("memory") or {}
    memory_note = text_display(memory.get("note") if isinstance(memory, dict) else None)
    targets = command_center_target_prices(row)
    return {
        "symbol": text_display(row.get("symbol")).upper(),
        "market": text_display(row.get("market")),
        "timeframe": text_display(row.get("timeframe")),
        "status": status,
        "tone": tone,
        "decision": decision,
        "strategy": strategy,
        "reason": reason,
        "movement": movement,
        "entry": safe_float(row.get("entry")),
        "stop": safe_float(row.get("stop")),
        "risk": safe_float(row.get("risk_pct")),
        "score": safe_float(row.get("score") or row.get("ai_score")),
        "readiness": safe_float(row.get("readiness") or row.get("alert_readiness_score")),
        "target_2": targets["target_2"],
        "target_5": targets["target_5"],
        "target_10": targets["target_10"],
        "memory_note": memory_note,
    }


def render_command_center_panel(
    row: dict[str, Any],
    *,
    platform_ticket: dict | None = None,
    chart_status: dict[str, Any] | None = None,
) -> None:
    summary = build_command_center_summary(row)
    tone = summary["tone"] if summary["tone"] in {"buy", "watch", "avoid"} else "watch"
    platform_name_text = text_display((platform_ticket or {}).get("platform"))
    platform_status_text = platform_status_label((platform_ticket or {}).get("status")) if platform_ticket else "-"
    platform_qty = num_display((platform_ticket or {}).get("quantity"), 4) if platform_ticket else "-"
    chart_status = chart_status or {}
    chart_tone = text_display(chart_status.get("tone") or "neutral")
    if chart_tone not in {"buy", "watch", "avoid", "neutral"}:
        chart_tone = "watch"
    chart_detail_parts = [
        text_display(chart_status.get("gate")),
        text_display(chart_status.get("source")),
    ]
    chart_detail = " | ".join(part for part in chart_detail_parts if part and part != "-") or text_display(
        chart_status.get("detail")
    )
    chart_label = "Grafica actual"
    st.markdown(
        f"""
        <section class="command-center command-center-{html.escape(tone)}">
            <div class="command-main">
                <div class="command-kicker">Oportunidad real</div>
                <h2>{html.escape(summary["symbol"])} · {html.escape(summary["status"])}</h2>
                <p>{html.escape(summary["reason"])}</p>
            </div>
            <div class="command-side">
                <span>Accion Roxy</span>
                <strong>{html.escape(summary["decision"])}</strong>
                <small>{html.escape(summary["strategy"])} · {html.escape(summary["timeframe"])}</small>
            </div>
        </section>
        """,
        unsafe_allow_html=True,
    )
    st.markdown(
        f"""
        <section class="command-quick-strip command-quick-strip-{html.escape(tone)}">
          <div><span>Entrada</span><strong>{html.escape(num_display(summary["entry"]))}</strong></div>
          <div><span>Stop</span><strong>{html.escape(num_display(summary["stop"]))}</strong></div>
          <div><span>Targets</span><strong>{html.escape(num_display(summary["target_2"]))} / {html.escape(num_display(summary["target_5"]))} / {html.escape(num_display(summary["target_10"]))}</strong></div>
          <div><span>Riesgo</span><strong>{html.escape(pct_display(summary["risk"]))}</strong></div>
          <div><span>Plataforma</span><strong>{html.escape(platform_name_text)}</strong><small>{html.escape(platform_status_text)} | Qty {html.escape(platform_qty)}</small></div>
          <div><span>{html.escape(chart_label)}</span><strong>{html.escape(text_display(chart_status.get("headline") or chart_status.get("label")))}</strong><small>{html.escape(chart_detail[:90])}</small></div>
        </section>
        """,
        unsafe_allow_html=True,
    )

    checklist = command_center_checklist_rows(row)
    if checklist:
        with st.expander("Detalles operativos: checklist, espera y validaciones", expanded=False):
            render_kpi_card("Esperamos", summary["movement"], tone="watch")
            cards = []
            for item in checklist:
                cards.append(
                    f'<div class="command-check command-check-{html.escape(item["tone"])}">'
                    f'<span>{html.escape(item["label"])}</span>'
                    f'<strong>{html.escape(item["status"])}</strong>'
                    f'<small>{html.escape(item["detail"])}</small>'
                    "</div>"
                )
            st.markdown(
                '<div class="command-checklist">' + "".join(cards) + "</div>",
                unsafe_allow_html=True,
            )
    if summary["memory_note"] != "-":
        st.caption("Memoria Roxy: " + summary["memory_note"])


def load_symbol_trade_context(
    *,
    symbol: str,
    market: str,
    timeframe: str,
    confluence_df: pd.DataFrame,
    options_df: pd.DataFrame,
    account_equity: float,
    risk_per_trade_pct: float,
    memory: dict | None = None,
) -> dict[str, Any]:
    resolved_symbol = resolve_symbol_query(symbol, market)
    try:
        history, data_source = fetch_symbol_history_with_source(resolved_symbol, market=market, timeframe=timeframe)
        chart_df = prepare_symbol_chart_data(history)
        setup = analyze_moving_average_setup(history) if not history.empty else {}
    except Exception as exc:
        history = fetch_direct_yfinance_ohlcv(resolved_symbol, timeframe) if market == "stock" else pd.DataFrame()
        data_source = {
            "provider": "yfinance",
            "source": "yfinance_direct_fallback",
            "mode": "FALLBACK",
            "label": "yfinance directo",
            "detail": f"Ruta principal fallo para {resolved_symbol}: {exc}",
            "fallback": True,
            "fallback_reason": "symbol_context_error",
            "fallback_action": "Confirmar externo antes de operar; no usar como ejecucion real.",
        }
        try:
            chart_df = prepare_symbol_chart_data(history)
            setup = analyze_moving_average_setup(history) if not history.empty else {}
        except Exception:
            chart_df = pd.DataFrame()
            setup = {}
    setup = apply_learned_strategy_brain(chart_df, setup) if setup else setup
    if chart_df.empty or not setup:
        return {
            "symbol": resolved_symbol,
            "chart_df": chart_df,
            "setup": setup,
            "trade_brief": {},
            "data_source": data_source,
        }
    confluence = latest_confluence_row(confluence_df, resolved_symbol)
    trade_brief = build_symbol_trade_brief(
        symbol=resolved_symbol,
        market=market,
        timeframe=timeframe,
        setup=setup,
        confluence=confluence,
        options_df=options_df,
        account_equity=float(account_equity),
        account_risk_pct=float(risk_per_trade_pct),
        memory=memory or load_memory(),
    )
    return {
        "symbol": resolved_symbol,
        "market": market,
        "timeframe": timeframe,
        "history": history,
        "chart_df": chart_df,
        "setup": setup,
        "confluence": confluence,
        "trade_brief": trade_brief,
        "data_source": data_source,
    }


@st.cache_data(ttl=21_600, show_spinner=False)
def load_company_profile(symbol: str, market: str) -> dict[str, Any]:
    clean_symbol = str(symbol or "").strip().upper()
    if not clean_symbol or "/" in clean_symbol or str(market or "").lower() != "stock" or yf is None:
        return {}
    try:
        ticker = yf.Ticker(clean_symbol)
        info = getattr(ticker, "info", None) or {}
    except Exception:
        return {}
    if not isinstance(info, dict):
        return {}
    return {
        key: info.get(key)
        for key in [
            "longName",
            "shortName",
            "sector",
            "industry",
            "country",
            "exchange",
            "fullExchangeName",
            "marketCap",
            "fullTimeEmployees",
            "currentPrice",
            "regularMarketPrice",
            "trailingPE",
            "forwardPE",
            "beta",
            "dividendYield",
            "recommendationKey",
            "targetMeanPrice",
            "fiftyTwoWeekLow",
            "fiftyTwoWeekHigh",
            "website",
            "longBusinessSummary",
        ]
    }


