def candle_reading_label(
    open_value: Any,
    high_value: Any,
    low_value: Any,
    close_value: Any,
    body_pct: Any,
    range_pct: Any,
    upper_wick_pct: Any,
    lower_wick_pct: Any,
) -> str:
    try:
        open_number = float(open_value)
        high_number = float(high_value)
        low_number = float(low_value)
        close_number = float(close_value)
    except (TypeError, ValueError):
        return "Sin lectura"
    if any(pd.isna(value) for value in [open_number, high_number, low_number, close_number]):
        return "Sin lectura"
    if high_number < low_number:
        return "Datos revisar"
    body = safe_float(body_pct) or 0.0
    candle_range = safe_float(range_pct) or 0.0
    upper_wick = safe_float(upper_wick_pct) or 0.0
    lower_wick = safe_float(lower_wick_pct) or 0.0
    is_green = close_number >= open_number
    if candle_range > 0 and body <= candle_range * 0.22:
        return "Indecisión"
    if lower_wick >= max(body * 1.4, 0.0025) and is_green:
        return "Rebote soporte"
    if upper_wick >= max(body * 1.4, 0.0025) and not is_green:
        return "Rechazo arriba"
    if is_green and body >= 0.004:
        return "Impulso alcista"
    if not is_green and body >= 0.004:
        return "Impulso bajista"
    return "Alcista leve" if is_green else "Bajista leve"


def candle_wick_pressure_label(upper_wick_pct: Any, lower_wick_pct: Any, body_pct: Any) -> str:
    upper_wick = safe_float(upper_wick_pct) or 0.0
    lower_wick = safe_float(lower_wick_pct) or 0.0
    body = safe_float(body_pct) or 0.0
    threshold = max(body * 1.15, 0.002)
    if upper_wick >= max(lower_wick * 1.35, threshold):
        return "Oferta arriba"
    if lower_wick >= max(upper_wick * 1.35, threshold):
        return "Demanda abajo"
    if upper_wick >= 0.002 and lower_wick >= 0.002:
        return "Mechas mixtas"
    return "Sin presion clara"


def chart_window_pressure_label(position: Any, upside_pct: Any, downside_pct: Any) -> tuple[str, str, str]:
    position_value = safe_float(position)
    upside_value = safe_float(upside_pct)
    downside_value = safe_float(downside_pct)
    if position_value is None:
        return "neutral", "Rango sin lectura", "Faltan velas suficientes para ubicar el precio."
    if position_value >= 0.82:
        return "avoid", "Presion en techo", "Precio cerca del maximo visible; evita perseguir sin ruptura limpia."
    if position_value <= 0.18:
        return "buy", "Presion en piso", "Precio cerca del soporte visible; buscar rebote confirmado."
    if position_value >= 0.58:
        detail = "Mitad alta del rango; compradores sostienen mientras no pierda medias."
        if upside_value is not None and upside_value <= 0.01:
            detail = "Muy cerca del techo; exigir ruptura y volumen antes de entrar."
        return "buy", "Mitad alta", detail
    if position_value <= 0.42:
        detail = "Mitad baja del rango; esperar recuperacion antes de tomar riesgo."
        if downside_value is not None and abs(downside_value) <= 0.01:
            detail = "Cerca del piso; confirmar defensa de soporte antes de operar."
        return "watch", "Mitad baja", detail
    return "watch", "Rango medio", "Sin ventaja clara; esperar ruptura, rebote o confirmacion de volumen."


def static_live_price_chart_svg(chart_df: pd.DataFrame, *, symbol: str, height: int = 420) -> str:
    if chart_df.empty or not {"ts", "open", "high", "low", "close"}.issubset(chart_df.columns):
        return ""
    window = prepare_chart_window(chart_df).tail(120).copy()
    if window.empty:
        return ""
    for column in ["open", "high", "low", "close", "sma20", "sma200"]:
        if column in window.columns:
            window[column] = pd.to_numeric(window[column], errors="coerce")
    window["ts"] = pd.to_datetime(window["ts"], errors="coerce")
    window = window.dropna(subset=["ts", "open", "high", "low", "close"]).reset_index(drop=True)
    if window.empty:
        return ""

    width = 1000
    height = max(260, min(620, int(height or 420)))
    margin_left = 62
    margin_right = 24
    margin_top = 18
    margin_bottom = 38
    plot_width = width - margin_left - margin_right
    plot_height = height - margin_top - margin_bottom
    low = safe_float(window["low"].min())
    high = safe_float(window["high"].max())
    if low is None or high is None:
        return ""
    if high <= low:
        high = low * 1.01 if low else 1.0
    padding = (high - low) * 0.08
    domain_low = low - padding
    domain_high = high + padding
    domain_span = domain_high - domain_low
    if domain_span <= 0:
        return ""

    def x_pos(idx: int) -> float:
        if len(window) <= 1:
            return margin_left + plot_width / 2
        return margin_left + (plot_width * idx / (len(window) - 1))

    def y_pos(value: Any) -> float:
        number = safe_float(value)
        if number is None:
            return margin_top + plot_height
        return margin_top + ((domain_high - number) / domain_span) * plot_height

    grid_parts: list[str] = []
    for idx in range(5):
        ratio = idx / 4
        price = domain_high - domain_span * ratio
        y = margin_top + plot_height * ratio
        grid_parts.append(
            f'<line x1="{margin_left}" y1="{y:.1f}" x2="{width - margin_right}" y2="{y:.1f}" stroke="rgba(148,163,184,.16)" />'
        )
        grid_parts.append(
            f'<text x="12" y="{y + 4:.1f}" fill="#94a3b8" font-size="12" font-weight="700">{price:.2f}</text>'
        )

    candle_width = max(3.0, min(8.0, plot_width / max(len(window), 1) * 0.58))
    candle_parts: list[str] = []
    for idx, row in window.iterrows():
        open_price = safe_float(row.get("open"))
        high_price = safe_float(row.get("high"))
        low_price = safe_float(row.get("low"))
        close_price = safe_float(row.get("close"))
        if None in (open_price, high_price, low_price, close_price):
            continue
        x = x_pos(idx)
        y_open = y_pos(open_price)
        y_close = y_pos(close_price)
        y_high = y_pos(high_price)
        y_low = y_pos(low_price)
        color = "#22c55e" if close_price >= open_price else "#ef4444"
        body_y = min(y_open, y_close)
        body_h = max(2.0, abs(y_close - y_open))
        candle_parts.append(
            f'<line x1="{x:.1f}" y1="{y_high:.1f}" x2="{x:.1f}" y2="{y_low:.1f}" stroke="{color}" stroke-width="1.35" />'
        )
        candle_parts.append(
            f'<rect x="{x - candle_width / 2:.1f}" y="{body_y:.1f}" width="{candle_width:.1f}" height="{body_h:.1f}" rx="1.4" fill="{color}" opacity=".92" />'
        )

    def line_path(column: str) -> str:
        if column not in window.columns:
            return ""
        points = []
        values = window[column].dropna()
        for idx, value in enumerate(window[column].tolist()):
            number = safe_float(value)
            if number is None:
                continue
            points.append(f"{x_pos(idx):.1f},{y_pos(number):.1f}")
        if len(points) < 2 or values.empty:
            return ""
        color = "#22c55e" if column == "sma20" else "#ef4444"
        label = "SMA20" if column == "sma20" else "SMA200"
        return (
            f'<polyline points="{" ".join(points)}" fill="none" stroke="{color}" stroke-width="1.8" opacity=".9" />'
            f'<text x="{width - margin_right - 74}" y="{y_pos(values.iloc[-1]) - 6:.1f}" '
            f'fill="{color}" font-size="11" font-weight="800">{label}</text>'
        )

    first_ts = pd.Timestamp(window["ts"].iloc[0]).strftime("%m/%d %H:%M")
    last_ts = pd.Timestamp(window["ts"].iloc[-1]).strftime("%m/%d %H:%M")
    latest = window.iloc[-1]
    latest_close = safe_float(latest.get("close"))
    latest_open = safe_float(latest.get("open"))
    latest_change = (
        (latest_close - latest_open) / latest_open
        if latest_close is not None and latest_open not in (None, 0)
        else None
    )
    safe_symbol = html.escape(text_display(symbol))
    summary = html.escape(f"C {num_display(latest_close, 2)} | vela {pct_display(latest_change)}")
    return f"""
    <section class="static-live-chart" aria-label="Grafica live {safe_symbol}">
      <svg viewBox="0 0 {width} {height}" role="img" width="100%" height="{height}">
        <rect x="0" y="0" width="{width}" height="{height}" rx="8" fill="#0b1220" />
        <rect x="{margin_left}" y="{margin_top}" width="{plot_width}" height="{plot_height}" rx="6" fill="#020617" opacity=".42" />
        {''.join(grid_parts)}
        {line_path("sma20")}
        {line_path("sma200")}
        {''.join(candle_parts)}
        <text x="{margin_left}" y="{height - 14}" fill="#94a3b8" font-size="12" font-weight="700">{html.escape(first_ts)}</text>
        <text x="{width - margin_right - 92}" y="{height - 14}" fill="#94a3b8" font-size="12" font-weight="700">{html.escape(last_ts)}</text>
        <text x="{margin_left}" y="14" fill="#e5edf7" font-size="13" font-weight="900">{safe_symbol}</text>
        <text x="{width - margin_right - 180}" y="14" fill="#cbd5e1" font-size="12" font-weight="800">{summary}</text>
      </svg>
    </section>
    """


def render_professional_chart_block(
    chart_df: pd.DataFrame,
    setup: dict,
    confluence: dict | None,
    trade_brief: dict | None,
    *,
    price_height: int = 500,
    volume_height: int = 130,
    oscillator_height: int = 120,
    key_prefix: str = "main",
    chart_interactive: bool = True,
    source_meta: dict[str, Any] | None = None,
) -> None:
    chart_symbol = text_display((trade_brief or {}).get("symbol") or setup.get("symbol"))
    timeframe = text_display((trade_brief or {}).get("timeframe") or setup.get("timeframe") or setup.get("tf"))
    chart_market = normalize_command_market((trade_brief or {}).get("market") or setup.get("market"), chart_symbol)
    source = chart_effective_source(chart_market, source_meta=source_meta)
    source_label = text_display(source.get("label") or source.get("source") or "-")
    source_mode = text_display(source.get("mode")).upper()
    fallback_reason = text_display(source.get("fallback_reason"))
    source_tone = "watch" if fallback_reason not in {"", "-"} or source_mode == "FALLBACK" else "buy"
    source_badge = "Fallback" if source_tone == "watch" else "Live"
    source_status = source_mode
    source_detail = fallback_reason if fallback_reason not in {"", "-"} else source_mode
    clean_window = prepare_chart_window(chart_df)
    live_data = chart_live_data_status(
        clean_window,
        market=chart_market,
        timeframe=timeframe,
        provider_summary=live_provider_quality_summary(live_provider_rows()),
        source_meta=source_meta,
    )
    data_contract = chart_data_contract(live_data)
    data_contract_html = render_chart_data_contract(data_contract)
    if clean_window.empty:
        st.markdown(
            f"""
            {data_contract_html}
            <section class="chart-empty-state">
              <div>
                <span>Gráfica pendiente</span>
                <strong>{html.escape(chart_symbol)} · {html.escape(timeframe)}</strong>
                <p>Roxy no encontró velas limpias suficientes para dibujar precio, volumen e indicadores. Fuente: {html.escape(text_display(data_contract.get("source_label") or source_label))} · gate {html.escape(text_display(data_contract.get("gate")))}.</p>
              </div>
              <ul>
                <li>Cambiar timeframe o símbolo.</li>
                <li>Verificar proveedor live.</li>
                <li>{html.escape(text_display(data_contract.get("action") or "Esperar nueva lectura del scanner."))}</li>
              </ul>
            </section>
            """,
            unsafe_allow_html=True,
        )
        return
    if len(clean_window) < 40:
        st.info(
            "Grafica limitada: hay pocas velas limpias para este simbolo/timeframe. Roxy muestra niveles, pero exige confirmacion extra."
        )
    visible_candles = len(clean_window)
    latest_candle = "-"
    if "ts" in clean_window.columns:
        try:
            ts_values = pd.to_datetime(clean_window["ts"], errors="coerce").dropna()
            if not ts_values.empty:
                latest_candle = pd.Timestamp(ts_values.max()).strftime("%m/%d %H:%M")
        except Exception:
            latest_candle = "-"
    latest_row = clean_window.iloc[-1]
    latest_open = safe_float(latest_row.get("open"))
    latest_high = safe_float(latest_row.get("high"))
    latest_low = safe_float(latest_row.get("low"))
    latest_close = safe_float(latest_row.get("close"))
    latest_volume = safe_float(latest_row.get("volume"))
    window_high = (
        safe_float(pd.to_numeric(clean_window.get("high"), errors="coerce").max())
        if "high" in clean_window.columns
        else None
    )
    window_low = (
        safe_float(pd.to_numeric(clean_window.get("low"), errors="coerce").min())
        if "low" in clean_window.columns
        else None
    )
    previous_close = safe_float(clean_window.iloc[-2].get("close")) if len(clean_window) > 1 else None
    candle_change = None
    if latest_close is not None and previous_close not in (None, 0):
        candle_change = (latest_close - previous_close) / previous_close
    candle_range = None
    if latest_high is not None and latest_low is not None and latest_close not in (None, 0):
        candle_range = (latest_high - latest_low) / latest_close
    candle_body_pct = None
    candle_upper_wick_pct = None
    candle_lower_wick_pct = None
    if latest_open is not None and latest_high is not None and latest_low is not None and latest_close not in (None, 0):
        body_top = max(latest_open, latest_close)
        body_bottom = min(latest_open, latest_close)
        candle_body_pct = abs(latest_close - latest_open) / latest_close
        candle_upper_wick_pct = max(0.0, latest_high - body_top) / latest_close
        candle_lower_wick_pct = max(0.0, body_bottom - latest_low) / latest_close
    candle_reading = candle_reading_label(
        latest_open,
        latest_high,
        latest_low,
        latest_close,
        candle_body_pct,
        candle_range,
        candle_upper_wick_pct,
        candle_lower_wick_pct,
    )
    candle_tone = "buy" if (latest_close or 0) >= (latest_open or latest_close or 0) else "avoid"
    candle_label = "Vela verde" if candle_tone == "buy" else "Vela roja"
    candle_ohlc = (
        f"O {num_display(latest_open, 2)} · H {num_display(latest_high, 2)} · "
        f"L {num_display(latest_low, 2)} · C {num_display(latest_close, 2)}"
    )
    candle_change_text = pct_display(candle_change) if candle_change is not None else "-"
    candle_range_text = pct_display(candle_range) if candle_range is not None else "-"
    candle_volume_text = num_display(latest_volume, 0) if latest_volume is not None else "-"
    window_range_text = "-"
    if window_low is not None and window_high is not None:
        window_range_text = f"{num_display(window_low, 2)}-{num_display(window_high, 2)}"
    window_position_text = "-"
    window_position_value = None
    if latest_close is not None and window_low is not None and window_high is not None and window_high != window_low:
        window_position_value = (latest_close - window_low) / (window_high - window_low)
        window_position_text = f"{window_position_value:.0%}"
    window_upside_text = "-"
    window_downside_text = "-"
    window_upside_value = None
    window_downside_value = None
    if latest_close not in (None, 0):
        if window_high is not None:
            window_upside_value = (window_high - latest_close) / latest_close
            window_upside_text = pct_display(window_upside_value)
        if window_low is not None:
            window_downside_value = (window_low - latest_close) / latest_close
            window_downside_text = pct_display(window_downside_value)
    entry_value = safe_float((trade_brief or {}).get("entry") or (confluence or {}).get("entry"))
    stop_value = safe_float((trade_brief or {}).get("stop") or (confluence or {}).get("stop"))
    target_value = safe_float((trade_brief or {}).get("target") or (trade_brief or {}).get("target_price"))

    def level_with_distance(value: float | None) -> str:
        if value is None:
            return "-"
        base = num_display(value, 2)
        if latest_close in (None, 0):
            return base
        distance = (value - latest_close) / latest_close
        return f"{base} · {pct_display(distance)}"

    entry_level = level_with_distance(entry_value)
    stop_level = level_with_distance(stop_value)
    target_level = level_with_distance(target_value)
    rr_value = None
    if (
        entry_value is not None
        and stop_value is not None
        and target_value is not None
        and abs(entry_value - stop_value) > 0
    ):
        rr_value = abs(target_value - entry_value) / abs(entry_value - stop_value)
    rr_display = f"1:{rr_value:.2f}" if rr_value is not None else "-"
    risk_lane_html = ""
    risk_points = [
        ("Stop", stop_value, "stop"),
        ("Entrada", entry_value, "entry"),
        ("Actual", latest_close, "current"),
        ("Target", target_value, "target"),
    ]
    valid_risk_points = [(label, value, tone) for label, value, tone in risk_points if value is not None]
    if len(valid_risk_points) >= 3:
        risk_values = [value for _, value, _ in valid_risk_points]
        risk_min = min(risk_values)
        risk_max = max(risk_values)
        risk_span = risk_max - risk_min
        if risk_span > 0:
            risk_items = []
            for risk_label, risk_value, risk_tone in valid_risk_points:
                risk_left = max(0.0, min(100.0, ((risk_value - risk_min) / risk_span) * 100.0))
                risk_items.append(
                    '<span class="chart-risk-point chart-risk-{tone}" style="left:{left:.1f}%" title="{title}">'
                    "<i></i><b>{label}</b><em>{value}</em></span>".format(
                        tone=html.escape(risk_tone),
                        left=risk_left,
                        title=html.escape(f"{risk_label}: {num_display(risk_value, 2)}"),
                        label=html.escape(risk_label),
                        value=html.escape(num_display(risk_value, 2)),
                    )
                )
            risk_lane_html = (
                '<section class="chart-risk-lane">'
                f'<header><strong>Mapa de trade</strong><span>R:R {html.escape(rr_display)} · '
                f'{html.escape(num_display(risk_min, 2))} → {html.escape(num_display(risk_max, 2))}</span></header>'
                f'<div class="chart-risk-track">{"".join(risk_items)}</div>'
                "</section>"
            )
    range_pressure_html = ""
    if (
        window_position_value is not None
        and latest_close is not None
        and window_low is not None
        and window_high is not None
    ):
        range_tone, range_label, range_detail = chart_window_pressure_label(
            window_position_value, window_upside_value, window_downside_value
        )
        range_left = max(0.0, min(100.0, window_position_value * 100.0))
        range_pressure_html = (
            '<section class="chart-range-pressure chart-range-pressure-{tone}">'
            '<header><strong>Rango visible</strong><span>{label} · Pos {position} · Techo {upside} · Piso {downside}</span></header>'
            '<div class="chart-range-track" title="{title}">'
            '<i class="chart-range-floor">Piso {floor}</i>'
            '<b style="left:{left:.1f}%"><em>Actual</em><strong>{current}</strong></b>'
            '<i class="chart-range-ceil">Techo {ceil}</i>'
            "</div>"
            "<small>{detail}</small>"
            "</section>"
        ).format(
            tone=html.escape(range_tone),
            label=html.escape(range_label),
            position=html.escape(window_position_text),
            upside=html.escape(window_upside_text),
            downside=html.escape(window_downside_text),
            title=html.escape(f"{range_label}: {range_detail}"),
            floor=html.escape(num_display(window_low, 2)),
            left=range_left,
            current=html.escape(num_display(latest_close, 2)),
            ceil=html.escape(num_display(window_high, 2)),
            detail=html.escape(range_detail),
        )
    decision_label = (
        human_trade_action(trade_brief or {}) if trade_brief else action_label((confluence or {}).get("signal"))
    )
    if decision_label in {"Operar", "Comprar"}:
        decision_tone = "buy"
    elif decision_label in {"No operar", "Evitar"}:
        decision_tone = "avoid"
    else:
        decision_tone = "watch"
    checklist_rows = command_center_checklist_rows(trade_brief or {})
    blocking_check = next((item for item in checklist_rows if item.get("tone") != "buy"), None)
    if blocking_check:
        next_hint = f"{text_display(blocking_check.get('label'))}: {text_display(blocking_check.get('detail'))}"
    else:
        next_hint = "Listo si respeta entrada, stop, volumen y gestion de riesgo."
    visible_checks = checklist_rows[:5]
    checks_total = len(visible_checks)
    checks_ok = sum(1 for item in visible_checks if item.get("tone") == "buy")
    checks_pending = max(0, checks_total - checks_ok)
    checks_tone = "buy" if checks_pending == 0 and checks_total else "watch" if checks_pending <= 2 else "avoid"
    checks_summary = f"Checks {checks_ok}/{checks_total}" if checks_total else "Checks -"
    blockers_summary = "Sin bloqueos" if checks_pending == 0 and checks_total else f"Faltan {checks_pending}"
    confirmation_html = "".join(
        '<span class="chart-check-pill chart-check-{tone}" title="{detail}">'
        "<span><em>{label}</em><small>{detail}</small></span><strong>{status}</strong></span>".format(
            tone=html.escape(text_display(item.get("tone"))),
            label=html.escape(text_display(item.get("label"))),
            status=html.escape(text_display(item.get("status"))),
            detail=html.escape(text_display(item.get("detail"))),
        )
        for item in visible_checks
    )
    candle_tape_html = ""
    if {"open", "high", "low", "close"}.issubset(clean_window.columns):
        tape_items: list[str] = []
        tape_ranges: list[float] = []
        tape_reading_counts: dict[str, int] = {}
        tape_tones: list[str] = []
        tape_green_count = 0
        tape_strong_count = 0
        tape_indecision_count = 0
        tape_first_open: float | None = None
        tape_last_close: float | None = None
        recent_candles = clean_window.tail(6).reset_index(drop=True)
        previous_closes = pd.to_numeric(clean_window["close"], errors="coerce").shift(1).tail(6).reset_index(drop=True)
        for row_idx, candle in recent_candles.iterrows():
            candle_open = safe_float(candle.get("open"))
            candle_high = safe_float(candle.get("high"))
            candle_low = safe_float(candle.get("low"))
            candle_close = safe_float(candle.get("close"))
            if tape_first_open is None and candle_open is not None:
                tape_first_open = candle_open
            if candle_close is not None:
                tape_last_close = candle_close
            previous_candle_close = (
                safe_float(previous_closes.iloc[row_idx]) if row_idx < len(previous_closes) else None
            )
            tape_tone = "buy" if (candle_close or 0) >= (candle_open or candle_close or 0) else "avoid"
            tape_tones.append(tape_tone)
            if tape_tone == "buy":
                tape_green_count += 1
            tape_change = None
            if candle_close is not None and previous_candle_close not in (None, 0):
                tape_change = (candle_close - previous_candle_close) / previous_candle_close
            tape_range = None
            if candle_high is not None and candle_low is not None and candle_close not in (None, 0):
                tape_range = (candle_high - candle_low) / candle_close
                tape_ranges.append(tape_range)
            tape_body_pct = None
            tape_upper_wick_pct = None
            tape_lower_wick_pct = None
            if (
                candle_open is not None
                and candle_high is not None
                and candle_low is not None
                and candle_close not in (None, 0)
            ):
                tape_body_top = max(candle_open, candle_close)
                tape_body_bottom = min(candle_open, candle_close)
                tape_body_pct = abs(candle_close - candle_open) / candle_close
                tape_upper_wick_pct = max(0.0, candle_high - tape_body_top) / candle_close
                tape_lower_wick_pct = max(0.0, tape_body_bottom - candle_low) / candle_close
            tape_reading = candle_reading_label(
                candle_open,
                candle_high,
                candle_low,
                candle_close,
                tape_body_pct,
                tape_range,
                tape_upper_wick_pct,
                tape_lower_wick_pct,
            )
            tape_strength = "normal"
            tape_strength_label = "cuerpo medio"
            if tape_body_pct is not None and tape_range not in (None, 0):
                tape_body_share = tape_body_pct / tape_range
                if tape_body_share >= 0.55 and tape_range >= 0.003:
                    tape_strength = "strong"
                    tape_strength_label = "cuerpo fuerte"
                elif tape_body_share <= 0.18 and tape_range >= 0.003:
                    tape_strength = "indecision"
                    tape_strength_label = "doji / indecisión"
            if tape_strength == "strong":
                tape_strong_count += 1
            elif tape_strength == "indecision":
                tape_indecision_count += 1
            if tape_reading not in {"", "-", "Sin lectura"}:
                tape_reading_counts[tape_reading] = tape_reading_counts.get(tape_reading, 0) + 1
            tape_time = "-"
            if "ts" in candle:
                try:
                    parsed_ts = pd.to_datetime(candle.get("ts"), errors="coerce")
                    if pd.notna(parsed_ts):
                        tape_time = pd.Timestamp(parsed_ts).strftime("%H:%M")
                except Exception:
                    tape_time = "-"
            tape_title = (
                f"{tape_time} · O {num_display(candle_open, 2)} · H {num_display(candle_high, 2)} · "
                f"L {num_display(candle_low, 2)} · C {num_display(candle_close, 2)} · "
                f"Rango {pct_display(tape_range) if tape_range is not None else '-'} · "
                f"Fuerza {tape_strength_label} · {tape_reading}"
            )
            latest_class = " chart-tape-latest" if row_idx == len(recent_candles) - 1 else ""
            tape_items.append(
                '<span class="chart-tape-candle chart-tape-{tone} chart-tape-strength-{strength}{latest_class}" title="{title}"><em>{time}</em><strong>{close}</strong>'
                "<small>{change} · {reading}</small></span>".format(
                    tone=html.escape(tape_tone),
                    strength=html.escape(tape_strength),
                    latest_class=latest_class,
                    title=html.escape(tape_title),
                    time=html.escape(tape_time),
                    close=html.escape(num_display(candle_close, 2)),
                    change=html.escape(pct_display(tape_change) if tape_change is not None else "-"),
                    reading=html.escape(tape_reading),
                )
            )
        if tape_items:
            tape_momentum = None
            if tape_first_open not in (None, 0) and tape_last_close is not None:
                tape_momentum = (tape_last_close - tape_first_open) / tape_first_open
            tape_avg_range = sum(tape_ranges) / len(tape_ranges) if tape_ranges else None
            tape_dominant_reading = "-"
            if tape_reading_counts:
                tape_dominant_reading = max(tape_reading_counts.items(), key=lambda item: (item[1], item[0]))[0]
            tape_latest_streak = 0
            tape_latest_tone_label = "-"
            if tape_tones:
                tape_latest_tone = tape_tones[-1]
                tape_latest_tone_label = "verdes" if tape_latest_tone == "buy" else "rojas"
                for tape_tone_item in reversed(tape_tones):
                    if tape_tone_item != tape_latest_tone:
                        break
                    tape_latest_streak += 1
            tape_bias = "Sesgo mixto"
            if tape_momentum is not None:
                green_ratio = tape_green_count / max(1, len(tape_items))
                if tape_momentum >= 0.002 and green_ratio >= 0.5:
                    tape_bias = "Sesgo alcista"
                elif tape_momentum <= -0.002 and green_ratio <= 0.5:
                    tape_bias = "Sesgo bajista"
                elif tape_avg_range is not None and tape_avg_range >= 0.018:
                    tape_bias = "Volatilidad alta"
            tape_bias_tone = "watch"
            if tape_bias == "Sesgo alcista":
                tape_bias_tone = "buy"
            elif tape_bias == "Sesgo bajista":
                tape_bias_tone = "avoid"
            tape_summary = (
                f"{tape_bias} · "
                f"{tape_green_count}/{len(tape_items)} verdes · "
                f"{tape_strong_count} fuertes · "
                f"{tape_indecision_count} doji · "
                f"racha {tape_latest_streak} {tape_latest_tone_label} · "
                f"{pct_display(tape_momentum) if tape_momentum is not None else '-'} · "
                f"lectura {tape_dominant_reading} · "
                f"rango {pct_display(tape_avg_range) if tape_avg_range is not None else '-'}"
            )
            tape_summary_badges = [
                tape_bias,
                f"{tape_green_count}/{len(tape_items)} verdes",
                f"{tape_strong_count} fuertes",
                f"{tape_indecision_count} doji",
                f"racha {tape_latest_streak} {tape_latest_tone_label}",
                pct_display(tape_momentum) if tape_momentum is not None else "-",
                f"rango {pct_display(tape_avg_range) if tape_avg_range is not None else '-'}",
            ]
            tape_summary_html = "".join(f"<i>{html.escape(text_display(item))}</i>" for item in tape_summary_badges)
            candle_tape_html = (
                f'<section class="chart-candle-tape chart-candle-tape-{html.escape(tape_bias_tone)}"><b><span>Últimas velas</span>'
                f'<small title="{html.escape(tape_summary)}">{tape_summary_html}</small></b>'
                + "".join(tape_items)
                + "</section>"
            )
    technical_strip_html = ""
    technical_items: list[str] = []
    technical_tones: list[str] = []

    def add_technical_item(label: str, value: str, detail: str, tone: str) -> None:
        technical_tones.append(tone)
        title = f"{label}: {value} · {detail}"
        technical_items.append(
            '<span class="chart-tech-pill chart-tech-{tone}" title="{title}"><em>{label}</em><strong>{value}</strong>'
            "<small>{detail}</small></span>".format(
                tone=html.escape(tone),
                title=html.escape(title),
                label=html.escape(label),
                value=html.escape(value),
                detail=html.escape(detail),
            )
        )

    rsi_value = safe_float(latest_row.get("rsi14"))
    if rsi_value is not None:
        if rsi_value >= 70:
            add_technical_item("RSI", num_display(rsi_value, 0), "Sobrecompra", "avoid")
        elif rsi_value <= 30:
            add_technical_item("RSI", num_display(rsi_value, 0), "Sobreventa", "watch")
        elif rsi_value >= 50:
            add_technical_item("RSI", num_display(rsi_value, 0), "Impulso sano", "buy")
        else:
            add_technical_item("RSI", num_display(rsi_value, 0), "Neutral débil", "watch")
    macd_hist = safe_float(latest_row.get("macd_hist"))
    if macd_hist is not None:
        add_technical_item(
            "MACD",
            num_display(macd_hist, 4),
            "Impulso +" if macd_hist >= 0 else "Impulso -",
            "buy" if macd_hist >= 0 else "avoid",
        )
    sma20_value = safe_float(latest_row.get("sma20") or setup.get("sma20"))
    sma200_value = safe_float(latest_row.get("sma200") or setup.get("sma200"))
    if latest_close is not None and sma20_value is not None and sma200_value is not None:
        if latest_close > sma20_value > sma200_value:
            add_technical_item("Medias", "Alcista", "Precio > 20 > 200", "buy")
        elif latest_close < sma20_value < sma200_value:
            add_technical_item("Medias", "Bajista", "Precio < 20 < 200", "avoid")
        else:
            add_technical_item("Medias", "Mixto", "Esperar confirmación", "watch")
    bb_upper = safe_float(latest_row.get("bb_upper"))
    bb_lower = safe_float(latest_row.get("bb_lower"))
    if latest_close is not None and bb_upper is not None and bb_lower is not None and bb_upper != bb_lower:
        bb_position = (latest_close - bb_lower) / (bb_upper - bb_lower)
        if bb_position >= 0.85:
            add_technical_item("Bollinger", "Alta", "Cerca de banda sup.", "watch")
        elif bb_position <= 0.15:
            add_technical_item("Bollinger", "Baja", "Cerca de banda inf.", "watch")
        else:
            add_technical_item("Bollinger", "Media", "Dentro del canal", "buy")
    volume_sma = safe_float(latest_row.get("volume_sma20"))
    if latest_volume is not None and volume_sma not in (None, 0):
        relative_volume = latest_volume / volume_sma
        volume_tone = "buy" if relative_volume >= 1.2 else "watch" if relative_volume >= 0.8 else "avoid"
        add_technical_item(
            "RVol",
            f"{relative_volume:.2f}x",
            "Volumen confirma" if relative_volume >= 1.2 else "Volumen bajo",
            volume_tone,
        )
    if candle_reading not in {"", "-", "Sin lectura"}:
        candle_reading_tone = "watch"
        candle_reading_lower = candle_reading.lower()
        if any(token in candle_reading_lower for token in ["alcista", "rebote"]):
            candle_reading_tone = "buy"
        elif any(token in candle_reading_lower for token in ["bajista", "rechazo"]):
            candle_reading_tone = "avoid"
        add_technical_item("Vela", candle_reading, f"Cuerpo {pct_display(candle_body_pct)}", candle_reading_tone)
    if technical_items:
        technical_buy_count = technical_tones.count("buy")
        technical_watch_count = technical_tones.count("watch")
        technical_avoid_count = technical_tones.count("avoid")
        technical_strip_tone = "watch"
        if technical_avoid_count >= 2 or technical_avoid_count > technical_buy_count:
            technical_strip_tone = "avoid"
        elif technical_buy_count >= max(1, len(technical_tones) - technical_avoid_count) and technical_avoid_count == 0:
            technical_strip_tone = "buy"
        technical_summary = (
            f"{technical_buy_count}/{len(technical_tones)} OK · "
            f"{technical_watch_count} espera · {technical_avoid_count} riesgo"
        )
        technical_summary_html = "".join(
            f"<i>{html.escape(text_display(item))}</i>"
            for item in [
                f"{technical_buy_count}/{len(technical_tones)} OK",
                f"{technical_watch_count} espera",
                f"{technical_avoid_count} riesgo",
            ]
        )
        technical_strip_html = (
            f'<section class="chart-tech-strip chart-tech-strip-{html.escape(technical_strip_tone)}"><b><span>Indicadores</span>'
            f'<small title="{html.escape(technical_summary)}">{technical_summary_html}</small></b>'
            + "".join(technical_items[:6])
            + "</section>"
        )
    st.markdown(
        f"""
        {data_contract_html}
        <section class="chart-command-head">
          <div>
            <span>Gráfica profesional</span>
            <strong>{html.escape(chart_symbol)} · {html.escape(timeframe)}</strong>
            <small class="chart-next-action">Ahora: {html.escape(next_hint)}</small>
          </div>
          <aside>
            <b class="chart-level-decision chart-level-decision-{decision_tone}" title="{html.escape(next_hint)}">Roxy {html.escape(decision_label)}</b>
            <b class="chart-level-entry" title="Entrada sugerida y distancia contra el precio actual">Entrada {html.escape(entry_level)}</b>
            <b class="chart-level-stop" title="Nivel de invalidación para controlar riesgo">Stop {html.escape(stop_level)}</b>
            <b class="chart-level-target" title="Objetivo principal y distancia contra el precio actual">Target {html.escape(target_level)}</b>
            <b class="chart-level-rr" title="Relación riesgo/recompensa calculada desde entrada, stop y target">R:R {html.escape(rr_display)}</b>
            <b class="chart-level-check chart-level-check-{checks_tone}" title="Confirmaciones visibles antes de operar">{html.escape(checks_summary)} · {html.escape(blockers_summary)}</b>
            <b class="chart-level-data" title="Cantidad de velas limpias usadas por Roxy">Velas {visible_candles}</b>
            <b class="chart-level-data" title="Mínimo, máximo y ubicación del precio dentro de la ventana visible">Ventana {html.escape(window_range_text)} · Pos {html.escape(window_position_text)}</b>
            <b class="chart-level-data" title="Distancia porcentual al techo y piso recientes">Techo {html.escape(window_upside_text)} · Piso {html.escape(window_downside_text)}</b>
            <b class="chart-level-data" title="Última vela limpia recibida">Última {html.escape(latest_candle)}</b>
            <b class="chart-level-candle chart-level-candle-{candle_tone}" title="{html.escape(candle_reading)}">{html.escape(candle_label)} · {html.escape(candle_change_text)}</b>
            <b class="chart-level-data" title="Open, high, low y close de la última vela">{html.escape(candle_ohlc)}</b>
            <b class="chart-level-data" title="Rango de la última vela y volumen actual">Rango {html.escape(candle_range_text)} · Vol {html.escape(candle_volume_text)}</b>
            <b class="chart-level-source chart-level-source-{source_tone}" title="{html.escape(source_detail if source_detail != '-' else source_status)}">{html.escape(source_badge)} · {html.escape(source_label)}</b>
            <b class="chart-level-interact" title="Puedes arrastrar, hacer zoom y usar hover para leer OHLC">Arrastra · Zoom · OHLC</b>
          </aside>
        </section>
        {risk_lane_html}
        {range_pressure_html}
        <section class="chart-check-strip">{confirmation_html}</section>
        <section class="chart-legend-strip">
          <span title="Precio actual o última vela limpia"><i class="chart-legend-dot chart-legend-current"></i>Actual</span>
          <span title="Zona donde Roxy esperaría confirmación de entrada"><i class="chart-legend-dot chart-legend-entry"></i>Entrada / compra</span>
          <span title="Nivel donde la idea queda invalidada o peligrosa"><i class="chart-legend-dot chart-legend-stop"></i>Stop / peligro</span>
          <span title="Objetivo principal de salida o toma de ganancia"><i class="chart-legend-dot chart-legend-target"></i>Target</span>
          <span title="Niveles de estructura que pueden frenar o sostener el precio"><i class="chart-legend-dot chart-legend-support"></i>Soporte / resistencia</span>
        </section>
        {candle_tape_html}
        {technical_strip_html}
        """,
        unsafe_allow_html=True,
    )
    if source_tone == "watch":
        fallback_detail = text_display(source.get("fallback_detail"))
        fallback_action = text_display(source.get("fallback_action"))
        fallback_parts = [part for part in [fallback_reason, fallback_detail, fallback_action] if part not in {"", "-"}]
        st.markdown(
            f"""
            <section class="chart-provider-warning">
              <strong>Proveedor en fallback</strong>
              <span>{html.escape(source_label)} · {html.escape(" | ".join(fallback_parts) if fallback_parts else source_mode)}</span>
            </section>
            """,
            unsafe_allow_html=True,
        )

    def render_static_live_price_chart() -> bool:
        svg = static_live_price_chart_svg(clean_window, symbol=chart_symbol, height=price_height)
        if not svg:
            return False
        st.markdown(svg, unsafe_allow_html=True)
        return True

    price_chart = build_professional_price_chart(
        clean_window,
        setup,
        confluence,
        trade_brief or {},
        paper_snapshot=st.session_state.get("alpaca_paper_journal_snapshot"),
        symbol=chart_symbol,
        hover_interactive=chart_interactive,
    ).properties(height=price_height)
    volume_chart = build_professional_volume_chart(clean_window) if chart_interactive else None
    oscillator_chart = build_professional_oscillator_chart(clean_window) if chart_interactive else None
    panels = [price_chart]
    if volume_chart is not None:
        panels.append(volume_chart.properties(height=volume_height))
    if oscillator_chart is not None:
        panels.append(oscillator_chart.properties(height=oscillator_height))
    symbol_key = safe_key((trade_brief or {}).get("symbol") or setup.get("symbol") or "symbol")
    market_key = safe_key((trade_brief or {}).get("market") or setup.get("market") or "market")
    timeframe_key = safe_key((trade_brief or {}).get("timeframe") or setup.get("tf") or setup.get("timeframe") or "tf")
    chart_key = f"professional_chart_{safe_key(key_prefix)}_{symbol_key}_{market_key}_{timeframe_key}"

    def render_price_chart_fallback() -> None:
        fallback_cols = [
            col for col in ["close", "ema9", "sma20", "sma40", "sma100", "sma200"] if col in clean_window.columns
        ]
        st.markdown(
            f"""
            <section class="chart-fallback-state">
              <span>Fallback seguro</span>
              <strong>{html.escape(chart_symbol)} · precio y medias</strong>
              <p>La gráfica avanzada no renderizó, pero Roxy mantiene una vista simple para no perder contexto.</p>
            </section>
            """,
            unsafe_allow_html=True,
        )
        if fallback_cols:
            fallback_df = clean_window[fallback_cols].apply(pd.to_numeric, errors="coerce")
            st.line_chart(fallback_df, height=min(price_height, 420), use_container_width=True)

    rendered_static_live_chart = False
    if not chart_interactive:
        rendered_static_live_chart = render_static_live_price_chart()

    if rendered_static_live_chart:
        pass
    elif len(panels) > 1:
        try:
            st.altair_chart(
                style_trading_chart(price_chart, interactive=chart_interactive),
                use_container_width=True,
                key=chart_key,
            )
        except Exception:
            render_price_chart_fallback()
        with st.expander("Volumen y osciladores", expanded=False):
            for panel_idx, panel in enumerate(panels[1:], start=1):
                try:
                    st.altair_chart(
                        style_trading_chart(panel, interactive=chart_interactive),
                        use_container_width=True,
                        key=f"{chart_key}_indicator_{panel_idx}",
                    )
                except Exception:
                    st.caption("Indicador omitido por incompatibilidad temporal de gráfica.")
    else:
        try:
            st.altair_chart(
                style_trading_chart(price_chart, interactive=chart_interactive),
                use_container_width=True,
                key=chart_key,
            )
        except Exception:
            render_price_chart_fallback()

    candle_table_cols = [col for col in ["ts", "open", "high", "low", "close", "volume"] if col in clean_window.columns]
    if {"open", "high", "low", "close"}.issubset(clean_window.columns):
        candle_table = clean_window[candle_table_cols].copy()
        open_values = pd.to_numeric(candle_table["open"], errors="coerce")
        close_values = pd.to_numeric(candle_table["close"], errors="coerce")
        high_values = pd.to_numeric(candle_table["high"], errors="coerce")
        low_values = pd.to_numeric(candle_table["low"], errors="coerce")
        candle_table["direction"] = "Roja"
        candle_table.loc[close_values >= open_values, "direction"] = "Verde"
        candle_table["change_pct"] = close_values.pct_change()
        close_denominator = close_values.replace(0, pd.NA)
        body_top = pd.concat([open_values, close_values], axis=1).max(axis=1)
        body_bottom = pd.concat([open_values, close_values], axis=1).min(axis=1)
        candle_table["range_pct"] = (high_values - low_values) / close_denominator
        candle_table["body_pct"] = (close_values - open_values).abs() / close_denominator
        candle_table["upper_wick_pct"] = (high_values - body_top).clip(lower=0) / close_denominator
        candle_table["lower_wick_pct"] = (body_bottom - low_values).clip(lower=0) / close_denominator
        candle_table["reading"] = [
            candle_reading_label(
                open_value,
                high_value,
                low_value,
                close_value,
                body_pct,
                range_pct,
                upper_wick_pct,
                lower_wick_pct,
            )
            for open_value, high_value, low_value, close_value, body_pct, range_pct, upper_wick_pct, lower_wick_pct in zip(
                open_values,
                high_values,
                low_values,
                close_values,
                candle_table["body_pct"],
                candle_table["range_pct"],
                candle_table["upper_wick_pct"],
                candle_table["lower_wick_pct"],
            )
        ]
        candle_table["wick_pressure"] = [
            candle_wick_pressure_label(upper_wick_pct, lower_wick_pct, body_pct)
            for upper_wick_pct, lower_wick_pct, body_pct in zip(
                candle_table["upper_wick_pct"],
                candle_table["lower_wick_pct"],
                candle_table["body_pct"],
            )
        ]

        def candle_micro_signal_label(
            direction: Any, reading: Any, change_pct: Any, range_pct: Any, body_pct: Any
        ) -> str:
            direction_text = text_display(direction)
            reading_text = text_display(reading).lower()
            change_value = safe_float(change_pct)
            range_value = safe_float(range_pct)
            body_value = safe_float(body_pct)
            body_share = None
            if body_value is not None and range_value not in (None, 0):
                body_share = body_value / range_value
            if (
                direction_text == "Verde"
                and (change_value is None or change_value >= 0)
                and ("alcista" in reading_text or "rebote" in reading_text or (body_share or 0) >= 0.55)
            ):
                return "🟢 Impulso"
            if "rechazo" in reading_text or (
                direction_text == "Roja" and change_value is not None and change_value <= -0.001
            ):
                return "🔴 Riesgo"
            if body_share is not None and body_share <= 0.20:
                return "🟡 Doji"
            if range_value is not None and range_value >= 0.015:
                return "🟡 Volátil"
            return "🟡 Esperar"

        candle_table["micro_signal"] = [
            candle_micro_signal_label(direction, reading, change_pct, range_pct, body_pct)
            for direction, reading, change_pct, range_pct, body_pct in zip(
                candle_table["direction"],
                candle_table["reading"],
                candle_table["change_pct"],
                candle_table["range_pct"],
                candle_table["body_pct"],
            )
        ]
        candle_table = candle_table.tail(8).copy()
        candle_green_count = int((candle_table["direction"] == "Verde").sum())
        candle_red_count = int((candle_table["direction"] == "Roja").sum())
        candle_avg_range = safe_float(pd.to_numeric(candle_table["range_pct"], errors="coerce").mean())
        candle_latest_reading = (
            text_display(candle_table["reading"].iloc[-1])
            if not candle_table.empty and "reading" in candle_table
            else "-"
        )
        candle_latest_signal = (
            text_display(candle_table["micro_signal"].iloc[-1])
            if not candle_table.empty and "micro_signal" in candle_table
            else "-"
        )
        candle_expander_label = (
            f"Últimas 8 velas OHLC · {candle_green_count} verdes/{candle_red_count} rojas · "
            f"rango avg {pct_display(candle_avg_range)} · {candle_latest_signal}"
        )
        candle_table = candle_table.drop(columns=["upper_wick_pct", "lower_wick_pct"], errors="ignore")
        if "ts" in candle_table.columns:
            candle_table["ts"] = pd.to_datetime(candle_table["ts"], errors="coerce").dt.strftime("%m/%d %H:%M")
        for column in ["open", "high", "low", "close"]:
            if column in candle_table.columns:
                candle_table[column] = candle_table[column].map(lambda value: num_display(value, 2))
        if "volume" in candle_table.columns:
            candle_table["volume"] = candle_table["volume"].map(lambda value: num_display(value, 0))
        candle_table["change_pct"] = candle_table["change_pct"].map(lambda value: pct_display(value))
        candle_table["range_pct"] = candle_table["range_pct"].map(lambda value: pct_display(value))
        candle_table["body_pct"] = candle_table["body_pct"].map(lambda value: pct_display(value))
        candle_table = candle_table.rename(
            columns={
                "ts": "Hora",
                "direction": "Dirección",
                "open": "Open",
                "high": "High",
                "low": "Low",
                "close": "Close",
                "volume": "Volumen",
                "micro_signal": "Micro señal",
                "wick_pressure": "Presión",
                "reading": "Lectura",
                "change_pct": "Cambio",
                "range_pct": "Rango",
                "body_pct": "Cuerpo",
            }
        )
        candle_order = [
            "Hora",
            "Micro señal",
            "Presión",
            "Dirección",
            "Lectura",
            "Open",
            "High",
            "Low",
            "Close",
            "Cambio",
            "Rango",
            "Cuerpo",
            "Volumen",
        ]
        candle_table = candle_table[[column for column in candle_order if column in candle_table.columns]]
        candle_column_config = {
            "Hora": st.column_config.TextColumn("Hora", help="Hora local de la vela.", width="small"),
            "Micro señal": st.column_config.TextColumn(
                "Micro señal",
                help="Lectura inmediata de la vela: impulso, riesgo, doji, volatilidad o esperar.",
                width="small",
            ),
            "Presión": st.column_config.TextColumn(
                "Presión",
                help="Lectura de mechas: oferta arriba, demanda abajo o presión mixta.",
                width="small",
            ),
            "Dirección": st.column_config.TextColumn(
                "Dirección", help="Verde si cierre >= apertura; roja si cierre < apertura.", width="small"
            ),
            "Lectura": st.column_config.TextColumn(
                "Lectura", help="Interpretación rápida de cuerpo y mechas.", width="medium"
            ),
            "Open": st.column_config.TextColumn("Open", help="Precio de apertura.", width="small"),
            "High": st.column_config.TextColumn("High", help="Máximo de la vela.", width="small"),
            "Low": st.column_config.TextColumn("Low", help="Mínimo de la vela.", width="small"),
            "Close": st.column_config.TextColumn("Close", help="Precio de cierre.", width="small"),
            "Volumen": st.column_config.TextColumn("Volumen", help="Volumen negociado en la vela.", width="small"),
            "Cambio": st.column_config.TextColumn(
                "Cambio", help="Cambio porcentual contra la vela previa.", width="small"
            ),
            "Rango": st.column_config.TextColumn("Rango", help="High-Low como porcentaje del cierre.", width="small"),
            "Cuerpo": st.column_config.TextColumn(
                "Cuerpo", help="Tamaño del cuerpo de la vela como porcentaje del cierre.", width="small"
            ),
        }
        with st.expander(candle_expander_label, expanded=False):
            st.caption(
                f"Última lectura: {candle_latest_reading}. Comparación rápida contra velas previas sin salir de la gráfica."
            )
            st.dataframe(candle_table, width="stretch", hide_index=True, height=260, column_config=candle_column_config)


def render_command_center_analysis(
    context: dict[str, Any],
    *,
    app_brief: dict,
    account_equity: float,
    risk_per_trade_pct: float,
    chart_interactive: bool = True,
    render_secondary_charts: bool = True,
    render_decision_panel: bool = True,
) -> None:
    chart_df = context.get("chart_df") if isinstance(context.get("chart_df"), pd.DataFrame) else pd.DataFrame()
    setup = context.get("setup") or {}
    trade_brief = context.get("trade_brief") or {}
    if chart_df.empty or not setup or not trade_brief:
        st.info(f"No hay suficiente historial para analizar {context.get('symbol', '-')}.")
        return
    confluence = context.get("confluence") or {}
    ticket = trade_plan_platform_preview(
        trade_brief,
        account_equity=float(account_equity),
        risk_per_trade_pct=float(risk_per_trade_pct),
        source_freshness=app_brief.get("source_freshness"),
        market_session=app_brief.get("market_session"),
    )
    chart_status = chart_command_center_status(
        chart_df,
        market=str(trade_brief.get("market") or context.get("market") or "stock"),
        timeframe=str(trade_brief.get("timeframe") or context.get("timeframe") or "1h"),
        source_meta=context.get("data_source"),
    )
    live_price = cached_live_price_snapshot(
        text_display(trade_brief.get("symbol") or context.get("symbol")).upper(),
        str(trade_brief.get("market") or context.get("market") or "stock"),
    )
    render_operational_chart_first(
        chart_df,
        setup,
        confluence,
        trade_brief,
        symbol=text_display(trade_brief.get("symbol") or context.get("symbol")).upper(),
        live_price=live_price,
        chart_interactive=chart_interactive,
        render_trade_snapshot=render_decision_panel,
    )
    if not render_decision_panel:
        return
    if render_secondary_charts:
        render_professional_chart_block(
            chart_df,
            setup,
            confluence,
            trade_brief,
            price_height=460,
            volume_height=115,
            key_prefix="command_center",
            chart_interactive=chart_interactive,
            source_meta=context.get("data_source"),
        )
    render_command_center_panel(trade_brief, platform_ticket=ticket, chart_status=chart_status)
    with st.expander("Lectura técnica, niveles y contexto", expanded=False):
        render_chart_readout(setup, confluence, trade_brief, chart_df, source_meta=context.get("data_source"))
        render_chart_strategy_summary(setup, confluence, trade_brief, chart_df)
        render_chart_level_plan(chart_df, setup, confluence, trade_brief)
    with st.expander("Detalles: por que Roxy toma esta decision", expanded=False):
        render_operation_gate(trade_brief)
        render_trade_plan_platform_preview(ticket)
        render_decision_reason(trade_brief)
        render_decision_transition(trade_brief)
        render_strategy_event_panel(chart_df, setup)


def chart_stream_interval_seconds(timeframe: Any) -> int:
    tf = normalize_command_timeframe(timeframe)
    return {"1m": 60, "5m": 300, "15m": 900, "1h": 3600, "2h": 7200, "4h": 14400, "1d": 86400, "1w": 604800}.get(tf, 3600)


def chart_stream_binance_interval(timeframe: Any) -> str:
    tf = normalize_command_timeframe(timeframe)
    return {"1m": "1m", "5m": "5m", "15m": "15m", "1h": "1h", "2h": "2h", "4h": "4h", "1d": "1d", "1w": "1w"}.get(tf, "1h")


def binanceus_symbol_candidates(symbol: str) -> list[str]:
    raw = str(symbol or "").strip().upper().replace("-", "/")
    base = raw.split("/")[0] if "/" in raw else raw
    quote = raw.split("/")[1] if "/" in raw and len(raw.split("/")) > 1 else "USD"
    candidates: list[str] = []
    if base:
        candidates.append(f"{base}{quote}")
        if quote == "USD":
            candidates.append(f"{base}USDT")
        if quote == "USDT":
            candidates.append(f"{base}USD")
    return list(dict.fromkeys(candidates))


def live_candle_chart_payload(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
    live_price: dict[str, Any] | None = None,
    trade_plan: dict[str, Any] | None = None,
    strategy_profile: str | None = None,
    max_candles: int = 3000,
) -> dict[str, Any]:
    window = prepare_chart_window(chart_df, limit=max_candles)
    if isinstance(window, pd.DataFrame) and not window.empty and "close" in window.columns:
        window = window.copy()
        close_series = pd.to_numeric(window["close"], errors="coerce")
        if "ema20" not in window.columns:
            window["ema20"] = close_series.ewm(span=20, adjust=False).mean()
        if "ema21" not in window.columns:
            window["ema21"] = close_series.ewm(span=21, adjust=False).mean()
    rows: list[dict[str, Any]] = []
    for row in window.to_dict("records"):
        ts = pd.to_datetime(row.get("ts"), errors="coerce", utc=True)
        if pd.isna(ts):
            continue
        candle: dict[str, Any] = {"time": int(ts.timestamp())}
        valid = True
        for column in ["open", "high", "low", "close"]:
            value = safe_float(row.get(column))
            if value is None:
                valid = False
                break
            candle[column] = float(value)
        if not valid:
            continue
        volume = safe_float(row.get("volume"))
        candle["volume"] = float(volume or 0)
        rows.append(candle)

    def _median(values: list[float]) -> float | None:
        clean = sorted(value for value in values if math.isfinite(value) and value > 0)
        if not clean:
            return None
        middle = len(clean) // 2
        if len(clean) % 2:
            return clean[middle]
        return (clean[middle - 1] + clean[middle]) / 2

    def _visual_candles(candles: list[dict[str, Any]]) -> list[dict[str, Any]]:
        ranges: list[float] = []
        for candle in candles:
            close = abs(float(candle.get("close") or 0))
            high = float(candle.get("high") or 0)
            low = float(candle.get("low") or 0)
            if close > 0 and high >= low:
                range_pct = (high - low) / close
                if 0 < range_pct <= 0.18:
                    ranges.append(range_pct)
        typical_range = _median(ranges) or 0.012
        max_range_pct = max(0.022, min(0.085, typical_range * 5.5))
        normalized: list[dict[str, Any]] = []
        for candle in candles:
            item = dict(candle)
            open_price = float(item["open"])
            close_price = float(item["close"])
            high_price = max(float(item["high"]), open_price, close_price)
            low_price = min(float(item["low"]), open_price, close_price)
            close_abs = abs(close_price)
            if close_abs > 0 and (high_price - low_price) / close_abs > max_range_pct:
                body_high = max(open_price, close_price)
                body_low = min(open_price, close_price)
                body_range = max(body_high - body_low, close_abs * 0.001)
                max_total_wick = max(close_abs * max_range_pct - body_range, close_abs * 0.002)
                upper_wick = max(0.0, high_price - body_high)
                lower_wick = max(0.0, body_low - low_price)
                total_wick = upper_wick + lower_wick
                if total_wick > max_total_wick and total_wick > 0:
                    scale = max_total_wick / total_wick
                    high_price = body_high + upper_wick * scale
                    low_price = body_low - lower_wick * scale
            item["high"] = float(max(high_price, open_price, close_price))
            item["low"] = float(min(low_price, open_price, close_price))
            normalized.append(item)
        return normalized

    rows = _visual_candles(rows)

    def _line(column: str) -> list[dict[str, Any]]:
        if column not in window.columns:
            return []
        out: list[dict[str, Any]] = []
        for row in window[["ts", column]].to_dict("records"):
            ts = pd.to_datetime(row.get("ts"), errors="coerce", utc=True)
            value = safe_float(row.get(column))
            if pd.notna(ts) and value is not None:
                out.append({"time": int(ts.timestamp()), "value": float(value)})
        return out

    normalized_symbol = text_display(symbol).upper()
    normalized_market = normalize_command_market(market, normalized_symbol)
    normalized_timeframe = normalize_command_timeframe(timeframe)
    live_price = live_price or {}
    trade_plan = trade_plan if isinstance(trade_plan, dict) else {}
    profile_key = text_display(strategy_profile or trade_plan.get("strategy_profile") or "default").lower()
    default_indicators = {
        "EMA9": True,
        "EMA20": False,
        "EMA21": False,
        "SMA20": True,
        "SMA40": True,
        "SMA100": False,
        "SMA200": False,
        "BB Upper": True,
        "BB Mid": False,
        "BB Lower": True,
        "BBand": True,
        "Labels": False,
        "Plan": False,
        "Info": False,
        "Scale": True,
        "Volume": True,
    }
    strategy_title = "Roxy operativo"
    strategy_detail = "EMA9 · Avg20/40 · Bollinger · volumen · plan"
    if profile_key == "acciones_15m_1h":
        default_indicators.update(
            {
                "EMA9": True,
                "EMA20": False,
                "EMA21": True,
                "SMA20": True,
                "SMA40": True,
                "SMA100": False,
                "SMA200": False,
                "BB Mid": False,
                "Labels": False,
                "Plan": True,
                "Info": True,
                "Scale": True,
                "Volume": True,
            }
        )
        strategy_title = "Acciones 15m/1h"
        strategy_detail = "Operacion: 15m entrada · 1h tendencia · EMA9/21 · Avg20/40 · Bollinger"
    elif profile_key == "crypto_20m":
        default_indicators.update({"EMA9": True, "EMA21": True, "SMA20": False, "SMA40": False, "SMA100": False, "SMA200": False})
        strategy_title = "Crypto 20min"
        strategy_detail = "Scalping: 1m entrada · 1h contexto · EMA9/21 · BB 20 2 · volumen"
    elif profile_key == "crypto_2h":
        default_indicators.update({"EMA9": False, "EMA20": True, "EMA21": False, "SMA20": False, "SMA40": True, "SMA100": False, "SMA200": False})
        strategy_title = "Crypto 2H"
        strategy_detail = "Confirmacion: 2h ejecucion · 4h contexto · EMA20/Avg40 · soporte/resistencia"
    elif profile_key == "crypto_daily":
        default_indicators.update({"EMA9": False, "EMA20": False, "EMA21": False, "SMA20": True, "SMA40": True, "SMA100": True, "SMA200": True, "BB Mid": True, "Labels": True})
        strategy_title = "Crypto Daily"
        strategy_detail = "Macro: 1D estructura · 1W confirmacion · SMA20/40/100/200 · niveles clave"
    return {
        "symbol": normalized_symbol,
        "market": normalized_market,
        "timeframe": normalized_timeframe,
        "candles": rows,
        "lines": {
            "EMA9": _line("ema9"),
            "EMA20": _line("ema20"),
            "EMA21": _line("ema21"),
            "SMA20": _line("sma20"),
            "SMA40": _line("sma40"),
            "SMA100": _line("sma100"),
            "SMA200": _line("sma200"),
            "BB Upper": _line("bb_upper"),
            "BB Mid": _line("bb_mid"),
            "BB Lower": _line("bb_lower"),
        },
        "lineColors": {
            "EMA9": "#d946ef",
            "EMA20": "#60a5fa",
            "EMA21": "#a855f7",
            "SMA20": "#22c55e",
            "SMA40": "#38bdf8",
            "SMA100": "#f59e0b",
            "SMA200": "#ef4444",
            "BB Upper": "#cbd5e1",
            "BB Mid": "#94a3b8",
            "BB Lower": "#cbd5e1",
        },
        "defaultIndicators": default_indicators,
        "strategy": {
            "profile": profile_key,
            "title": strategy_title,
            "detail": strategy_detail,
            "role": text_display(trade_plan.get("strategy_role")),
            "timeframes": text_display(trade_plan.get("strategy_timeframes")),
        },
        "live": {
            "price": safe_float(live_price.get("price")),
            "freshness": text_display(live_price.get("freshness")),
            "source": text_display(live_price.get("source")),
            "ageSeconds": safe_float(live_price.get("age_seconds")),
            "observedAt": text_display(live_price.get("observed_at")),
            "marketOpen": live_price.get("market_open"),
        },
        "tradePlan": {
            "action": text_display(trade_plan.get("action")),
            "tone": text_display(trade_plan.get("tone")),
            "planStatus": text_display(trade_plan.get("plan_status")),
            "entry": safe_float(trade_plan.get("entry")),
            "stop": safe_float(trade_plan.get("stop")),
            "target2": safe_float(trade_plan.get("target_2")),
            "target5": safe_float(trade_plan.get("target_5")),
            "target10": safe_float(trade_plan.get("target_10")),
            "entryZoneLow": safe_float(trade_plan.get("entry_zone_low")),
            "entryZoneHigh": safe_float(trade_plan.get("entry_zone_high")),
            "rrTo2": safe_float(trade_plan.get("rr_to_2")),
        },
        "stream": {
            "enabled": normalized_market == "crypto",
            "provider": (
                "BinanceUS WebSocket + REST fallback"
                if normalized_market == "crypto"
                else f"{text_display(live_price.get('source') or 'quote')} + historial"
            ),
            "mode": "WEBSOCKET_MARKET_STREAM" if normalized_market == "crypto" else "SERVER_HISTORY",
            "wsBase": "wss://stream.binance.us:9443",
            "symbols": binanceus_symbol_candidates(normalized_symbol),
            "interval": chart_stream_binance_interval(normalized_timeframe),
            "intervalSeconds": chart_stream_interval_seconds(normalized_timeframe),
            "tickerMs": 2000,
            "klineMs": 30000,
        },
    }


def trade_desk_timeframe_pair(timeframe: Any) -> tuple[str, str]:
    tf = normalize_command_timeframe(timeframe)
    if tf == "1m":
        return "5m", "1m"
    if tf == "5m":
        return "15m", "5m"
    if tf == "15m":
        return "1h", "15m"
    if tf == "1h":
        return "1h", "15m"
    if tf == "2h":
        return "2h", "15m"
    if tf == "4h":
        return "4h", "1h"
    if tf == "1d":
        return "1d", "1h"
    if tf == "1w":
        return "1w", "1d"
    return "1h", "15m"


@st.cache_data(ttl=20, show_spinner=False)
def cached_trade_desk_chart_df(symbol: str, market: str, timeframe: str) -> pd.DataFrame:
    resolved_symbol = resolve_symbol_query(symbol, market)
    normalized_timeframe = normalize_command_timeframe(timeframe)
    try:
        history, _data_source = fetch_symbol_history_with_source(
            resolved_symbol,
            market=market,
            timeframe=normalized_timeframe,
        )
    except Exception:
        history = fetch_direct_yfinance_ohlcv(resolved_symbol, normalized_timeframe)
    if history is None or history.empty:
        history = fetch_direct_yfinance_ohlcv(resolved_symbol, normalized_timeframe)
    return prepare_symbol_chart_data(history)


def chart_df_for_trade_desk_pane(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    selected_timeframe: str,
    pane_timeframe: str,
) -> pd.DataFrame:
    if normalize_command_timeframe(selected_timeframe) == normalize_command_timeframe(pane_timeframe):
        return chart_df
    try:
        pane_df = cached_trade_desk_chart_df(symbol, market, pane_timeframe)
        return pane_df if isinstance(pane_df, pd.DataFrame) and not pane_df.empty else chart_df
    except Exception:
        return chart_df


TRADE_DESK_CHART_HEIGHT = 520


def render_browser_live_candle_chart(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
    live_price: dict[str, Any] | None = None,
    trade_plan: dict[str, Any] | None = None,
    height: int = TRADE_DESK_CHART_HEIGHT,
) -> bool:
    left_tf, right_tf = trade_desk_timeframe_pair(timeframe)
    left_df = chart_df_for_trade_desk_pane(
        chart_df,
        symbol=symbol,
        market=market,
        selected_timeframe=timeframe,
        pane_timeframe=left_tf,
    )
    right_df = chart_df_for_trade_desk_pane(
        chart_df,
        symbol=symbol,
        market=market,
        selected_timeframe=timeframe,
        pane_timeframe=right_tf,
    )
    if left_df.empty and right_df.empty:
        return False
    st.markdown(
        (
            '<div class="dual-chart-contract-strip" '
            'style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;'
            'margin:3px 0 5px;padding:4px 8px;border:1px solid rgba(34,197,94,.24);'
            'border-radius:6px;background:rgba(15,23,42,.62);color:#cbd5e1;font-size:11px;">'
            '<strong>2 GRAFICAS LIVE</strong>'
            f"<span>{html.escape(text_display(symbol).upper())} · {html.escape(left_tf)} + {html.escape(right_tf)}</span>"
            "<span>EMA9 · Avg20/40 · Bollinger · volumen · sin recargar</span>"
            "</div>"
        ),
        unsafe_allow_html=True,
    )
    left, right = st.columns([1, 1], gap="small")
    rendered = False
    with left:
        rendered = (
            render_browser_live_candle_chart_panel(
                left_df,
                symbol=symbol,
                market=market,
                timeframe=left_tf,
                live_price=live_price,
                trade_plan=trade_plan,
                height=height,
                panel_label="Tendencia",
            )
            or rendered
        )
    with right:
        rendered = (
            render_browser_live_candle_chart_panel(
                right_df,
                symbol=symbol,
                market=market,
                timeframe=right_tf,
                live_price=live_price,
                trade_plan=trade_plan,
                height=height,
                panel_label="Entrada",
            )
            or rendered
        )
    return rendered


