def source_memory_bias_for_opportunity(
    row: dict[str, Any] | None,
    lookup: dict[tuple[str, str], dict[str, Any]] | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    data_status = opportunity_data_source_bucket(row)
    bucket = text_display(data_status.get("bucket"))
    source = text_display(data_status.get("source"))
    source_lookup = lookup if isinstance(lookup, dict) else {}
    bias = source_lookup.get((bucket, source)) or source_lookup.get((bucket, "*"))
    if bias:
        return bias
    return {
        "label": "Aprendiendo",
        "tone": "watch",
        "detail": f"{bucket} / {source} | sin muestra paper suficiente",
        "action": "Registrar resultados paper antes de confiar en esta fuente.",
        "priority_delta": 0,
        "tracked": 0,
        "hit_2_rate": 0.0,
        "hit_5_rate": 0.0,
        "stop_rate": 0.0,
    }


def strategy_source_memory_bias_from_summary_row(row: dict[str, Any] | None, *, min_sample: int = 3) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    strategy = text_display(row.get("strategy_family"))
    base = source_memory_bias_from_summary_row(row, min_sample=min_sample)
    label_map = {
        "Aprendiendo": "Aprendiendo setup+fuente",
        "Memoria fuente negativa": "Memoria setup+fuente negativa",
        "Memoria fuente positiva": "Memoria setup+fuente positiva",
        "Memoria fuente neutral": "Memoria setup+fuente neutral",
    }
    action_map = {
        "Aprendiendo setup+fuente": "No bloquear; falta muestra paper de esta estrategia con esta fuente.",
        "Memoria setup+fuente negativa": "Bajar prioridad: esta estrategia con esta fuente fallo en paper.",
        "Memoria setup+fuente positiva": "Setup+fuente favorecido; exigir entrada, stop, target y datos live.",
        "Memoria setup+fuente neutral": "Mantener prioridad normal; sin edge claro en esta combinacion.",
    }
    label = label_map.get(base["label"], "Aprendiendo setup+fuente")
    detail = f"{strategy} | {base['detail']}"
    return {
        **base,
        "label": label,
        "detail": detail,
        "action": action_map[label],
    }


def strategy_source_memory_lookup_from_summary(
    summary: Any, *, min_sample: int = 3
) -> dict[tuple[str, str, str], dict[str, Any]]:
    if isinstance(summary, pd.DataFrame):
        records = summary.to_dict("records")
    elif isinstance(summary, list):
        records = [item for item in summary if isinstance(item, dict)]
    elif isinstance(summary, dict):
        records = [item for item in summary.values() if isinstance(item, dict)]
    else:
        records = []
    lookup: dict[tuple[str, str, str], dict[str, Any]] = {}
    for row in records:
        strategy = text_display(row.get("strategy_family"))
        bucket = text_display(row.get("data_bucket"))
        source = text_display(row.get("data_source"))
        if strategy == "-" or bucket == "-":
            continue
        bias = strategy_source_memory_bias_from_summary_row(row, min_sample=min_sample)
        lookup[(strategy, bucket, source)] = bias
        fallback_key = (strategy, bucket, "*")
        current = lookup.get(fallback_key)
        if current is None or int(bias.get("tracked") or 0) > int(current.get("tracked") or 0):
            lookup[fallback_key] = bias
    return lookup


