def backtest_memory_bias_from_summary_row(row: dict[str, Any] | None, *, min_sample: int = 10) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    strategy = text_display(row.get("strategy_family"))
    timeframe = text_display(row.get("timeframe"))
    symbol = text_display(row.get("symbol")).upper()
    source = text_display(row.get("source"))
    trades = int(safe_float(row.get("trades")) or 0)
    win_rate = safe_float(row.get("win_rate")) or 0.0
    profit_factor = safe_float(row.get("profit_factor"))
    avg_r = safe_float(row.get("avg_r")) or 0.0
    max_drawdown_pct = safe_float(row.get("max_drawdown_pct")) or 0.0
    if profit_factor is None:
        profit_factor = 0.0
    if trades < max(1, int(min_sample)):
        label = "Backtest aprendiendo"
        tone = "watch"
        action = "No subir ni bloquear; falta muestra historica suficiente."
        priority_delta = 0
    elif profit_factor >= 1.35 and avg_r > 0 and max_drawdown_pct <= 0.15 and win_rate >= 0.45:
        label = "Backtest positivo"
        tone = "buy"
        action = "Subir prioridad si los gates live, entrada, stop y eventos tambien pasan."
        priority_delta = 1
    elif profit_factor < 1.0 or avg_r < 0 or max_drawdown_pct >= 0.25:
        label = "Backtest negativo"
        tone = "avoid"
        action = "Bajar prioridad: historicamente este setup/timeframe fue debil."
        priority_delta = -1
    else:
        label = "Backtest neutral"
        tone = "watch"
        action = "Mantener prioridad normal; evidencia historica sin edge claro."
        priority_delta = 0
    detail = (
        f"{strategy} | {timeframe} | {symbol or '*'} | {source or '*'} | n={trades} | "
        f"win {pct_display(win_rate)} | PF {num_display(profit_factor, 2)} | "
        f"avgR {num_display(avg_r, 2)} | DD {pct_display(max_drawdown_pct)}"
    )
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "action": action,
        "priority_delta": priority_delta,
        "trades": trades,
        "win_rate": win_rate,
        "profit_factor": profit_factor,
        "avg_r": avg_r,
        "max_drawdown_pct": max_drawdown_pct,
    }


def backtest_memory_lookup_from_summary(
    summary: Any, *, min_sample: int = 10
) -> dict[tuple[str, str, str, str], dict[str, Any]]:
    if isinstance(summary, pd.DataFrame):
        records = summary.to_dict("records")
    elif isinstance(summary, list):
        records = [item for item in summary if isinstance(item, dict)]
    elif isinstance(summary, dict):
        records = [item for item in summary.values() if isinstance(item, dict)]
    else:
        records = []
    lookup: dict[tuple[str, str, str, str], dict[str, Any]] = {}

    def put_best(key: tuple[str, str, str, str], bias: dict[str, Any]) -> None:
        current = lookup.get(key)
        current_trades = int((current or {}).get("trades") or 0)
        bias_trades = int(bias.get("trades") or 0)
        if current is None or bias_trades > current_trades:
            lookup[key] = bias

    for row in records:
        strategy = text_display(row.get("strategy_family"))
        timeframe = text_display(row.get("timeframe"))
        symbol = text_display(row.get("symbol")).upper()
        source = text_display(row.get("source"))
        if strategy == "-" and timeframe == "-":
            continue
        bias = backtest_memory_bias_from_summary_row(row, min_sample=min_sample)
        put_best((strategy, timeframe, symbol, source), bias)
        put_best((strategy, timeframe, symbol, "*"), bias)
        put_best((strategy, timeframe, "*", "*"), bias)
        put_best((strategy, "*", "*", "*"), bias)
        if symbol != "-":
            put_best(("*", timeframe, symbol, "*"), bias)
    return lookup


