def backtest_memory_bias_for_opportunity(
    row: dict[str, Any] | None,
    lookup: dict[tuple[str, str, str, str], dict[str, Any]] | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    strategy = dashboard_strategy_label(row)
    timeframe = text_display(row.get("timeframe") or row.get("tf") or "1h")
    symbol = text_display(row.get("symbol")).upper()
    source = text_display(row.get("backtest_source") or row.get("source") or "*")
    memory_lookup = lookup if isinstance(lookup, dict) else {}
    keys = [
        (strategy, timeframe, symbol, source),
        (strategy, timeframe, symbol, "*"),
        (strategy, timeframe, "*", "*"),
        (strategy, "*", "*", "*"),
        ("*", timeframe, symbol, "*"),
    ]
    for key in keys:
        bias = memory_lookup.get(key)
        if bias:
            return bias
    return {
        "label": "Backtest aprendiendo",
        "tone": "watch",
        "detail": f"{strategy} | {timeframe} | {symbol} | sin muestra backtest suficiente",
        "action": "Correr mas backtests por estrategia/timeframe antes de subir peso.",
        "priority_delta": 0,
        "trades": 0,
        "win_rate": 0.0,
        "profit_factor": 0.0,
        "avg_r": 0.0,
        "max_drawdown_pct": 0.0,
    }


def crypto_context_memory_bias_from_summary_row(row: dict[str, Any] | None, *, min_sample: int = 3) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    tracked = int(safe_float(row.get("tracked")) or 0)
    hit_2_rate = safe_float(row.get("hit_2_rate")) or 0.0
    hit_5_rate = safe_float(row.get("hit_5_rate")) or 0.0
    hit_10_rate = safe_float(row.get("hit_10_rate")) or 0.0
    stop_rate = safe_float(row.get("stop_rate")) or 0.0
    open_count = int(safe_float(row.get("open")) or 0)
    symbol = text_display(row.get("symbol")).upper()
    timeframe = text_display(row.get("timeframe"))
    strategy = text_display(row.get("strategy_family"))
    source = text_display(row.get("data_source"))
    if tracked < max(1, int(min_sample)):
        label = "Aprendiendo crypto"
        tone = "watch"
        action = "No subir ni bloquear; falta muestra paper crypto cerrada."
        priority_delta = 0
    elif stop_rate > hit_2_rate:
        label = "Memoria crypto negativa"
        tone = "avoid"
        action = "Bajar prioridad: este contexto crypto fallo en paper."
        priority_delta = -1
    elif hit_2_rate > stop_rate:
        label = "Memoria crypto positiva"
        tone = "buy"
        action = "Subir prioridad si entrada, stop, target y datos live siguen validos."
        priority_delta = 1
    else:
        label = "Memoria crypto neutral"
        tone = "watch"
        action = "Mantener prioridad normal; sin edge crypto claro."
        priority_delta = 0
    detail = (
        f"{symbol} | {timeframe} | {strategy} | {source} | n={tracked} | "
        f"2% {pct_display(hit_2_rate)} | 5% {pct_display(hit_5_rate)} | "
        f"10% {pct_display(hit_10_rate)} | stop {pct_display(stop_rate)} | abiertas {open_count}"
    )
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "action": action,
        "priority_delta": priority_delta,
        "tracked": tracked,
        "hit_2_rate": hit_2_rate,
        "hit_5_rate": hit_5_rate,
        "hit_10_rate": hit_10_rate,
        "stop_rate": stop_rate,
        "open": open_count,
    }


def crypto_context_memory_lookup_from_summary(
    summary: Any, *, min_sample: int = 3
) -> dict[tuple[str, str, str, str], dict[str, Any]]:
    if isinstance(summary, pd.DataFrame):
        records = summary.to_dict("records")
    elif isinstance(summary, list):
        records = [item for item in summary if isinstance(item, dict)]
    elif isinstance(summary, dict):
        records = [item for item in summary.values() if isinstance(item, dict)]
    else:
        records = []
    lookup: dict[tuple[str, str, str, str], dict[str, Any]] = {}

    def put_best(key: tuple[str, str, str, str], bias: dict[str, Any]) -> None:
        current = lookup.get(key)
        if current is None or int(bias.get("tracked") or 0) > int(current.get("tracked") or 0):
            lookup[key] = bias

    for row in records:
        symbol = text_display(row.get("symbol")).upper()
        timeframe = text_display(row.get("timeframe"))
        strategy = text_display(row.get("strategy_family"))
        source = text_display(row.get("data_source"))
        if symbol == "-" and strategy == "-":
            continue
        bias = crypto_context_memory_bias_from_summary_row(row, min_sample=min_sample)
        put_best((symbol, timeframe, strategy, source), bias)
        put_best((symbol, timeframe, strategy, "*"), bias)
        put_best((symbol, "*", strategy, "*"), bias)
        put_best((symbol, "*", "*", "*"), bias)
        put_best(("*", timeframe, strategy, "*"), bias)
        put_best(("*", "*", strategy, "*"), bias)
    return lookup


