    return (
        f'<section class="chart-data-contract chart-data-contract-{html.escape(tone)}">'
        '<header><span>Contrato de datos</span>'
        f'<strong>{html.escape(text_display(contract.get("label")))}</strong>'
        f'<em>{html.escape(text_display(contract.get("detail")))}</em></header>'
        f"<aside>{field_html}</aside>"
        f'<p>{html.escape(text_display(contract.get("action")))}</p>'
        "</section>"
    )


