def notification_channel_display(rows: list[dict] | pd.DataFrame) -> pd.DataFrame:
    df = pd.DataFrame(rows)
    if df.empty:
        return df
    if "channel" in df.columns:
        df["channel"] = df["channel"].map(
            lambda value: NOTIFICATION_CHANNEL_LABELS.get(str(value), text_display(value))
        )
    if "configured" in df.columns:
        df["status"] = df["configured"].map(lambda value: "Listo" if value else "Falta configurar")
    if "notes" in df.columns:
        df["notes"] = df["notes"].map(lambda value: NOTIFICATION_NOTE_LABELS.get(str(value), text_display(value)))
    cols = [col for col in ["channel", "status", "requirements", "notes"] if col in df.columns]
    return df[cols].rename(
        columns={
            "channel": "Canal",
            "status": "Estado",
            "requirements": "Requisitos",
            "notes": "Notas",
        }
    )


def valid_lan_ip(value: Any) -> bool:
    text = str(value or "").strip()
    if not text or ":" in text:
        return False
    if text.startswith(("127.", "169.254.", "0.")):
        return False
    parts = text.split(".")
    if len(parts) != 4:
        return False
    try:
        return all(0 <= int(part) <= 255 for part in parts)
    except ValueError:
        return False


def local_ip_candidates() -> list[str]:
    candidates: list[str] = []

    def add(value: Any) -> None:
        text = str(value or "").strip()
        if valid_lan_ip(text) and text not in candidates:
            candidates.append(text)

    for iface in ["en0", "en1", "en2", "bridge100"]:
        try:
            result = subprocess.run(
                ["ipconfig", "getifaddr", iface], text=True, capture_output=True, timeout=1.5, check=False
            )
            add(result.stdout)
        except Exception:
            pass
    try:
        hostname = socket.gethostname()
        for item in socket.getaddrinfo(hostname, None, family=socket.AF_INET):
            add(item[4][0])
    except Exception:
        pass
    return candidates


def build_mobile_access_rows(
    *,
    local_ips: list[str],
    port: int | None,
    lan_ready: bool,
    public_url: str | None = None,
) -> list[dict[str, str]]:
    rows = []
    for ip in local_ips:
        rows.append(
            {
                "modo": "Misma Wi-Fi",
                "url": f"http://{ip}:{int(port or 3000)}",
                "estado": "Listo" if lan_ready else "Requiere abrir Streamlit en 0.0.0.0",
                "uso": "Telefono/tablet conectado a la misma red que la Mac.",
            }
        )
    if public_url:
        rows.append(
            {
                "modo": "Fuera de casa",
                "url": public_url,
                "estado": "Configurar seguridad",
                "uso": "Usar solo con tunel/VPN seguro y autenticacion.",
            }
        )
    elif not rows:
        rows.append(
            {
                "modo": "Pendiente",
                "url": "-",
                "estado": "No se detecto IP local",
                "uso": "Conecta la Mac a Wi-Fi o Ethernet y vuelve a revisar.",
            }
        )
    return rows


def mobile_access_status() -> dict[str, Any]:
    try:
        from tools import streamlit_launchd

        launchd_status = streamlit_launchd.status()
    except Exception as exc:
        launchd_status = {
            "installed": False,
            "loaded": False,
            "address": "-",
            "port": 3000,
            "lan_ready": False,
            "error": str(exc),
        }
    port = safe_float(launchd_status.get("port")) or 3000
    public_url = text_display(st.session_state.get("roxy_public_url"))
    if public_url == "-":
        public_url = ""
    local_ips = local_ip_candidates()
    rows = build_mobile_access_rows(
        local_ips=local_ips,
        port=int(port),
        lan_ready=bool(launchd_status.get("lan_ready")),
        public_url=public_url,
    )
    return {
        "launchd": launchd_status,
        "local_ips": local_ips,
        "public_url": public_url,
        "rows": rows,
        "port": int(port),
    }


def safe_float(value) -> float | None:
    if value is None:
        return None
    try:
        if pd.isna(value):
            return None
    except Exception:
        pass
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def platform_status_label(status: Any) -> str:
    raw = str(status or "-").upper()
    return PLATFORM_STATUS_LABELS.get(raw, text_display(status))


def platform_reason_label(reason: Any) -> str:
    raw = text_display(reason)
    if raw in PLATFORM_REASON_LABELS:
        return PLATFORM_REASON_LABELS[raw]
    if raw.startswith("Stocks/options are in "):
        session = raw.split("Stocks/options are in ", 1)[1].split(";", 1)[0]
        return f"Acciones/opciones estan en {session}. Usa Roxy para estudio hasta que reabra la sesion."
    return raw


def asset_type_label(asset_type: Any) -> str:
    raw = str(asset_type or "-").lower()
    return ASSET_TYPE_LABELS.get(raw, text_display(asset_type))


def action_label(action: Any) -> str:
    raw = str(action or "-").upper()
    return ACTION_LABELS.get(raw, text_display(action))


def connection_mode_label(mode: Any) -> str:
    raw = str(mode or "-").upper()
    return CONNECTION_MODE_LABELS.get(raw, text_display(mode))


def adapter_status_label(status: Any) -> str:
    raw = str(status or "-").upper()
    return ADAPTER_STATUS_LABELS.get(raw, text_display(status))


def execution_blocker_label(blocker: Any) -> str:
    raw = text_display(blocker)
    if raw in EXECUTION_BLOCKER_LABELS:
        return EXECUTION_BLOCKER_LABELS[raw]
    if raw.endswith("=1 is not set."):
        return "La ejecucion real sigue apagada por seguridad."
    if raw.startswith("Roxy status is "):
        status = raw.split("Roxy status is ", 1)[1].split(";", 1)[0]
        return f"Estado Roxy: {platform_status_label(status)}. Solo se puede armar cuando esta Listo para preparar."
    return raw


def center_decision_summary(row: dict) -> dict[str, str]:
    signal = str(row.get("signal") or "").upper()
    decision = str(row.get("decision") or row.get("trade_decision") or "").upper()
    action = str(row.get("action") or row.get("ai_action") or "").upper()
    if opportunity_is_trade_ready(row):
        status = "Operar"
        tone = "buy"
        headline = "Hay setup accionable, pero la orden sigue manual."
    elif signal == "AVOID" or decision.startswith("NO_TRADE"):
        status = "No operar"
        tone = "avoid"
        headline = "Roxy bloquea la operacion hasta que cambie la estructura."
    else:
        status = "Esperar"
        tone = "watch"
        headline = "Roxy esta esperando el gatillo exacto antes de entrar."
    return {
        "status": status,
        "tone": tone,
        "headline": human_alert_reason(row) or headline,
        "action": human_trade_action(row) if action or signal or decision else action_label(action or signal),
        "why": human_alert_reason(row),
        "wait_for": watch_movement_label(row),
        "changes_when": opportunity_change_label(row),
    }


def entry_exit_plan_engine(row: dict[str, Any] | None) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    entry = safe_float(row.get("entry") or row.get("price") or row.get("current_price"))
    stop = safe_float(row.get("stop") or row.get("stop_loss"))
    latest = safe_float(row.get("current_price") or row.get("price") or row.get("last") or entry)
    risk_pct = safe_float(row.get("risk_pct"))
    targets = command_center_target_prices(row)
    target_2 = safe_float(targets.get("target_2"))
    target_5 = safe_float(targets.get("target_5"))
    target_10 = safe_float(targets.get("target_10"))
    data_bucket = text_display(row.get("data_bucket"))
    signal = text_display(row.get("signal")).upper()
    decision = text_display(row.get("decision") or row.get("trade_decision")).upper()
    ready = opportunity_has_paper_trigger(row)
    blockers: list[str] = []
    if entry is None or entry <= 0:
        blockers.append("falta entrada")
    if stop is None or stop <= 0:
        blockers.append("falta stop")
    if entry is not None and stop is not None and entry <= stop:
        blockers.append("entrada debe estar sobre stop")
    if target_2 is None:
        blockers.append("target 2% no calculado")
    if risk_pct is not None and risk_pct > 0.035:
        blockers.append("riesgo mayor a 3.5%")
    if data_bucket in {"Bloqueadas", "Sin contrato"}:
        blockers.append("fuente de datos no operable")
    entry_zone_low = entry_zone_high = None
    chase_distance_pct = None
    if entry is not None and entry > 0:
        entry_zone_low = entry * 0.998
        entry_zone_high = entry * 1.003
        if latest is not None:
            chase_distance_pct = (latest - entry) / entry
            if chase_distance_pct > 0.012:
                blockers.append("precio alejado de entrada")
    rr_to_2 = None
    if entry is not None and stop is not None and target_2 is not None and abs(entry - stop) > 0:
        rr_to_2 = abs(target_2 - entry) / abs(entry - stop)
        if rr_to_2 < 1.0:
            blockers.append("target 2% paga menos de 1R")
    if blockers:
        plan_status = "BLOCKED"
        tone = "avoid"
    elif ready:
        plan_status = "READY"
        tone = "buy"
    else:
        plan_status = "WAIT_CONFIRMATION"
        tone = "watch"
    confirmation_rule = "Esperar 15m BUY y 1h sosteniendo tendencia/volumen antes de entrar."
    if ready and not blockers:
        confirmation_rule = "Entrada paper/manual permitida solo si precio sigue dentro de zona y vela 15m no esta extendida."
    invalidation_rule = "No operar sin stop valido."
    if stop is not None:
        invalidation_rule = f"Invalida si pierde {price_display(stop)} o 1h cambia a AVOID."
    do_not_chase_rule = "No perseguir si el precio sale de la zona de entrada."
    if chase_distance_pct is not None:
        do_not_chase_rule = (
            f"No perseguir si esta >1.2% sobre entrada; distancia actual {chase_distance_pct:.2%}."
            if chase_distance_pct > 0.012
            else f"Precio dentro/cerca de zona; distancia actual {chase_distance_pct:.2%}."
        )
    return {
        "plan_status": plan_status,
        "tone": tone,
        "entry": entry,
        "entry_zone_low": entry_zone_low,
        "entry_zone_high": entry_zone_high,
        "stop": stop,
        "target_2": target_2,
        "target_5": target_5,
        "target_10": target_10,
        "rr_to_2": rr_to_2,
        "risk_pct": risk_pct,
        "latest": latest,
        "chase_distance_pct": chase_distance_pct,
        "blockers": blockers,
        "confirmation_rule": confirmation_rule,
        "invalidation_rule": invalidation_rule,
        "do_not_chase_rule": do_not_chase_rule,
        "signal": signal,
        "decision": decision,
    }


def entry_proximity_status(
    row: dict[str, Any] | None,
    plan: dict[str, Any] | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    plan = plan if isinstance(plan, dict) else entry_exit_plan_engine(row)
    latest = safe_float(
        row.get("current_price")
        or row.get("latest_price")
        or row.get("last_price")
        or row.get("last")
        or row.get("close")
        or row.get("price")
    )
    entry = safe_float(plan.get("entry") or row.get("entry"))
    stop = safe_float(plan.get("stop") or row.get("stop") or row.get("stop_loss"))
    low = safe_float(plan.get("entry_zone_low"))
    high = safe_float(plan.get("entry_zone_high"))
    if latest is None or entry is None or entry <= 0 or low is None or high is None:
        return {
            "state": "Sin precio",
            "tone": "watch",
            "distance_to_entry_pct": None,
            "distance_to_zone_pct": None,
            "priority_delta": -8,
            "detail": "Falta precio live o zona de entrada para medir proximidad.",
            "action": "Esperar precio live confirmado.",
        }

    distance_to_entry_pct = (latest - entry) / entry
    distance_to_zone_pct = 0.0
    state = "Entrada en zona"
    tone = "buy"
    priority_delta = 15
    detail = f"Precio {price_display(latest)} dentro de zona {price_display(low)} - {price_display(high)}."
    action = "Puede entrar paper/manual si los demas gates siguen OK."
    if stop is not None and latest <= stop:
        state = "Invalida"
        tone = "avoid"
        priority_delta = -35
        distance_to_zone_pct = (latest - low) / entry
        detail = f"Precio {price_display(latest)} perdio el stop {price_display(stop)}."
        action = "No operar; esperar nuevo setup."
    elif low <= latest <= high:
        distance_to_zone_pct = 0.0
    elif latest < low:
        distance_to_zone_pct = (latest - low) / entry
        if abs(distance_to_zone_pct) <= 0.006:
            state = "Cerca de entrada"
            tone = "watch"
            priority_delta = 6
            detail = f"Precio {price_display(latest)} esta debajo de la zona por {abs(distance_to_zone_pct):.2%}."
            action = "Esperar confirmacion 15m dentro de zona."
        else:
            state = "Esperar pullback"
            tone = "watch"
            priority_delta = -3
            detail = f"Precio {price_display(latest)} aun esta lejos bajo la zona por {abs(distance_to_zone_pct):.2%}."
            action = "Esperar recuperacion hacia la zona."
    else:
        distance_to_zone_pct = (latest - high) / entry
        if distance_to_entry_pct > 0.012:
            state = "No perseguir"
            tone = "avoid"
            priority_delta = -25
            detail = f"Precio {price_display(latest)} esta {distance_to_entry_pct:.2%} sobre entrada."
            action = "Esperar pullback; no perseguir vela extendida."
        else:
            state = "Cerca de entrada"
            tone = "watch"
            priority_delta = 4
            detail = f"Precio {price_display(latest)} esta apenas sobre la zona por {distance_to_zone_pct:.2%}."
            action = "Esperar pullback corto hacia la zona."
    return {
        "state": state,
        "tone": tone,
        "distance_to_entry_pct": distance_to_entry_pct,
        "distance_to_zone_pct": distance_to_zone_pct,
        "priority_delta": priority_delta,
        "detail": detail,
        "action": action,
        "latest": latest,
        "entry": entry,
        "stop": stop,
        "entry_zone_low": low,
        "entry_zone_high": high,
    }


def entry_proximity_alert_event(row: dict[str, Any] | None) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    status = trade_decision_card_status(row)
    state = text_display(status.get("entry_proximity"))
    action = text_display(status.get("action"))
    symbol = text_display(status.get("symbol") or row.get("symbol")).upper()
    entry = safe_float(status.get("entry"))
    stop = safe_float(status.get("stop"))
    latest = safe_float(row.get("current_price") or row.get("latest_price") or row.get("last_price") or row.get("last") or row.get("price"))
    should_alert = state == "Entrada en zona" and action == "Entrar paper/manual"
    tone = text_display(status.get("entry_proximity_tone"))
    priority = 0
    if should_alert:
        priority = 100
    elif state == "Cerca de entrada":
        priority = 65
    elif state in {"No perseguir", "Invalida"}:
        priority = 20
    else:
        priority = 40
    message = (
        f"{symbol} | {state} | precio {price_display(latest)} | entrada {price_display(entry)} | stop {price_display(stop)}"
        if symbol != "-"
        else f"{state} | precio {price_display(latest)} | entrada {price_display(entry)}"
    )
    return {
        "state": state,
        "tone": tone,
        "priority": priority,
        "should_alert": should_alert,
        "message": message,
        "action": text_display(status.get("entry_proximity_action")),
        "detail": text_display(status.get("entry_proximity_detail")),
        "decision_action": action,
        "entry": entry,
        "stop": stop,
        "target_2": safe_float(status.get("target_2")),
        "target_5": safe_float(status.get("target_5")),
        "target_10": safe_float(status.get("target_10")),
        "rr_to_2": safe_float(status.get("rr_to_2")),
        "risk_pct": safe_float(status.get("risk_pct")),
        "distance_to_entry_pct": safe_float(status.get("entry_distance_pct")),
    }


def actionable_alert_state(
    row: dict[str, Any] | None,
    *,
    status: dict[str, Any] | None = None,
    alert_event: dict[str, Any] | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    status = status if isinstance(status, dict) else trade_decision_card_status(row)
    alert_event = alert_event if isinstance(alert_event, dict) else entry_proximity_alert_event(row)
    action = text_display(status.get("action"))
    entry_state = text_display(status.get("entry_proximity") or alert_event.get("state"))
    symbol = text_display(status.get("symbol") or row.get("symbol")).upper()
    entry = safe_float(status.get("entry") or alert_event.get("entry"))
    stop = safe_float(status.get("stop") or alert_event.get("stop"))
    target_2 = safe_float(status.get("target_2") or alert_event.get("target_2"))
    reason = text_display(status.get("reason") or alert_event.get("detail"))
    if action == "Entrar paper/manual" and entry_state == "Entrada en zona":
        state = "Entra ahora"
        tone = "buy"
        priority = 100
        instruction = "Entrada paper/manual en zona; orden real OFF."
    elif action == "Esperar pullback" or entry_state in {"No perseguir", "Esperar pullback"}:
        state = "Espera pullback"
        tone = "watch"
        priority = 70
        instruction = "No perseguir; esperar que vuelva a zona limpia."
    elif action == "No operar" or entry_state == "Invalida":
        state = "No operar"
        tone = "avoid"
        priority = 90
        instruction = "Setup bloqueado o invalidado; no abrir paper/manual."
    elif action == "Confirmar externo":
        state = "Confirmar externo"
        tone = "watch"
        priority = 55
        instruction = "Confirmar TradingView/broker antes de actuar."
    else:
        state = "Vigilar"
        tone = "watch"
        priority = 40
        instruction = "Esperar confirmacion; no alertar telefono."
    message = (
        f"{symbol} | {state.upper()} | entrada {price_display(entry)} | "
        f"stop {price_display(stop)} | target 2% {price_display(target_2)} | {instruction}"
    )
    return {
        "state": state,
        "tone": tone,
        "priority": priority,
        "should_alert_state": state in {"Entra ahora", "Espera pullback", "No operar"},
        "message": message,
        "instruction": instruction,
        "reason": reason,
        "entry": entry,
        "stop": stop,
        "target_2": target_2,
    }


def action_state_from_snapshot(previous: dict[str, Any] | str | None) -> str:
    if isinstance(previous, dict):
        value = text_display(previous.get("actionable_state") or previous.get("action_state"))
        if value != "-":
            return value
        state = text_display(previous.get("state"))
        dashboard_state = text_display(previous.get("dashboard_state"))
    else:
        state = text_display(previous)
        dashboard_state = "-"
    if dashboard_state in {"Entrada en zona", "Lista paper/manual"} and state == "Entrada en zona":
        return "Entra ahora"
    if dashboard_state == "No operar" or state == "Invalida":
        return "No operar"
    if dashboard_state == "Esperar pullback" or state == "No perseguir":
        return "Espera pullback"
    if state in {"Cerca de entrada", "Sin precio", "Esperar pullback"}:
        return "Vigilar"
    return "-"


def actionable_alert_transition_event(
    *,
    symbol: Any,
    market: Any,
    current_state: Any,
    previous_snapshot: dict[str, Any] | None,
    alert_state: dict[str, Any] | None = None,
) -> dict[str, Any]:
    previous_snapshot = previous_snapshot if isinstance(previous_snapshot, dict) else {}
    positions = previous_snapshot.get("positions") if isinstance(previous_snapshot.get("positions"), dict) else previous_snapshot
    key = entry_proximity_state_key(symbol, market)
    previous = positions.get(key) if isinstance(positions, dict) else {}
    previous_state = action_state_from_snapshot(previous)
    current = text_display(current_state)
    changed = previous_state not in {"-", current}
    should_notify = bool(changed and current in {"Entra ahora", "Espera pullback", "No operar"})
    transition = f"{previous_state} -> {current}" if changed else current
    if previous_state == "-":
        transition = f"Nuevo -> {current}"
    return {
        "key": key,
        "previous_state": previous_state,
        "current_state": current,
        "changed": changed,
        "should_notify": should_notify,
        "transition": transition,
        "message": text_display((alert_state or {}).get("message")),
        "tone": text_display((alert_state or {}).get("tone")),
        "priority": safe_float((alert_state or {}).get("priority")) or 0,
    }


def entry_proximity_state_key(symbol: Any, market: Any = "") -> str:
    symbol_text = text_display(symbol).upper()
    market_text = text_display(market).lower()
    if symbol_text == "-":
        symbol_text = "UNKNOWN"
    if market_text == "-":
        market_text = ""
    return f"{market_text}:{symbol_text}" if market_text else symbol_text


def read_entry_proximity_state(path: Path = ENTRY_PROXIMITY_STATE_FILE) -> dict[str, Any]:
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def write_entry_proximity_state(state: dict[str, Any], path: Path = ENTRY_PROXIMITY_STATE_FILE) -> None:
    payload = {
        "updated_at": datetime.utcnow().isoformat() + "Z",
        "positions": state if isinstance(state, dict) else {},
    }
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp_path = path.with_suffix(path.suffix + ".tmp")
        tmp_path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")
        tmp_path.replace(path)
    except Exception:
        return


def entry_proximity_transition_event(
    *,
    symbol: Any,
    market: Any,
    current_state: Any,
    previous_snapshot: dict[str, Any] | None,
    alert_event: dict[str, Any] | None = None,
) -> dict[str, Any]:
    previous_snapshot = previous_snapshot if isinstance(previous_snapshot, dict) else {}
    positions = previous_snapshot.get("positions") if isinstance(previous_snapshot.get("positions"), dict) else previous_snapshot
    key = entry_proximity_state_key(symbol, market)
    previous = positions.get(key) if isinstance(positions, dict) else {}
    previous_state = text_display((previous or {}).get("state") if isinstance(previous, dict) else previous)
    current = text_display(current_state)
    changed = previous_state not in {"-", current}
    entered_zone = changed and current == "Entrada en zona"
    invalidated = changed and current == "Invalida"
    should_notify = bool(entered_zone and (alert_event or {}).get("should_alert"))
    transition = f"{previous_state} -> {current}" if changed else current
    if previous_state == "-":
        transition = f"Nuevo -> {current}"
    return {
        "key": key,
        "previous_state": previous_state,
        "current_state": current,
        "changed": changed,
        "entered_zone": entered_zone,
        "invalidated": invalidated,
        "should_notify": should_notify,
        "transition": transition,
        "message": text_display((alert_event or {}).get("message")),
    }


def entry_proximity_snapshot_from_alert_rows(rows: pd.DataFrame | list[dict[str, Any]]) -> dict[str, Any]:
    records = rows.to_dict("records") if isinstance(rows, pd.DataFrame) else list(rows or [])
    positions: dict[str, Any] = {}
    for row in records:
        if not isinstance(row, dict):
            continue
        symbol = text_display(row.get("Ticker") or row.get("symbol")).upper()
        market = text_display(row.get("_market") or row.get("market") or row.get("Mercado"))
        state = text_display(row.get("Estado entrada") or row.get("entry_proximity"))
        if symbol == "-" or state == "-":
            continue
        key = entry_proximity_state_key(symbol, market)
        positions[key] = {
            "symbol": symbol,
            "market": market,
            "state": state,
            "dashboard_state": text_display(row.get("Estado")),
            "actionable_state": text_display(row.get("Decision alerta") or row.get("actionable_state")),
            "actionable_transition": text_display(row.get("Cambio decision") or row.get("actionable_transition")),
            "updated_at": datetime.utcnow().isoformat() + "Z",
        }
    return positions


def actionable_alert_transition_messages(rows: pd.DataFrame | list[dict[str, Any]]) -> list[str]:
    records = rows.to_dict("records") if isinstance(rows, pd.DataFrame) else list(rows or [])
    messages: list[str] = []
    for row in records:
        if not isinstance(row, dict) or not bool(row.get("_action_transition_alert")):
            continue
        symbol = text_display(row.get("Ticker")).upper()
        action_state = text_display(row.get("Decision alerta"))
        change = text_display(row.get("Cambio decision"))
        detail = text_display(row.get("Detalle decision") or row.get("Detalle entrada"))
        next_action = text_display(row.get("Siguiente accion") or row.get("Accion decision"))
        messages.append(f"{symbol} | {action_state.upper()} | {change} | {detail} | {next_action} | Orden real OFF")
    return messages


def entry_proximity_transition_messages(rows: pd.DataFrame | list[dict[str, Any]]) -> list[str]:
    records = rows.to_dict("records") if isinstance(rows, pd.DataFrame) else list(rows or [])
    messages: list[str] = []
