def trade_decision_card_status(row: dict[str, Any] | None) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    symbol = text_display(row.get("symbol")).upper()
    market = text_display(row.get("market"))
    signal = text_display(row.get("signal")).upper()
    decision = text_display(row.get("decision") or row.get("trade_decision")).upper()
    data_bucket = text_display(row.get("data_bucket"))
    data_state = text_display(row.get("data_state"))
    data_gate = text_display(row.get("data_gate"))
    source_memory = text_display(row.get("source_memory_bias"))
    strategy_source_memory = text_display(row.get("strategy_source_memory_bias"))
    crypto_context_memory = text_display(row.get("crypto_context_memory_bias"))
    backtest_memory = text_display(row.get("backtest_memory_bias"))
    tradingview_confirmation = text_display(row.get("tradingview_confirmation"))
    market_event_state = text_display(
        row.get("market_event_state")
        or row.get("event_state")
        or row.get("macro_event_state")
        or row.get("earnings_event_state")
    )
    plan = entry_exit_plan_engine(row)
    entry = safe_float(plan.get("entry"))
    stop = safe_float(plan.get("stop"))
    target_2 = safe_float(plan.get("target_2"))
    target_5 = safe_float(plan.get("target_5"))
    target_10 = safe_float(plan.get("target_10"))
    risk_pct = safe_float(row.get("risk_pct"))
    readiness = safe_float(row.get("readiness") or row.get("alert_readiness_score"))
    proximity = entry_proximity_status(row, plan)
    proximity_state = text_display(proximity.get("state"))
    if data_bucket in {"Bloqueadas", "Sin contrato"}:
        action = "No operar"
        tone = "avoid"
        reason = "Datos bloqueados o sin contrato operable."
    elif market_event_state in {"Evento macro activo", "Earnings cercanos"}:
        action = "No operar"
        tone = "avoid"
        reason = text_display(row.get("market_event_detail") or row.get("market_event_action"))
    elif market_event_state in {"Evento macro proximo", "Earnings revisar"}:
        action = "Esperar"
        tone = "watch"
        reason = text_display(row.get("market_event_detail") or row.get("market_event_action"))
    elif tradingview_confirmation == "TradingView contradice":
        action = "Esperar"
        tone = "watch"
        reason = "TradingView webhook reciente contradice la entrada."
    elif strategy_source_memory == "Memoria setup+fuente negativa":
        action = "No operar"
        tone = "avoid"
        reason = "La combinacion estrategia + fuente fallo en paper."
    elif crypto_context_memory == "Memoria crypto negativa":
        action = "Esperar"
        tone = "watch"
        reason = "La memoria crypto de este ticker/timeframe/fuente fallo en paper."
    elif backtest_memory == "Backtest negativo":
        action = "Esperar"
        tone = "watch"
        reason = "El backtest de esta estrategia/timeframe fue debil."
    elif source_memory == "Memoria fuente negativa":
        action = "Esperar"
        tone = "watch"
        reason = "La fuente tiene memoria paper negativa."
    elif data_bucket == "Fallback":
        action = "Confirmar externo"
        tone = "watch"
        reason = "La idea viene de fallback publico; confirmar broker/TradingView."
    elif proximity_state == "Invalida":
        action = "No operar"
        tone = "avoid"
        reason = text_display(proximity.get("detail"))
    elif proximity_state == "No perseguir":
        action = "Esperar pullback"
        tone = "watch"
        reason = text_display(proximity.get("detail"))
    elif opportunity_has_paper_trigger(row) and plan.get("plan_status") == "READY" and proximity_state == "Entrada en zona":
        action = "Entrar paper/manual"
        tone = "buy"
        if tradingview_confirmation == "TradingView confirma" and not opportunity_is_trade_ready(row):
            reason = "TradingView BUY fresco confirma el gatillo paper; plan, precio y riesgo estan alineados."
        else:
            reason = human_alert_reason(row) or "Setup accionable con entrada, stop y target definidos."
    elif signal == "AVOID" or decision.startswith("NO_TRADE"):
        action = "No operar"
        tone = "avoid"
        reason = human_alert_reason(row) or "La estructura actual invalida el trade."
    else:
        action = "Esperar confirmacion"
        tone = "watch"
        reason = watch_movement_label(row) or "Falta gatillo de entrada confirmado."

    invalidation = text_display(plan.get("invalidation_rule"))
    partial_exit = "Parcial 2%, runner 5%, stretch 10%."
    if target_2 is not None and target_5 is not None and target_10 is not None:
        partial_exit = f"2% {price_display(target_2)} | 5% {price_display(target_5)} | 10% {price_display(target_10)}"
    if strategy_source_memory == "Memoria setup+fuente negativa":
        next_step = text_display(row.get("strategy_source_memory_action"))
    elif market_event_state in {"Evento macro activo", "Evento macro proximo", "Earnings cercanos", "Earnings revisar"}:
        next_step = text_display(row.get("market_event_action"))
    elif tradingview_confirmation == "TradingView contradice":
        next_step = text_display(row.get("tradingview_confirmation_action"))
    elif crypto_context_memory == "Memoria crypto negativa":
        next_step = text_display(row.get("crypto_context_memory_action"))
    elif backtest_memory == "Backtest negativo":
        next_step = text_display(row.get("backtest_memory_action"))
    elif source_memory == "Memoria fuente negativa":
        next_step = text_display(row.get("source_memory_action"))
    elif action in {"Confirmar externo", "No operar"}:
        next_step = text_display(row.get("data_source_action"))
    else:
        next_step = "-"
    if next_step == "-":
        next_step = text_display(
            row.get("waiting_for")
            or row.get("cambia_si")
            or row.get("next")
            or "Esperar siguiente actualizacion live."
        )
    return {
        "symbol": symbol,
        "market": market,
        "action": action,
        "tone": tone,
        "reason": reason,
        "entry": entry,
        "stop": stop,
        "target_2": target_2,
        "target_5": target_5,
        "target_10": target_10,
        "entry_zone_low": safe_float(plan.get("entry_zone_low")),
        "entry_zone_high": safe_float(plan.get("entry_zone_high")),
        "rr_to_2": safe_float(plan.get("rr_to_2")),
        "plan_status": text_display(plan.get("plan_status")),
        "risk_pct": risk_pct,
        "readiness": readiness,
        "data_bucket": data_bucket,
        "data_state": data_state,
        "data_gate": data_gate,
        "source_memory": source_memory,
        "strategy_source_memory": strategy_source_memory,
        "crypto_context_memory": crypto_context_memory,
        "backtest_memory": backtest_memory,
        "backtest_memory_action": text_display(row.get("backtest_memory_action")),
        "backtest_memory_detail": text_display(row.get("backtest_memory_detail")),
        "tradingview_confirmation": tradingview_confirmation,
        "tradingview_confirmation_action": text_display(row.get("tradingview_confirmation_action")),
        "tradingview_confirmation_detail": text_display(row.get("tradingview_confirmation_detail")),
        "market_event_state": market_event_state,
        "market_event_action": text_display(row.get("market_event_action")),
        "market_event_detail": text_display(row.get("market_event_detail")),
        "invalidation": invalidation,
        "partial_exit": partial_exit,
        "confirmation_rule": text_display(plan.get("confirmation_rule")),
        "do_not_chase_rule": text_display(plan.get("do_not_chase_rule")),
        "entry_proximity": proximity_state,
        "entry_proximity_tone": text_display(proximity.get("tone")),
        "entry_proximity_detail": text_display(proximity.get("detail")),
        "entry_proximity_action": text_display(proximity.get("action")),
        "entry_distance_pct": safe_float(proximity.get("distance_to_entry_pct")),
        "entry_zone_distance_pct": safe_float(proximity.get("distance_to_zone_pct")),
        "entry_proximity_priority_delta": safe_float(proximity.get("priority_delta")),
        "plan_blockers": list(plan.get("blockers") or []),
        "next_step": next_step,
    }


def compound_steps_required(starting_capital: float, target_capital: float, net_gain_pct: float) -> int | None:
    try:
        start = float(starting_capital)
        target = float(target_capital)
        gain = float(net_gain_pct)
    except (TypeError, ValueError):
        return None
    if start <= 0 or target <= start or gain <= 0:
        return 0
    return int(math.ceil(math.log(target / start) / math.log(1.0 + gain)))


def capital_growth_phase(equity: float) -> tuple[str, str, str]:
    if equity < 1_000:
        return (
            "Proteccion",
            "Fractional shares/crypto pequeno; opciones solo paper o debit muy bajo.",
            "La meta es sobrevivir y medir setups, no forzar trades.",
        )
    if equity < 5_000:
        return (
            "Base",
            "Acciones fraccionadas y calls/puts solo si max loss cabe en riesgo.",
            "Solo operar 1h + 15m confirmados; evitar revenge trades.",
        )
    if equity < 25_000:
        return (
            "Consistencia",
            "Acciones liquidas, opciones con DTE y spread controlado.",
            "Subir tamano solo despues de 20 senales cerradas con edge positivo.",
        )
    if equity < 100_000:
        return (
            "Escala controlada",
            "Acciones + opciones liquidas; evitar concentracion.",
            "Bajar riesgo despues de rachas negativas y proteger ganancias.",
        )
    if equity < 500_000:
        return (
            "Profesional",
            "Portafolio de setups, no una sola apuesta.",
            "Roxy prioriza drawdown bajo antes que crecimiento agresivo.",
        )
    return (
        "Preservacion",
        "Menos riesgo por trade, mas filtros y menos ruido.",
        "El objetivo cambia de crecer rapido a no devolver capital.",
    )


def build_million_growth_plan(
    starting_capital: float = 500.0,
    target_capital: float = 1_000_000.0,
    risk_per_trade_pct: float = 0.01,
) -> dict:
    start = max(1.0, float(starting_capital or 500.0))
    target = max(start, float(target_capital or 1_000_000.0))
    risk_pct = max(0.001, float(risk_per_trade_pct or 0.01))
    milestone_values = [500, 1_000, 2_500, 5_000, 10_000, 25_000, 50_000, 100_000, 250_000, 500_000, 1_000_000]
    milestone_values = sorted({float(value) for value in milestone_values if value >= start} | {target})

    previous = start
    rows = []
    for idx, milestone in enumerate(milestone_values, start=1):
        phase, products, rule = capital_growth_phase(previous)
        rows.append(
            {
                "stage": idx,
                "phase": phase,
                "from": previous,
                "target": milestone,
                "risk_per_trade": previous * risk_pct,
                "daily_stop": previous * risk_pct * 2.0,
                "trades_2pct": compound_steps_required(previous, milestone, 0.02),
                "trades_5pct": compound_steps_required(previous, milestone, 0.05),
                "trades_10pct": compound_steps_required(previous, milestone, 0.10),
                "products": products,
                "rule": rule,
            }
        )
        previous = milestone

    return {
        "starting_capital": start,
        "target_capital": target,
        "multiplier": target / start,
        "risk_per_trade_pct": risk_pct,
        "risk_per_trade": start * risk_pct,
        "daily_stop": start * risk_pct * 2.0,
        "max_option_debit": start * risk_pct,
        "guardrail": build_account_risk_guardrail(start, risk_pct),
        "steps_to_target": {
            "2%": compound_steps_required(start, target, 0.02),
            "5%": compound_steps_required(start, target, 0.05),
            "10%": compound_steps_required(start, target, 0.10),
        },
        "milestones": rows,
        "rules": [
            "No operar si Roxy no marca Operar o una alerta BUY con riesgo y target validos.",
            "Riesgo base 0.5% a 1% por trade; con $500, 1% son $5.",
            "Maximo 2R de perdida diaria; despues de eso Roxy debe pasar a modo esperar.",
            "Opciones solo si el max loss del contrato cabe en el riesgo definido; si no, mirar accion fraccionada o paper.",
            "Subir tamano solo cuando la memoria muestre que el setup llega a 2% mas veces de las que toca stop.",
            "Nunca promediar perdedor; el stop invalida la idea.",
        ],
    }


def build_account_risk_guardrail(
    account_equity: float = 500.0,
    risk_per_trade_pct: float = 0.01,
    *,
    planned_risk_dollars: float | None = None,
    realized_loss_today: float = 0.0,
    open_risk_dollars: float = 0.0,
) -> dict:
    equity = max(1.0, float(account_equity or 500.0))
    risk_pct = max(0.001, float(risk_per_trade_pct or 0.01))
    per_trade_budget = equity * risk_pct
    daily_stop = per_trade_budget * 2.0
    planned_risk = safe_float(planned_risk_dollars)
    if planned_risk is None:
        planned_risk = per_trade_budget
    used_risk = max(0.0, float(realized_loss_today or 0.0)) + max(0.0, float(open_risk_dollars or 0.0))
    remaining_daily_risk = max(0.0, daily_stop - used_risk)

    if used_risk >= daily_stop:
        status = "DAILY_STOP"
        allowed = False
        message = "Modo proteger capital: ya se alcanzo el stop diario 2R."
    elif planned_risk > per_trade_budget:
        status = "REDUCE_SIZE"
        allowed = False
        message = "Reducir tamano: el riesgo planeado supera el presupuesto por trade."
    elif planned_risk > remaining_daily_risk:
        status = "REDUCE_SIZE"
        allowed = False
        message = "Reducir tamano: no queda suficiente riesgo diario disponible."
    else:
        status = "OK"
        allowed = True
        message = "Riesgo permitido dentro del plan 1R por trade y 2R diario."

    return {
        "status": status,
        "allowed": allowed,
        "account_equity": equity,
        "risk_per_trade_pct": risk_pct,
        "per_trade_budget": per_trade_budget,
        "daily_stop": daily_stop,
        "used_risk": used_risk,
        "remaining_daily_risk": remaining_daily_risk,
        "planned_risk": planned_risk,
        "message": message,
    }


def paper_journal_operational_risk_state(
    alpaca_journal: pd.DataFrame | None = None,
    crypto_journal: pd.DataFrame | None = None,
    *,
    account_equity: float = 500.0,
    risk_per_trade_pct: float = 0.01,
    max_open_signals: int = 3,
    max_daily_stops: int = 2,
    now: datetime | None = None,
) -> dict[str, Any]:
    current_time = now or datetime.now(timezone.utc)
    current_day = current_time.date()
    frames: list[pd.DataFrame] = []
    for source, journal in (("alpaca", alpaca_journal), ("crypto", crypto_journal)):
        if isinstance(journal, pd.DataFrame) and not journal.empty:
            data = journal.copy()
            data["_paper_source"] = source
            frames.append(data)
    if frames:
        data = pd.concat(frames, ignore_index=True, sort=False)
    else:
        data = pd.DataFrame(columns=["status", "closed_at", "closed_outcome", "risk_dollars"])

    for column in ["status", "closed_at", "closed_outcome", "risk_dollars"]:
        if column not in data.columns:
            data[column] = None

    status = data["status"].fillna("").astype(str).str.strip().str.upper()
    closed_outcome = (
        data["closed_outcome"]
        .fillna("")
        .astype(str)
        .str.strip()
        .str.upper()
        .replace({"NAN": "", "NONE": "", "<NA>": "", "NULL": ""})
    )
    open_mask = status.eq("READY_FOR_PAPER") & ~status.str.startswith("CLOSED_") & closed_outcome.eq("")
    open_count = int(open_mask.sum())
    open_risk = float(pd.to_numeric(data.loc[open_mask, "risk_dollars"], errors="coerce").fillna(0).sum())

    closed_at = pd.to_datetime(data["closed_at"], errors="coerce", utc=True)
    closed_today_mask = closed_at.dt.date.eq(current_day)
    stops_today_mask = closed_today_mask & closed_outcome.eq("STOP")
    stops_today = int(stops_today_mask.sum())
    realized_loss_today = float(pd.to_numeric(data.loc[stops_today_mask, "risk_dollars"], errors="coerce").fillna(0).sum())

    guardrail = build_account_risk_guardrail(
        account_equity=account_equity,
        risk_per_trade_pct=risk_per_trade_pct,
        planned_risk_dollars=max(1.0, float(account_equity or 500.0) * float(risk_per_trade_pct or 0.01)),
        realized_loss_today=realized_loss_today,
        open_risk_dollars=open_risk,
    )
    max_open = max(1, int(max_open_signals or 3))
    max_stops = max(1, int(max_daily_stops or 2))
    daily_stop = safe_float(guardrail.get("daily_stop")) or 0.0
    used_risk = safe_float(guardrail.get("used_risk")) or 0.0

    blockers: list[str] = []
    warnings: list[str] = []
    if stops_today >= max_stops:
        blockers.append(f"{stops_today} stops paper hoy")
    if guardrail.get("status") == "DAILY_STOP":
        blockers.append("stop diario 2R alcanzado")
    if open_count >= max_open:
        blockers.append(f"{open_count} señales paper abiertas")
    if not blockers and daily_stop > 0 and used_risk >= daily_stop * 0.70:
        warnings.append("riesgo diario usado sobre 70%")
    if not blockers and open_count >= max_open - 1:
        warnings.append("cerca del máximo de señales abiertas")

    if blockers:
        state = "Modo proteccion"
        action = "No abrir nuevas entradas paper"
        tone = "avoid"
        allowed = False
        reason = "; ".join(dict.fromkeys(blockers))
    elif warnings:
        state = "Riesgo alto"
        action = "Solo mejor oportunidad, reducir tamaño"
        tone = "watch"
        allowed = True
        reason = "; ".join(dict.fromkeys(warnings))
    else:
        state = "Puede operar"
        action = "Paper permitido con gates activos"
        tone = "buy"
        allowed = bool(guardrail.get("allowed"))
        reason = text_display(guardrail.get("message"))

    return {
        "state": state,
        "action": action,
        "tone": tone,
        "allowed": allowed,
        "reason": reason,
        "open_signals": open_count,
        "max_open_signals": max_open,
        "stops_today": stops_today,
        "max_daily_stops": max_stops,
        "open_risk_dollars": round(open_risk, 2),
        "realized_loss_today": round(realized_loss_today, 2),
        "daily_stop": round(daily_stop, 2),
        "used_risk": round(used_risk, 2),
        "remaining_daily_risk": round(safe_float(guardrail.get("remaining_daily_risk")) or 0.0, 2),
        "guardrail_status": text_display(guardrail.get("status")),
        "guardrail_message": text_display(guardrail.get("message")),
    }


