    live_data_fresh = bool(summary.get("latest_live_data_fresh"))
    live_data_fresh_streak = int(summary.get("current_live_data_fresh_streak") or 0)
    live_scan_age_minutes = safe_float(summary.get("latest_live_scan_age_minutes"))
    confluence_age_minutes = safe_float(summary.get("latest_confluence_age_minutes"))
    notification_delivery_healthy = bool(summary.get("latest_notification_delivery_healthy"))
    notification_delivery_streak = int(summary.get("current_notification_delivery_healthy_streak") or 0)
    notification_delivery_mode = text_display(summary.get("latest_notification_delivery_mode") or "")
