    dashboard_probes_fresh = bool(summary.get("latest_dashboard_probes_fresh"))
    dashboard_probes_fresh_streak = int(summary.get("current_dashboard_probes_fresh_streak") or 0)
    dashboard_render_age_minutes = safe_float(summary.get("latest_dashboard_render_age_minutes"))
    dashboard_search_render_age_minutes = safe_float(summary.get("latest_dashboard_search_render_age_minutes"))
    dashboard_render_text_length = int(summary.get("latest_dashboard_render_text_length") or 0)
