def crypto_twenty_min_strike_rows(
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    symbols: list[str] | tuple[str, ...] | None = None,
    limit: int = 4,
    now: datetime | None = None,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "price",
        "direction",
        "strike",
        "distance_pct",
        "momentum_20m",
        "momentum_5m",
        "confidence",
        "action",
        "risk_dollars",
        "source",
        "expires_at",
        "minutes_to_expiry",
        "timer_state",
        "next_step",
        "tone",
        "href",
    ]
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    selected_symbols = list(dict.fromkeys(symbols or DEFAULT_CRYPTO_SYMBOLS))[: max(1, int(limit or 4))]
    current_time = (now or datetime.now(timezone.utc)).astimezone(timezone.utc)
    minute_block = (current_time.minute // 20 + 1) * 20
    expires_at = current_time.replace(second=0, microsecond=0)
    if minute_block >= 60:
        expires_at = expires_at.replace(minute=0) + timedelta(hours=1)
    else:
        expires_at = expires_at.replace(minute=minute_block)
    minutes_to_expiry = max(0.0, (expires_at - current_time).total_seconds() / 60.0)
    timer_state = "Ventana valida" if 8.0 <= minutes_to_expiry <= 18.5 else "Esperar proxima ronda"
    rows: list[dict[str, Any]] = []
    for symbol in selected_symbols:
        href = f"?view=Activo&symbol={quote(str(symbol).upper(), safe='')}&market=crypto&tf=1m"
        try:
            frame = fetch_crypto_history_fast(str(symbol), timeframe="1m", limit=80)
        except Exception as exc:
            rows.append(
                {
                    "symbol": str(symbol).upper(),
                    "price": None,
                    "direction": "Esperar",
                    "strike": None,
                    "distance_pct": None,
                    "momentum_20m": None,
                    "momentum_5m": None,
                    "confidence": 0,
                    "action": "Sin datos 1m",
                    "risk_dollars": risk_budget,
                    "source": f"crypto_1m_error:{type(exc).__name__}",
                    "expires_at": expires_at.strftime("%H:%M UTC"),
                    "minutes_to_expiry": minutes_to_expiry,
                    "timer_state": timer_state,
                    "next_step": "No operar 20m hasta recibir velas 1m frescas.",
                    "tone": "avoid",
                    "href": href,
                }
            )
            continue
        if not isinstance(frame, pd.DataFrame) or frame.empty or "close" not in frame.columns:
            rows.append(
                {
                    "symbol": str(symbol).upper(),
                    "price": None,
                    "direction": "Esperar",
                    "strike": None,
                    "distance_pct": None,
                    "momentum_20m": None,
                    "momentum_5m": None,
                    "confidence": 0,
                    "action": "Sin velas 1m",
                    "risk_dollars": risk_budget,
                    "source": "crypto_1m_empty",
                    "expires_at": expires_at.strftime("%H:%M UTC"),
                    "minutes_to_expiry": minutes_to_expiry,
                    "timer_state": timer_state,
                    "next_step": "No operar 20m hasta tener precio y velas 1m.",
                    "tone": "avoid",
                    "href": href,
                }
            )
            continue

        data = frame.copy().tail(80)
        for column in ("open", "high", "low", "close", "volume"):
            if column in data.columns:
                data[column] = pd.to_numeric(data[column], errors="coerce")
        data = data.dropna(subset=["close"])
        price = safe_float(data["close"].iloc[-1]) if not data.empty else None
        if price is None or price <= 0 or len(data) < 24:
            rows.append(
                {
                    "symbol": str(symbol).upper(),
                    "price": price,
                    "direction": "Esperar",
                    "strike": None,
                    "distance_pct": None,
                    "momentum_20m": None,
                    "momentum_5m": None,
                    "confidence": 0,
                    "action": "Historial corto",
                    "risk_dollars": risk_budget,
                    "source": "crypto_1m_insufficient",
                    "expires_at": expires_at.strftime("%H:%M UTC"),
                    "minutes_to_expiry": minutes_to_expiry,
                    "timer_state": timer_state,
                    "next_step": "Esperar mas velas 1m antes de decidir arriba/abajo.",
                    "tone": "watch",
                    "href": href,
                }
            )
            continue

        close = data["close"]
        prior = safe_float(close.iloc[-21]) if len(close) >= 21 else safe_float(close.iloc[0])
        prior_5m = safe_float(close.iloc[-6]) if len(close) >= 6 else safe_float(close.iloc[0])
        momentum_20m = ((price / prior) - 1.0) if prior else 0.0
        momentum_5m = ((price / prior_5m) - 1.0) if prior_5m else 0.0
        sma9 = safe_float(close.tail(9).mean()) or price
        sma20 = safe_float(close.tail(20).mean()) or price
        returns = close.pct_change().replace([float("inf"), float("-inf")], pd.NA).dropna()
        minute_vol = safe_float(returns.tail(20).std()) or 0.001
        expected_move_pct = min(0.018, max(0.0015, minute_vol * math.sqrt(20)))
        strike_gap = min(0.012, max(0.0015, expected_move_pct * 0.55))
        bullish_confirmed = momentum_20m > 0.0005 and momentum_5m > 0.0002 and price >= sma9 >= sma20
        bearish_confirmed = momentum_20m < -0.0005 and momentum_5m < -0.0002 and price <= sma9 <= sma20
        if bullish_confirmed:
            direction = "Arriba"
        elif bearish_confirmed:
            direction = "Abajo"
        else:
            direction = "Esperar"
        if direction == "Arriba":
            strike = price * (1.0 + strike_gap)
            trend_ok = bullish_confirmed
        elif direction == "Abajo":
            strike = price * (1.0 - strike_gap)
            trend_ok = bearish_confirmed
        else:
            strike = price * (1.0 + strike_gap if momentum_5m >= 0 else 1.0 - strike_gap)
            trend_ok = False
        distance_pct = abs(strike - price) / price
        momentum_aligned = (direction == "Arriba" and momentum_20m > 0) or (direction == "Abajo" and momentum_20m < 0)
        edge_ratio = expected_move_pct / distance_pct if distance_pct else 0.0
        confidence = 35
        confidence += 20 if trend_ok else 0
        confidence += 16 if momentum_aligned and direction != "Esperar" else 0
        confidence += 14 if edge_ratio >= 1.35 else (6 if edge_ratio >= 1.0 else 0)
        confidence += min(12, abs(momentum_20m) * 1200)
        confidence += 6 if 8.0 <= minutes_to_expiry <= 18.5 else -18
        confidence = int(min(92, max(0, round(confidence))))
        timer_ok = timer_state == "Ventana valida"
        ready = direction != "Esperar" and trend_ok and momentum_aligned and edge_ratio >= 1.1 and timer_ok
        tone = "buy" if ready and confidence >= 78 else ("watch" if confidence >= 58 else "avoid")
        action = "Paper SI 20m" if tone == "buy" else ("Vigilar 20m" if tone == "watch" else "No operar 20m")
        if not timer_ok:
            action = "Esperar timer"
            tone = "watch"
            next_step = (
                f"No entrar ahora: quedan {num_display(minutes_to_expiry, 1)} min para el cierre. "
                "Evaluar al inicio de la proxima ronda :00/:20/:40."
            )
        elif direction == "Esperar":
            next_step = "No operar 20m: 20m y 5m no estan alineados con medias; esperar confirmacion clara."
        else:
            next_step = (
                f"Solo paper/manual: {direction.lower()} de {price_display(strike)} antes de {expires_at.strftime('%H:%M UTC')}; "
                "confirmar spread y liquidez antes de arriesgar."
            )
        rows.append(
            {
                "symbol": str(symbol).upper(),
                "price": price,
                "direction": direction,
                "strike": strike,
                "distance_pct": distance_pct,
                "momentum_20m": momentum_20m,
                "momentum_5m": momentum_5m,
                "confidence": confidence,
                "action": action,
                "risk_dollars": risk_budget,
                "source": "crypto_1m_ohlcv",
                "expires_at": expires_at.strftime("%H:%M UTC"),
                "minutes_to_expiry": minutes_to_expiry,
                "timer_state": timer_state,
                "next_step": next_step,
                "tone": tone,
                "href": href,
            }
        )
    return pd.DataFrame(rows, columns=columns).sort_values("confidence", ascending=False).reset_index(drop=True)


def render_crypto_twenty_min_strike_panel(
    *,
    account_equity: float,
    risk_pct: float,
    symbols: list[str] | tuple[str, ...] | None = None,
) -> None:
    rows = crypto_twenty_min_strike_rows(
        account_equity=account_equity,
        risk_pct=risk_pct,
        symbols=symbols,
        limit=4,
    )
    if rows.empty:
        return
    cards: list[str] = []
    for row in rows.to_dict("records"):
        tone = text_display(row.get("tone"))
        if tone not in {"buy", "watch", "avoid"}:
            tone = "watch"
        cards.append(
            f'<article class="strike20-card strike20-{html.escape(tone)}">'
            f'<header><a href="{html.escape(text_display(row.get("href")))}">{html.escape(text_display(row.get("symbol")))}</a>'
            f'<span>{html.escape(text_display(row.get("expires_at")))}</span></header>'
            f'<strong>{html.escape(text_display(row.get("action")))}</strong>'
            f'<p>{html.escape(text_display(row.get("direction")))} de <b>{html.escape(price_display(row.get("strike")))}</b> en 20 min</p>'
            '<div class="strike20-metrics">'
            f'<b><small>Ahora</small>{html.escape(price_display(row.get("price")))}</b>'
            f'<b><small>Distancia</small>{html.escape(pct_display(row.get("distance_pct")))}</b>'
            f'<b><small>Mom. 20m</small>{html.escape(pct_display(row.get("momentum_20m")))}</b>'
            f'<b><small>Mom. 5m</small>{html.escape(pct_display(row.get("momentum_5m")))}</b>'
            f'<b><small>Timer</small>{html.escape(num_display(row.get("minutes_to_expiry"), 1))}m</b>'
            f'<b><small>Conf.</small>{html.escape(num_display(row.get("confidence"), 0))}/100</b>'
            "</div>"
            f'<small>{html.escape(text_display(row.get("timer_state")))}</small>'
            f'<em>{html.escape(text_display(row.get("next_step"))[:160])}</em>'
            f'<a class="budget-chart-link" href="{html.escape(text_display(row.get("href")))}">Cargar en graficas</a>'
            "</article>"
        )
    st.markdown(
        '<section class="strike20-panel">'
        '<header><strong>Crypto 20min</strong><span>Simulacion paper/manual · no coloca orden real · no es garantia</span></header>'
        f'<div class="strike20-grid">{"".join(cards)}</div>'
        "</section>",
        unsafe_allow_html=True,
    )


def budget_trade_plan_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "action",
        "product",
        "qty",
        "entry",
        "stop",
        "target_1",
        "target_2",
        "risk_dollars",
        "reward_1_dollars",
        "reward_2_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "quality_label",
        "quality_reasons",
        "verdict",
        "next_step",
        "href",
    ]
    filtered = budget_filtered_opportunity_table(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if filtered.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for item in filtered.to_dict("records"):
        symbol = text_display(item.get("symbol")).upper()
        market = normalize_command_market(item.get("market"), symbol)
        tf = text_display(item.get("timeframe") or item.get("tf") or "1h")
        status = trade_decision_card_status(item)
        budget = opportunity_budget_fit(item, account_equity=account_equity, risk_pct=risk_pct)
        expectancy = budget_expectancy_status(item, account_equity=account_equity, risk_pct=risk_pct)
        stage = budget_execution_stage(expectancy)
        entry = safe_float(status.get("entry"))
        target_1 = safe_float(status.get("target_2"))
        target_2 = safe_float(status.get("target_5") or status.get("target_10"))
        units = safe_float(budget.get("units"))
        reward_1 = safe_float(budget.get("reward_2_dollars"))
        reward_2 = None
        if entry and target_2 and units:
            reward_2 = max(0.0, target_2 - entry) * units
        expected_r = safe_float(expectancy.get("expected_r"))
        allowed = bool(budget.get("allowed"))
        if allowed and expected_r is not None and expected_r > 0.35 and status.get("action") != "No operar":
            verdict = "Vale la pena vigilar/ejecutar paper si confirma."
        elif allowed and expected_r is not None and expected_r > 0:
            verdict = "Solo si mejora entrada o confirma volumen."
        else:
            verdict = "No vale la pena con este capital ahora."
        rows.append(
            {
                "symbol": symbol,
                "stage": stage["code"],
                "stage_label": stage["label"],
                "stage_tone": stage["tone"],
                "stage_reason": stage["reason"],
                "action": text_display(status.get("action")),
                "product": text_display(budget.get("recommendation")),
                "qty": units,
                "entry": entry,
                "stop": safe_float(status.get("stop")),
                "target_1": target_1,
                "target_2": target_2,
                "risk_dollars": safe_float(budget.get("risk_dollars")),
                "reward_1_dollars": reward_1,
                "reward_2_dollars": reward_2,
                "win_probability": safe_float(expectancy.get("win_probability")),
                "expected_r": expected_r,
                "expected_value": safe_float(expectancy.get("expected_value")),
                "quality_label": text_display(expectancy.get("quality_label")),
                "quality_reasons": " · ".join(text_display(reason) for reason in expectancy.get("quality_reasons") or []),
                "verdict": verdict,
                "next_step": text_display(budget.get("next_step") or status.get("next_step")),
                "href": f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market, safe='')}&tf={quote(tf, safe='')}",
            }
        )
    return pd.DataFrame(rows, columns=columns)


def budget_top_trade_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> pd.DataFrame:
    columns = [
        "rank",
        "rank_label",
        "symbol",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "action",
        "product",
        "qty",
        "entry",
        "stop",
        "target_1",
        "risk_dollars",
        "reward_1_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "quality_label",
        "quality_reasons",
        "verdict",
        "next_step",
        "href",
    ]
    rows = budget_trade_plan_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if rows.empty:
        return pd.DataFrame(columns=columns)
    rows = rows.copy()
    rows["_stage_sort"] = rows["stage"].map(BUDGET_STAGE_ORDER).fillna(9)
    rows["_expected_sort"] = pd.to_numeric(rows["expected_value"], errors="coerce").fillna(-999)
    rows["_prob_sort"] = pd.to_numeric(rows["win_probability"], errors="coerce").fillna(0)
    output = (
        rows.sort_values(["_stage_sort", "_expected_sort", "_prob_sort"], ascending=[True, False, False])
        .drop(columns=["_stage_sort", "_expected_sort", "_prob_sort"])
        .head(max(1, int(max_trades or 3)))
        .copy()
    )
    labels = ["Mejor oportunidad", "Alternativa", "Solo si confirma"]
    output.insert(0, "rank", range(1, len(output) + 1))
    output.insert(1, "rank_label", [labels[idx] if idx < len(labels) else "Vigilar" for idx in range(len(output))])
    return output.reindex(columns=columns)


def render_budget_top_trades_panel(
    table: pd.DataFrame,
    *,
    account_equity: float,
    risk_pct: float,
    market_scope: str,
    max_trades: int,
) -> None:
    rows = budget_top_trade_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=min(3, max(1, int(max_trades or 3))),
    )
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    if rows.empty:
        st.markdown(
            '<section class="budget-top-panel budget-top-empty compact-empty-budget">'
            f'<header><strong>Sin entrada lista para tu presupuesto</strong><span>${account_equity:,.0f} capital · 1R ${risk_budget:,.2f} · paper/manual</span></header>'
            '<div><article class="budget-empty-card">'
            '<b>Esperar</b>'
            '<p>No hay setup con precio, stop, target, liquidez y frescura suficientes ahora.</p>'
            '<small>Roxy sigue escaneando. No arriesga capital hasta tener entrada y stop medibles.</small>'
            '</article></div>'
            "</section>",
            unsafe_allow_html=True,
        )
        return
    cards = []
    for row in rows.to_dict("records"):
        rank = int(row.get("rank") or 0)
        tone = text_display(row.get("stage_tone"))
        if tone == "-":
            tone = "buy" if rank == 1 and safe_float(row.get("expected_r")) and safe_float(row.get("expected_r")) > 0 else "watch"
        if "No vale" in text_display(row.get("verdict")):
            tone = "avoid"
        qty = safe_float(row.get("qty"))
        qty_text = f"{qty:.4f}" if qty is not None and qty < 1 else num_display(qty, 0)
        reasons = text_display(row.get("quality_reasons"))
        stage_label = text_display(row.get("stage_label"))
        stage_reason = text_display(row.get("stage_reason"))
        size_prefix = "Comprar" if stage_label == "Operar ahora" else "Plan"
        cards.append(
            f'<article class="budget-top-card budget-top-{html.escape(tone)}">'
            f'<span>#{rank} · {html.escape(text_display(row.get("rank_label")))}</span>'
            f'<a href="{html.escape(text_display(row.get("href")))}">{html.escape(text_display(row.get("symbol")).upper())}</a>'
            f'<b>{html.escape(stage_label)} · {html.escape(text_display(row.get("quality_label")))}</b>'
            f'<p>{html.escape(size_prefix)} {html.escape(qty_text)} · Entrada {html.escape(price_display(row.get("entry")))} · Stop {html.escape(price_display(row.get("stop")))} · T1 {html.escape(price_display(row.get("target_1")))}</p>'
            f'<em>Riesgo ${html.escape(num_display(row.get("risk_dollars"), 2))} · Gana T1 ${html.escape(num_display(row.get("reward_1_dollars"), 2))} · EV {html.escape(num_display(row.get("expected_value"), 2))} · Prob. {html.escape(pct_display(row.get("win_probability")))}</em>'
            f'<i>{html.escape((stage_reason if stage_reason != "-" else reasons if reasons != "-" else text_display(row.get("next_step")))[:128])}</i>'
            "</article>"
        )
    st.markdown(
        '<section class="budget-top-panel">'
        f'<header><strong>Top 3 para tu presupuesto</strong><span>${account_equity:,.0f} capital · 1R ${risk_budget:,.2f} · {html.escape(text_display(market_scope))} · paper/manual</span></header>'
        f'<div>{"".join(cards)}</div></section>',
        unsafe_allow_html=True,
    )


def record_budget_filtered_paper_candidates(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> dict[str, int]:
    result = {"stock": 0, "crypto": 0}
    filtered = budget_filtered_opportunity_table(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if not isinstance(filtered, pd.DataFrame) or filtered.empty:
        return result
    records = filtered.to_dict("records")
    stock_rows = [
        row
        for row in records
        if normalize_command_market(row.get("market"), text_display(row.get("symbol")).upper()) == "stock"
    ]
    crypto_rows = [
        row
        for row in records
        if normalize_command_market(row.get("market"), text_display(row.get("symbol")).upper()) == "crypto"
    ]
    if stock_rows:
        try:
            candidates = build_alpaca_paper_practice_candidates(
                pd.DataFrame(stock_rows),
                account_equity=account_equity,
                risk_pct=risk_pct,
                limit=len(stock_rows),
            )
            if not candidates.empty and "status" in candidates.columns:
                candidates = candidates[candidates["status"].astype(str).eq("READY_FOR_PAPER")].reset_index(drop=True)
            if not candidates.empty:
                record_alpaca_paper_practice_candidates(candidates)
                result["stock"] = len(candidates)
        except Exception:
            pass
    if crypto_rows:
        try:
            candidates = build_crypto_paper_practice_candidates(
                pd.DataFrame(crypto_rows),
                account_equity=account_equity,
                risk_pct=risk_pct,
                limit=len(crypto_rows),
            )
            if not candidates.empty and "status" in candidates.columns:
                candidates = candidates[candidates["status"].astype(str).eq("READY_FOR_PAPER")].reset_index(drop=True)
            if not candidates.empty:
                record_crypto_paper_practice_candidates(candidates)
                result["crypto"] = len(candidates)
        except Exception:
            pass
    return result


def render_budget_trade_plan_panel(
    table: pd.DataFrame,
    *,
    account_equity: float,
    risk_pct: float,
    market_scope: str,
    max_trades: int,
) -> None:
    rows = budget_trade_plan_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if rows.empty:
        return
    cards = []
    for row in rows.to_dict("records"):
        expected = safe_float(row.get("expected_value"))
        tone = text_display(row.get("stage_tone"))
        if tone == "-":
            tone = "buy" if expected is not None and expected > 0 else "watch"
        qty = safe_float(row.get("qty"))
        qty_text = f"{qty:.4f}" if qty is not None and qty < 1 else num_display(qty, 0)
        stage_label = text_display(row.get("stage_label"))
        size_label = "Comprar" if stage_label == "Operar ahora" else "Tamano plan"
        cards.append(
            f'<article class="budget-plan-card budget-plan-{html.escape(tone)}">'
            f'<header><a href="{html.escape(text_display(row.get("href")))}">{html.escape(text_display(row.get("symbol")))}</a><span>{html.escape(stage_label)}</span></header>'
            f'<div><b>{html.escape(size_label)}</b><strong>{html.escape(qty_text)} · {html.escape(text_display(row.get("product")))}</strong></div>'
            f'<div><b>Entrada</b><strong>{html.escape(price_display(row.get("entry")))}</strong></div>'
            f'<div><b>Stop</b><strong>{html.escape(price_display(row.get("stop")))}</strong></div>'
            f'<div><b>Target 1</b><strong>{html.escape(price_display(row.get("target_1")))}</strong></div>'
            f'<div><b>Target 2</b><strong>{html.escape(price_display(row.get("target_2")))}</strong></div>'
            f'<p>Pierdes max ${html.escape(num_display(row.get("risk_dollars"), 2))} · Ganas T1 ${html.escape(num_display(row.get("reward_1_dollars"), 2))} · EV ${html.escape(num_display(row.get("expected_value"), 2))}</p>'
            f'<em>{html.escape(text_display(row.get("verdict")))}</em>'
            f'<small>{html.escape((text_display(row.get("stage_reason")) if text_display(row.get("stage_reason")) != "-" else text_display(row.get("next_step")))[:132])}</small>'
            "</article>"
        )
    st.markdown(
        '<section class="budget-plan-panel">'
        f'<header><strong>Plan de trade por presupuesto</strong><span>{html.escape(text_display(market_scope))} · max {int(max_trades or 3)} trades/dia · paper/manual.</span></header>'
        f'<div>{"".join(cards)}</div></section>',
        unsafe_allow_html=True,
    )


def render_budget_market_cards(
    rows: pd.DataFrame,
    *,
    fallback_rows: pd.DataFrame,
    account_equity: float,
    risk_pct: float,
    market_label: str,
    market_scope: str,
) -> None:
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    cards: list[str] = []
    if isinstance(rows, pd.DataFrame) and not rows.empty:
        for row in rows.to_dict("records"):
            tone = text_display(row.get("stage_tone"))
            if tone not in {"buy", "watch", "avoid"}:
                tone = "watch"
            if "No vale" in text_display(row.get("verdict")):
                tone = "avoid"
            qty = safe_float(row.get("qty"))
            qty_text = f"{qty:.4f}" if qty is not None and qty < 1 else num_display(qty, 0)
            href = text_display(row.get("href"))
            strategy_label = budget_strategy_watch_label(row)
            strategy_reason = budget_strategy_watch_reason(row)
            cards.append(
                f'<article class="budget-market-card budget-market-{html.escape(tone)}">'
                f'<header><a href="{html.escape(href)}">{html.escape(text_display(row.get("symbol")).upper())}</a>'
                f'<span>{html.escape(strategy_label)}</span></header>'
                f'<p>{html.escape(strategy_reason)}</p>'
                '<div class="budget-market-metrics">'
                f'<b><small>Entrada</small>{html.escape(price_display(row.get("entry")))}</b>'
                f'<b><small>Stop</small>{html.escape(price_display(row.get("stop")))}</b>'
                f'<b><small>Target 1</small>{html.escape(price_display(row.get("target_1")))}</b>'
                f'<b><small>Riesgo</small>${html.escape(num_display(row.get("risk_dollars"), 2))}</b>'
                f'<b><small>Ganancia</small>${html.escape(num_display(row.get("reward_1_dollars"), 2))}</b>'
                f'<b><small>Tamano</small>{html.escape(qty_text)}</b>'
                "</div>"
                f'<em>{html.escape(text_display(row.get("verdict")))}</em>'
                f'<a class="budget-chart-link" href="{html.escape(href)}">Cargar en graficas</a>'
                "</article>"
            )
    elif isinstance(fallback_rows, pd.DataFrame) and not fallback_rows.empty:
        for row in fallback_rows.head(6).to_dict("records"):
            tone = text_display(row.get("stage_tone") or row.get("tone"))
            if tone not in {"buy", "watch", "avoid"}:
                tone = "watch"
            href = text_display(row.get("href"))
            is_watch_seed = bool(row.get("watch_seed"))
            strategy_label = "24/7" if is_watch_seed else budget_strategy_watch_label(row)
            strategy_reason = (
                f'{text_display(row.get("action"))} · {text_display(row.get("strategy"))}'
                if is_watch_seed
                else budget_strategy_watch_reason(row)
            )
            entry = safe_float(row.get("entry"))
            stop = safe_float(row.get("stop"))
            target_1 = safe_float(row.get("target_1"))
            has_operational_plan = is_watch_seed and entry is not None and stop is not None and target_1 is not None
            if has_operational_plan:
                qty = safe_float(row.get("qty"))
                qty_text = f"{qty:.6f}" if qty is not None and qty < 1 else num_display(qty, 2)
                metrics_html = (
                    '<div class="budget-market-metrics">'
                    f'<b><small>Entrada</small>{html.escape(price_display(entry))}</b>'
                    f'<b><small>Stop</small>{html.escape(price_display(stop))}</b>'
                    f'<b><small>Target 1</small>{html.escape(price_display(target_1))}</b>'
                    f'<b><small>Riesgo</small>${html.escape(num_display(row.get("risk_dollars"), 2))}</b>'
                    f'<b><small>Ganancia</small>${html.escape(num_display(row.get("reward_1_dollars"), 2))}</b>'
                    f'<b><small>Tamano</small>{html.escape(qty_text)}</b>'
                    "</div>"
                )
            elif is_watch_seed:
                metrics_html = (
                    '<div class="budget-market-metrics">'
                    '<b><small>Mercado</small>Crypto</b>'
                    f'<b><small>Estado</small>{html.escape(text_display(row.get("quality_label")))}</b>'
                    f'<b><small>1R</small>${html.escape(num_display(row.get("risk_dollars"), 2))}</b>'
                    f'<b><small>Setup</small>{html.escape(text_display(row.get("strategy")))}</b>'
                    f'<b><small>Fuente</small>{html.escape(text_display(row.get("price_source")))}</b>'
                    '<b><small>Fit</small>Esperar</b>'
                    "</div>"
                )
            else:
                metrics_html = (
                    '<div class="budget-market-metrics">'
                    f'<b><small>Score</small>{html.escape(num_display(row.get("budget_score"), 1))}</b>'
                    f'<b><small>EV</small>{html.escape(num_display(row.get("expected_value"), 2))}</b>'
                    f'<b><small>1R</small>${html.escape(num_display(row.get("risk_dollars"), 2))}</b>'
                    f'<b><small>2%</small>${html.escape(num_display(row.get("reward_2_dollars"), 2))}</b>'
                    f'<b><small>Prob.</small>{html.escape(pct_display(row.get("win_probability")))}</b>'
                    f'<b><small>Fit</small>{html.escape("Cabe" if bool(row.get("budget_allowed")) else "Vigilar")}</b>'
                    "</div>"
                )
            cards.append(
                f'<article class="budget-market-card budget-market-{html.escape(tone)}">'
                f'<header><a href="{html.escape(href)}">{html.escape(text_display(row.get("symbol")).upper())}</a>'
                f'<span>{html.escape(strategy_label)}</span></header>'
                f'<p>{html.escape(strategy_reason)}</p>'
                f'{metrics_html}'
                f'<em>{html.escape((text_display(row.get("verdict")) if has_operational_plan else text_display(row.get("next_step")))[:150])}</em>'
                f'<a class="budget-chart-link" href="{html.escape(href)}">Cargar en graficas</a>'
                "</article>"
            )
    if not cards:
        st.markdown(
            '<section class="budget-market-panel budget-market-empty">'
            f'<header><strong>{html.escape(market_label)}</strong><span>${account_equity:,.0f} capital · 1R ${risk_budget:,.2f}</span></header>'
            '<p>Sin candidatos en este mercado durante el scan actual. Roxy sigue buscando setups con entrada, stop, liquidez y target medible.</p>'
            "</section>",
            unsafe_allow_html=True,
        )
        return
    st.markdown(
        '<section class="budget-market-panel">'
        f'<header><strong>{html.escape(market_label)}</strong><span>${account_equity:,.0f} capital · 1R ${risk_budget:,.2f} · {html.escape(market_scope)} · toca ticker para cargar grafica</span></header>'
        f'<div class="budget-market-grid">{"".join(cards)}</div></section>',
        unsafe_allow_html=True,
    )


def render_budget_split_opportunities_panel(
    table: pd.DataFrame,
    *,
    account_equity: float,
    risk_pct: float,
    max_trades: int,
) -> None:
    if not isinstance(table, pd.DataFrame) or table.empty:
        st.info("Roxy todavia no recibio suficientes oportunidades para separar acciones y crypto por presupuesto.")
        return
    visible_limit = max(8, int(max_trades or 3) * 4)
    stock_rows = budget_trade_plan_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope="stock",
        max_trades=visible_limit,
    )
    crypto_rows = budget_trade_plan_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope="crypto",
        max_trades=visible_limit,
    )
    stock_fallback = (
        pd.DataFrame()
        if not stock_rows.empty
        else budget_wide_search_rows(
            table,
            account_equity=account_equity,
            risk_pct=risk_pct,
            market_scope="stock",
            limit=visible_limit,
        )
    )
    crypto_fallback = (
        pd.DataFrame()
        if not crypto_rows.empty
        else budget_wide_search_rows(
            table,
            account_equity=account_equity,
            risk_pct=risk_pct,
            market_scope="crypto",
            limit=visible_limit,
        )
    )
    if crypto_rows.empty and crypto_fallback.empty:
        crypto_fallback = default_crypto_budget_watch_rows(
            account_equity=account_equity,
            risk_pct=risk_pct,
            limit=visible_limit,
        )
    st.markdown("### Acciones disponibles para trabajar")
    st.caption("Separadas por mercado. Toca un ticker o 'Cargar en graficas' para abrir ese activo arriba.")
    render_budget_market_cards(
        stock_rows,
        fallback_rows=stock_fallback,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_label="Acciones",
        market_scope="Acciones",
    )
    st.markdown("### Criptomonedas disponibles para trabajar")
    render_budget_market_cards(
        crypto_rows,
        fallback_rows=crypto_fallback,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_label="Crypto 20min",
        market_scope="Crypto",
    )
    render_crypto_twenty_min_strike_panel(
        account_equity=account_equity,
        risk_pct=risk_pct,
    )


def small_account_learning_rows(
    alpaca_summary: pd.DataFrame | None = None,
    crypto_summary: pd.DataFrame | None = None,
    *,
    limit: int = 4,
) -> pd.DataFrame:
    columns = ["strategy", "market", "tracked", "hit_2_rate", "stop_rate", "tone", "tomorrow"]
    frames: list[pd.DataFrame] = []
    if alpaca_summary is None:
        try:
            alpaca_summary = summarize_alpaca_paper_practice(score_alpaca_paper_practice_journal(load_alpaca_paper_practice_journal()))
        except Exception:
            alpaca_summary = pd.DataFrame()
    if crypto_summary is None:
        try:
            crypto_summary = summarize_crypto_paper_practice(score_crypto_paper_practice_journal(load_crypto_paper_practice_journal()))
        except Exception:
            crypto_summary = pd.DataFrame()
    for market_label, frame in [("stock", alpaca_summary), ("crypto", crypto_summary)]:
        if isinstance(frame, pd.DataFrame) and not frame.empty:
            data = frame.copy()
            data["market"] = market_label
            frames.append(data)
    if not frames:
        return pd.DataFrame(columns=columns)
    combined = pd.concat(frames, ignore_index=True)
    rows: list[dict[str, Any]] = []
    for item in combined.to_dict("records"):
        tracked = int(safe_float(item.get("tracked")) or 0)
        hit_2 = safe_float(item.get("hit_2_rate") or item.get("hit_2pct_rate"))
        stop = safe_float(item.get("stop_rate"))
        if tracked < 3:
            tone = "watch"
            tomorrow = "Seguir midiendo antes de subir prioridad."
        elif (hit_2 or 0.0) >= 0.55 and (stop or 0.0) <= 0.35:
            tone = "buy"
            tomorrow = "Priorizar manana si cabe en presupuesto y confirma entrada."
        elif (stop or 0.0) >= 0.45:
            tone = "avoid"
            tomorrow = "Bajar prioridad; esperar entrada mas cerca del stop."
        else:
            tone = "watch"
            tomorrow = "Mantener en vigilancia hasta mas evidencia."
        rows.append(
            {
                "strategy": text_display(item.get("strategy_family") or item.get("strategy")),
                "market": text_display(item.get("market")),
                "tracked": tracked,
                "hit_2_rate": hit_2,
                "stop_rate": stop,
                "tone": tone,
                "tomorrow": tomorrow,
            }
        )
    output = pd.DataFrame(rows, columns=columns)
    output["tracked_sort"] = pd.to_numeric(output["tracked"], errors="coerce").fillna(0)
    output["hit_sort"] = pd.to_numeric(output["hit_2_rate"], errors="coerce").fillna(0)
    output["stop_sort"] = pd.to_numeric(output["stop_rate"], errors="coerce").fillna(1)
    return (
        output.sort_values(["tracked_sort", "hit_sort", "stop_sort"], ascending=[False, False, True])
        .head(limit)
        .drop(columns=["tracked_sort", "hit_sort", "stop_sort"])
        .reset_index(drop=True)
    )


def render_small_account_learning_panel() -> None:
    rows = small_account_learning_rows(limit=4)
    if rows.empty:
        st.caption("Aprendizaje por resultado: todavia falta memoria paper suficiente para decir que setups priorizar manana.")
        return
    cards = []
