def roxy_crypto20_rows(table: pd.DataFrame, *, limit: int = 8) -> list[dict[str, Any]]:
    wanted = ["BTC/USD", "ETH/USD", "SOL/USD", "XRP/USD", "BNB/USD"]
    source_rows = roxy_asset_rows_for_market(table, "crypto", limit=max(limit, 12))
    by_base: dict[str, dict[str, Any]] = {}
    for row in source_rows:
        base = roxy_crypto_base_symbol(text_display(row.get("symbol")).upper())
        if base and base not in by_base:
            by_base[base] = row
    for symbol in wanted:
        base = roxy_crypto_base_symbol(symbol)
        if base in by_base:
            continue
        by_base[base] = (
            {
                "symbol": symbol,
                "market": "crypto",
                "current_price": None,
                "entry": None,
                "stop": None,
                "target_price": None,
                "risk_pct": None,
                "signal": "WATCH",
                "action": "Vigilar",
                "decision": "WAIT",
                "strategy_family": "Esperando confirmacion de Roxy",
                "por_que": "Abre la grafica para que Roxy recalcule velas, indicadores y recomendacion.",
                "readiness": 0,
            }
        )
    rows: list[dict[str, Any]] = []
    seen: set[str] = set()
    for symbol in wanted:
        base = roxy_crypto_base_symbol(symbol)
        row = by_base.get(base)
        row_symbol = text_display(row.get("symbol") if row else symbol).upper()
        if row and row_symbol not in seen:
            rows.append(row)
            seen.add(row_symbol)
    for row in source_rows:
        symbol = text_display(row.get("symbol")).upper()
        if symbol and symbol not in seen:
            rows.append(row)
            seen.add(symbol)
        if len(rows) >= limit:
            break
    return rows[:limit]


def roxy_actions_sparkline_svg(symbol: str, market: str = "stock") -> str:
    try:
        spark_df = cached_trade_desk_chart_df(resolve_symbol_query(symbol, market), market, "1h")
    except Exception:
        spark_df = pd.DataFrame()
    values: list[float] = []
    if isinstance(spark_df, pd.DataFrame) and not spark_df.empty and "close" in spark_df.columns:
        closes = pd.to_numeric(spark_df["close"], errors="coerce").dropna().tail(24)
        values = [float(value) for value in closes.tolist()]
    if len(values) < 4:
        base = abs(sum(ord(ch) for ch in text_display(symbol))) % 9
        values = [10 + base, 11 + base, 10.5 + base, 12 + base, 12.8 + base, 12.2 + base, 13.8 + base]
    min_value, max_value = min(values), max(values)
    span = max(max_value - min_value, 0.0001)
    points = []
    for idx, value in enumerate(values):
        x = 4 + (idx / max(len(values) - 1, 1)) * 74
        y = 31 - ((value - min_value) / span) * 24
        points.append(f"{x:.1f},{y:.1f}")
    latest_up = values[-1] >= values[0]
    stroke = "#22c55e" if latest_up else "#ef4444"
    return (
        '<svg class="roxy-actions-sparkline" viewBox="0 0 82 36" preserveAspectRatio="none" aria-hidden="true">'
        '<path d="M4 30H78 M4 20H78 M4 10H78" stroke="#7dd3fc" stroke-opacity=".10" stroke-width="1"/>'
        f'<polyline points="{" ".join(points)}" fill="none" stroke="{stroke}" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"/>'
        f'<circle cx="{points[-1].split(",")[0]}" cy="{points[-1].split(",")[1]}" r="2.5" fill="{stroke}"/>'
        "</svg>"
    )


def roxy_crypto_ccxt_symbol_candidates(symbol: str) -> list[str]:
    raw = text_display(symbol).strip().upper().replace("-", "/")
    base = roxy_crypto_base_symbol(raw)
    quote = raw.split("/", 1)[1] if "/" in raw else "USD"
    candidates = []
    for candidate_quote in (quote, "USD", "USDT", "USDC"):
        if base and candidate_quote:
            candidates.append(f"{base}/{candidate_quote}")
    return list(dict.fromkeys(candidates))


@st.cache_data(ttl=5, show_spinner=False)
def roxy_crypto_history_for_signal(symbol: str, timeframe: str, limit: int = 180) -> pd.DataFrame:
    for candidate in roxy_crypto_ccxt_symbol_candidates(symbol):
        try:
            frame = fetch_crypto_history_fast(candidate, timeframe=timeframe, limit=limit)
        except Exception:
            continue
        if isinstance(frame, pd.DataFrame) and not frame.empty and "close" in frame.columns:
            out = frame.copy()
            out["symbol_used"] = candidate
            return out
    return pd.DataFrame()


def roxy_crypto_cycle_window(kind: str, now: datetime | None = None) -> dict[str, Any]:
    current = now or datetime.now()
    normalized = text_display(kind).lower()
    if normalized == "20m":
        next_minute = ((current.minute // 20) + 1) * 20
        if next_minute >= 60:
            next_dt = current.replace(minute=0, second=0, microsecond=0) + timedelta(hours=1)
        else:
            next_dt = current.replace(minute=next_minute, second=0, microsecond=0)
        last_dt = next_dt - timedelta(minutes=20)
        cycle_seconds = 20 * 60
        mode = "mmss"
    elif normalized == "2h":
        anchor = current.replace(hour=0, minute=30, second=0, microsecond=0)
        while anchor <= current:
            anchor += timedelta(hours=2)
        next_dt = anchor
        last_dt = next_dt - timedelta(hours=2)
        cycle_seconds = 2 * 60 * 60
        mode = "hhmmss"
    else:
        next_dt = current.replace(hour=10, minute=30, second=0, microsecond=0)
        if next_dt <= current:
            next_dt += timedelta(days=1)
        last_dt = next_dt - timedelta(days=1)
        cycle_seconds = 24 * 60 * 60
        mode = "hhmmss"
    remaining = max(0, int((next_dt - current).total_seconds()))
    return {
        "now": current,
        "last": last_dt,
        "next": next_dt,
        "remaining": remaining,
        "countdown": f"{remaining // 60:02d}:{remaining % 60:02d}" if mode == "mmss" else f"{remaining // 3600:02d}:{(remaining % 3600) // 60:02d}:{remaining % 60:02d}",
        "mode": mode,
        "cycle_ms": cycle_seconds * 1000,
        "next_ts_ms": int(next_dt.timestamp() * 1000),
        "current_time_label": current.strftime("%I:%M %p").lstrip("0"),
        "last_time_label": last_dt.strftime("%I:%M %p").lstrip("0"),
        "next_time_label": next_dt.strftime("%I:%M %p").lstrip("0"),
        "next_day_label": "Hoy" if next_dt.date() == current.date() else f"Manana {next_dt.strftime('%I:%M %p').lstrip('0')}",
    }


def roxy_crypto_strategy_validation_from_data(
    data: pd.DataFrame,
    *,
    horizon_bars: int,
    ema_fast_span: int,
    ema_slow_span: int,
) -> dict[str, Any]:
    if not isinstance(data, pd.DataFrame) or data.empty or "close" not in data.columns:
        return {
            "sample_count": 0,
            "wins": 0,
            "losses": 0,
            "win_rate": None,
            "edge_pct": None,
            "avg_move_pct": None,
            "status": "insufficient",
            "label": "Validacion insuficiente",
        }
    close = pd.to_numeric(data["close"], errors="coerce").dropna().tail(260)
    if len(close) < max(55, horizon_bars * 3):
        return {
            "sample_count": 0,
            "wins": 0,
            "losses": 0,
            "win_rate": None,
            "edge_pct": None,
            "avg_move_pct": None,
            "status": "insufficient",
            "label": "Pocas velas para validar",
        }
    ema_fast = close.ewm(span=ema_fast_span, adjust=False).mean()
    ema_slow = close.ewm(span=ema_slow_span, adjust=False).mean()
    wins = 0
    losses = 0
    moves: list[float] = []
    start = max(ema_slow_span + 5, horizon_bars + 8)
    stop = len(close) - horizon_bars
    for idx in range(start, stop):
        price = safe_float(close.iloc[idx])
        if price is None or price <= 0:
            continue
        long_prior = safe_float(close.iloc[idx - horizon_bars])
        short_window = max(3, min(horizon_bars // 4, 8))
        short_prior = safe_float(close.iloc[max(0, idx - short_window)])
        fast_now = safe_float(ema_fast.iloc[idx]) or price
        slow_now = safe_float(ema_slow.iloc[idx]) or price
        if long_prior in (None, 0) or short_prior in (None, 0) or slow_now in (None, 0):
            continue
        returns = close.iloc[: idx + 1].pct_change().replace([float("inf"), float("-inf")], pd.NA).dropna()
        bar_vol = safe_float(returns.tail(max(20, horizon_bars)).std()) or 0.001
        expected_vol = min(0.18, max(0.001, bar_vol * math.sqrt(horizon_bars)))
        momentum = (price / long_prior) - 1.0
        short_momentum = (price / short_prior) - 1.0
        ema_spread = (fast_now / slow_now) - 1.0
        drift = (momentum * 0.50) + (short_momentum * 0.25) + (ema_spread * 0.25)
        max_projection = max(expected_vol * 1.45, 0.001)
        forecast_pct = max(-max_projection, min(max_projection, drift))
        threshold = max(0.00035, expected_vol * 0.18)
        if abs(forecast_pct) < threshold:
            continue
        side = "ABOVE" if forecast_pct > 0 else "BELOW"
        future = safe_float(close.iloc[idx + horizon_bars])
        if future is None or future <= 0:
            continue
        realized = (future / price) - 1.0
        moves.append(realized)
        if (side == "ABOVE" and future > price) or (side == "BELOW" and future < price):
            wins += 1
        else:
            losses += 1
    sample_count = wins + losses
    if sample_count <= 0:
        return {
            "sample_count": 0,
            "wins": 0,
            "losses": 0,
            "win_rate": None,
            "edge_pct": None,
            "avg_move_pct": None,
            "status": "insufficient",
            "label": "Sin senales historicas",
        }
    win_rate = wins / sample_count
    edge_pct = (win_rate - 0.50) * 100
    avg_move_pct = (sum(abs(item) for item in moves) / max(1, len(moves))) * 100
    if sample_count < 12:
        status = "insufficient"
        label = "Muestra insuficiente"
    elif win_rate >= 0.62:
        status = "validated"
        label = "Ventaja reciente validada"
    elif win_rate >= 0.54:
        status = "watch"
        label = "Ventaja moderada"
    else:
        status = "weak"
        label = "Sin ventaja reciente"
    return {
        "sample_count": sample_count,
        "wins": wins,
        "losses": losses,
        "win_rate": win_rate,
        "edge_pct": edge_pct,
        "avg_move_pct": avg_move_pct,
        "status": status,
        "label": label,
    }


@st.cache_data(ttl=5, show_spinner=False)
def roxy_crypto_horizon_signal(symbol: str, horizon: str) -> dict[str, Any]:
    profile = text_display(horizon).lower()
    if profile == "20m":
        timeframe, limit, horizon_bars, horizon_label = "1m", 140, 20, "20 minutos"
    elif profile == "2h":
        timeframe, limit, horizon_bars, horizon_label = "5m", 180, 24, "2 horas"
    else:
        timeframe, limit, horizon_bars, horizon_label = "1h", 220, 24, "daily"
    frame = roxy_crypto_history_for_signal(symbol, timeframe, limit)
    empty_result = {
        "symbol": text_display(symbol).upper(),
        "direction": "Esperar",
        "action": "Sin datos live",
        "tone": "watch",
        "price": None,
        "expected_price": None,
        "above_price": None,
        "below_price": None,
        "primary_side": "WAIT",
        "primary_label": "Esperar",
        "confidence": 0,
        "probability": 0,
        "forecast_pct": None,
        "momentum_pct": None,
        "short_momentum_pct": None,
        "volatility_pct": None,
        "entry_price": None,
        "target_price": None,
        "virtual_stop": None,
        "contract_side": "WAIT",
        "decision_state": "NO OPERAR",
        "decision_class": "avoid",
        "strength": 0,
        "reasons": ["Sin velas reales suficientes para validar una operacion."],
        "validation": {
            "sample_count": 0,
            "wins": 0,
            "losses": 0,
            "win_rate": None,
            "edge_pct": None,
            "avg_move_pct": None,
            "status": "insufficient",
            "label": "Validacion insuficiente",
        },
        "source": "sin_velas_crypto",
        "horizon_label": horizon_label,
        "next_step": "No operar hasta recibir velas reales del exchange.",
    }
    if not isinstance(frame, pd.DataFrame) or frame.empty or "close" not in frame.columns:
        return empty_result
    data = frame.copy()
    for column in ("open", "high", "low", "close", "volume"):
        if column in data.columns:
            data[column] = pd.to_numeric(data[column], errors="coerce")
    data = data.dropna(subset=["close"]).tail(limit)
    if len(data) < max(30, horizon_bars + 8):
        result = dict(empty_result)
        result.update({"source": "historial_crypto_corto", "next_step": "Esperar mas velas reales antes de decidir arriba/abajo."})
        return result
    close = data["close"]
    price = safe_float(close.iloc[-1])
    if price is None or price <= 0:
        result = dict(empty_result)
        result.update({"source": "precio_crypto_invalido"})
        return result
    ema_fast_span = 9 if profile == "20m" else (20 if profile == "2h" else 20)
    ema_slow_span = 21 if profile == "20m" else (40 if profile == "2h" else 50)
    ema_fast = close.ewm(span=ema_fast_span, adjust=False).mean()
    ema_slow = close.ewm(span=ema_slow_span, adjust=False).mean()
    ema_fast_now = safe_float(ema_fast.iloc[-1]) or price
    ema_slow_now = safe_float(ema_slow.iloc[-1]) or price
    ema_fast_prev = safe_float(ema_fast.iloc[-2]) if len(ema_fast) > 1 else ema_fast_now
    ema_slow_prev = safe_float(ema_slow.iloc[-2]) if len(ema_slow) > 1 else ema_slow_now
    crossed_up = bool(ema_fast_prev is not None and ema_slow_prev is not None and ema_fast_prev <= ema_slow_prev and ema_fast_now > ema_slow_now)
    crossed_down = bool(ema_fast_prev is not None and ema_slow_prev is not None and ema_fast_prev >= ema_slow_prev and ema_fast_now < ema_slow_now)
    volume_ratio = None
    if "volume" in data.columns:
        volume_series = pd.to_numeric(data["volume"], errors="coerce").dropna()
        if len(volume_series) >= 22:
            recent_volume = safe_float(volume_series.tail(3).mean())
            base_volume = safe_float(volume_series.tail(24).head(21).mean())
            if recent_volume is not None and base_volume not in (None, 0):
                volume_ratio = recent_volume / base_volume
    sma20 = close.rolling(20).mean()
    std20 = close.rolling(20).std()
    bb_width = ((sma20 + (std20 * 2)) - (sma20 - (std20 * 2))) / close.replace(0, pd.NA)
    bb_now = safe_float(bb_width.iloc[-1]) if len(bb_width.dropna()) else None
    bb_prev = safe_float(bb_width.dropna().iloc[-8]) if len(bb_width.dropna()) >= 8 else bb_now
    bb_expanding = bool(bb_now is not None and bb_prev is not None and bb_now > bb_prev * 1.05)
    long_prior = safe_float(close.iloc[-horizon_bars - 1]) if len(close) > horizon_bars else safe_float(close.iloc[0])
    short_window = max(3, min(horizon_bars // 4, 8))
    short_prior = safe_float(close.iloc[-short_window - 1]) if len(close) > short_window else safe_float(close.iloc[0])
    momentum = ((price / long_prior) - 1.0) if long_prior else 0.0
    short_momentum = ((price / short_prior) - 1.0) if short_prior else 0.0
    ema_spread = (ema_fast_now / (ema_slow_now or price) - 1.0)
    returns = close.pct_change().replace([float("inf"), float("-inf")], pd.NA).dropna()
    bar_vol = safe_float(returns.tail(max(20, horizon_bars)).std()) or 0.001
    expected_vol = min(0.18, max(0.001, bar_vol * math.sqrt(horizon_bars)))
    drift = (momentum * 0.50) + (short_momentum * 0.25) + (ema_spread * 0.25)
    max_projection = max(expected_vol * 1.45, 0.001)
    forecast_pct = max(-max_projection, min(max_projection, drift))
    if abs(forecast_pct) < max(0.00035, expected_vol * 0.18):
        primary_side = "WAIT"
        direction = "Esperar"
    elif forecast_pct > 0:
        primary_side = "ABOVE"
        direction = "Arriba"
    else:
        primary_side = "BELOW"
        direction = "Abajo"
    expected_price = price * (1.0 + forecast_pct)
    threshold_gap = max(price * 0.00035, abs(expected_price - price) * 0.48, price * expected_vol * 0.22)
    above_price = price + threshold_gap
    below_price = price - threshold_gap
    trend_aligned = (primary_side == "ABOVE" and price >= ema_fast_now >= ema_slow_now) or (
        primary_side == "BELOW" and price <= ema_fast_now <= ema_slow_now
    )
    edge = abs(forecast_pct) / expected_vol if expected_vol else 0.0
    validation = roxy_crypto_strategy_validation_from_data(
        data,
        horizon_bars=horizon_bars,
        ema_fast_span=ema_fast_span,
        ema_slow_span=ema_slow_span,
    )
    confidence = 42
    confidence += 20 if primary_side != "WAIT" else -8
    confidence += 15 if trend_aligned else 0
    confidence += 12 if (momentum > 0 and short_momentum > 0 and primary_side == "ABOVE") or (momentum < 0 and short_momentum < 0 and primary_side == "BELOW") else 0
    confidence += 10 if edge >= 0.85 else (4 if edge >= 0.55 else 0)
    validation_status = text_display(validation.get("status"))
    validation_win_rate = safe_float(validation.get("win_rate"))
    if validation_status == "validated":
        confidence += 8
    elif validation_status == "watch":
        confidence = min(confidence + 3, 72)
    elif validation_status == "weak":
        confidence = min(confidence - 18, 58)
    else:
        confidence = min(confidence, 56)
    confidence = int(max(0, min(92, round(confidence))))
    tone = "buy" if confidence >= 72 and primary_side != "WAIT" else ("watch" if confidence >= 54 else "avoid")
    if primary_side == "WAIT" or confidence < 50:
        decision_state = "NO OPERAR"
        decision_class = "avoid"
    elif confidence >= 74 and trend_aligned and validation_status == "validated":
        decision_state = "OPERAR AHORA"
        decision_class = "buy"
    else:
        decision_state = "ESPERAR CONFIRMACION"
        decision_class = "watch"
    contract_side = "YES" if primary_side == "ABOVE" else ("NO" if primary_side == "BELOW" else "WAIT")
    action = (
        f"Paper {direction} {horizon_label}"
        if tone == "buy"
        else (f"Vigilar {horizon_label}" if primary_side != "WAIT" else f"Esperar {horizon_label}")
    )
    if primary_side == "ABOVE":
        primary_label = f"Will be above {price_display(above_price)}"
        next_step = f"Solo paper/manual: arriba de {price_display(above_price)} en {horizon_label}; confirmar spread, liquidez y timer."
    elif primary_side == "BELOW":
        primary_label = f"Will be below {price_display(below_price)}"
        next_step = f"Solo paper/manual: abajo de {price_display(below_price)} en {horizon_label}; confirmar spread, liquidez y timer."
    else:
        primary_label = "Esperar confirmacion"
        next_step = "No operar: momentum, medias y volatilidad no dan ventaja suficiente ahora."
    target_price = above_price if primary_side == "ABOVE" else (below_price if primary_side == "BELOW" else expected_price)
    virtual_stop = below_price if primary_side == "ABOVE" else (above_price if primary_side == "BELOW" else None)
    reasons: list[str] = []
    if crossed_up:
        reasons.append(f"EMA{ema_fast_span} cruzo sobre EMA{ema_slow_span}.")
    elif crossed_down:
        reasons.append(f"EMA{ema_fast_span} cruzo debajo de EMA{ema_slow_span}.")
    elif trend_aligned:
        reasons.append(f"Precio alineado con EMA{ema_fast_span}/EMA{ema_slow_span}.")
    else:
        reasons.append(f"EMA{ema_fast_span}/EMA{ema_slow_span} aun no confirma completo.")
    if volume_ratio is not None:
        volume_delta = (volume_ratio - 1.0) * 100
        if volume_ratio >= 1.12:
            reasons.append(f"Volumen aumento {volume_delta:.0f}%.")
        elif volume_ratio <= 0.88:
            reasons.append(f"Volumen bajo {abs(volume_delta):.0f}%, requiere cautela.")
        else:
            reasons.append("Volumen estable, sin exceso de ruido.")
    else:
        reasons.append("Volumen live no disponible en este par.")
    if bb_expanding:
        reasons.append("Bollinger se esta expandiendo.")
    elif bb_now is not None:
        reasons.append("Bollinger estable, movimiento controlado.")
    if primary_side != "WAIT":
        reasons.append("Momentum positivo." if primary_side == "ABOVE" else "Momentum negativo controlado.")
    if trend_aligned and primary_side != "WAIT":
        reasons.append("Confirmacion completa con tendencia del timeframe.")
    else:
        reasons.append("Falta confirmacion completa en timeframe superior.")
    if validation_win_rate is not None and safe_float(validation.get("sample_count")):
        reasons.append(
            f"{text_display(validation.get('label'))}: {validation_win_rate * 100:.0f}% win rate en {int(safe_float(validation.get('sample_count')) or 0)} senales recientes."
        )
    else:
        reasons.append(f"{text_display(validation.get('label'))}: no hay muestra suficiente para activar entrada.")
    source_symbol = text_display(data["symbol_used"].iloc[-1]) if "symbol_used" in data.columns else roxy_crypto_ccxt_symbol_candidates(symbol)[0]
    return {
        "symbol": text_display(symbol).upper(),
        "direction": direction,
        "action": action,
        "tone": tone,
        "price": price,
        "expected_price": expected_price,
        "above_price": above_price,
        "below_price": below_price,
        "entry_price": price,
        "target_price": target_price,
        "virtual_stop": virtual_stop,
        "primary_side": primary_side,
        "primary_label": primary_label,
        "contract_side": contract_side,
        "decision_state": decision_state,
        "decision_class": decision_class,
        "strength": confidence,
        "reasons": reasons,
        "validation": validation,
        "confidence": confidence,
        "probability": confidence,
        "forecast_pct": forecast_pct,
        "momentum_pct": momentum,
        "short_momentum_pct": short_momentum,
        "volatility_pct": expected_vol,
        "source": f"BinanceUS {source_symbol} {timeframe}",
        "horizon_label": horizon_label,
        "next_step": next_step,
    }


def roxy_crypto_live_symbols_attr(symbol: str) -> str:
    candidates = binanceus_symbol_candidates(resolve_symbol_query(symbol, "crypto"))
    if not candidates:
        candidates = [candidate.replace("/", "") for candidate in roxy_crypto_ccxt_symbol_candidates(symbol)]
    return ",".join(dict.fromkeys(candidate.upper() for candidate in candidates if candidate))


def roxy_crypto_signal_reasons_html(signal: dict[str, Any]) -> str:
    reasons = signal.get("reasons")
    if not isinstance(reasons, list) or not reasons:
        reasons = [text_display(signal.get("next_step") or "Roxy espera mas confirmacion.")]
    return "".join(f"<li>{html.escape(text_display(reason))}</li>" for reason in reasons[:6])


def roxy_crypto_validation_summary(signal: dict[str, Any]) -> str:
    validation = signal.get("validation")
    if not isinstance(validation, dict):
        return "Validacion no disponible"
    label = text_display(validation.get("label") or "Validacion")
    sample_count = int(safe_float(validation.get("sample_count")) or 0)
    win_rate = safe_float(validation.get("win_rate"))
    if win_rate is None or sample_count <= 0:
        return f"{label} · sin muestra suficiente"
    return f"{label} · {win_rate * 100:.0f}% en {sample_count} senales"


def roxy_crypto_strength_stars(score: int | float | None) -> str:
    value = int(max(0, min(100, safe_float(score) or 0)))
    filled = min(5, max(0, round(value / 20)))
    return ("★" * filled) + ("☆" * (5 - filled))


def roxy_crypto_decision_icon(state: str) -> str:
    normalized = text_display(state).upper()
    if "OPERAR AHORA" in normalized:
        return "🟢"
    if "ESPERAR" in normalized:
        return "🟡"
    return "🔴"


def roxy_crypto_plan_values(signal: dict[str, Any], *, period_label: str, next_time_label: str) -> dict[str, str]:
    side = text_display(signal.get("primary_side") or "WAIT")
    direction = "ARRIBA" if side == "ABOVE" else ("ABAJO" if side == "BELOW" else "ESPERAR")
    state = text_display(signal.get("decision_state") or "NO OPERAR")
    score = int(max(0, min(100, safe_float(signal.get("strength") or signal.get("probability")) or 0)))
    return {
        "period": period_label,
        "direction": direction,
        "state": state,
        "state_icon": roxy_crypto_decision_icon(state),
        "state_class": text_display(signal.get("decision_class") or "avoid"),
        "entry": price_display(signal.get("entry_price") or signal.get("price")),
        "target": price_display(signal.get("target_price") or signal.get("expected_price")),
        "stop": price_display(signal.get("virtual_stop")),
        "confidence": f"{score}%",
        "strength": f"{score}/100",
        "stars": roxy_crypto_strength_stars(score),
        "contract": text_display(signal.get("contract_side") or "WAIT"),
        "next_time": next_time_label,
        "validation": roxy_crypto_validation_summary(signal),
    }


def roxy_enrich_crypto_rows_for_horizon(
    rows: list[dict[str, Any]],
    *,
    horizon: str,
    limit: int | None = None,
) -> list[dict[str, Any]]:
    enriched: list[dict[str, Any]] = []
    for idx, source_row in enumerate(rows):
        row = dict(source_row or {})
        symbol = text_display(row.get("symbol") or "").upper()
        if not symbol:
            continue
        resolved = resolve_symbol_query(symbol, "crypto")
        signal = roxy_crypto_horizon_signal(resolved, horizon)
        price = safe_float(signal.get("price") or row.get("current_price") or row.get("price") or row.get("last_price"))
        target = safe_float(signal.get("target_price") or signal.get("expected_price") or row.get("target_price") or row.get("target"))
        stop = safe_float(signal.get("virtual_stop") or row.get("stop") or row.get("stop_loss"))
        row.update(
            {
                "symbol": symbol,
                "market": "crypto",
                "current_price": price,
                "price": price,
                "last_price": price,
                "entry": safe_float(signal.get("entry_price")) or price,
                "target_price": target,
                "target": target,
                "stop": stop,
                "stop_loss": stop,
                "risk_pct": (abs((price or 0) - stop) / price) if price and stop else row.get("risk_pct"),
                "signal": text_display(signal.get("contract_side") or "WAIT"),
                "action": text_display(signal.get("action") or row.get("action") or "Vigilar"),
                "decision": text_display(signal.get("decision_state") or "NO OPERAR"),
                "decision_class": text_display(signal.get("decision_class") or "avoid"),
                "readiness": int(max(0, min(100, safe_float(signal.get("strength") or signal.get("probability")) or 0))),
                "roxy_signal": signal,
                "roxy_plan_source": text_display(signal.get("source") or "sin_fuente_crypto"),
                "roxy_validation": roxy_crypto_validation_summary(signal),
                "roxy_rank": idx,
            }
        )
        enriched.append(row)
    enriched.sort(
        key=lambda item: (
            0 if text_display(item.get("decision_class")) == "buy" else 1 if text_display(item.get("decision_class")) == "watch" else 2,
            -(safe_float(item.get("readiness")) or 0),
            int(safe_float(item.get("roxy_rank")) or 0),
        )
    )
    return enriched[:limit] if limit else enriched


