def render_focused_page_content(
    context: dict[str, Any],
    selected_page: str,
    *,
    home_controls: dict[str, Any] | None = None,
) -> None:
    scan_df = context.get("scan_df") if isinstance(context.get("scan_df"), pd.DataFrame) else pd.DataFrame()
    confluence_df = (
        context.get("confluence_df") if isinstance(context.get("confluence_df"), pd.DataFrame) else pd.DataFrame()
    )
    options_df = context.get("options_df") if isinstance(context.get("options_df"), pd.DataFrame) else pd.DataFrame()
    brief = context.get("brief") if isinstance(context.get("brief"), dict) else {}
    if selected_page is None:
        selected_page = render_focused_page_navigation()
    if selected_page == "Dashboard":
        if home_controls is None:
            show_focused_home(scan_df, confluence_df, options_df, brief)
        else:
            render_focused_home_live(scan_df, confluence_df, options_df, brief, home_controls)
    elif selected_page == "Activo":
        show_trade_plan_screen(scan_df, confluence_df, options_df, brief)
    elif selected_page == "Capital":
        show_million_plan_screen()
    elif selected_page == "Plataformas":
        show_platform_router_screen(brief)
    elif selected_page == "Opciones":
        show_options_screen(confluence_df, options_df, brief)
    elif selected_page == "Backtest":
        show_backtest_screen()
    elif selected_page == "Precision":
        show_accuracy_screen(brief)
    elif selected_page == "Estudios":
        show_strategy_study_center(scan_df, confluence_df, options_df, brief)
    elif selected_page == "Roxy IA":
        show_focused_ai_24h(brief)


def render_focused_live_workspace(realtime: dict[str, Any], *, selected_page: str | None = None) -> None:
    context = load_focused_live_context()
    render_focused_static_workspace(context, realtime)
    if selected_page is None:
        selected_page = render_focused_page_navigation()
    render_focused_page_content(context, selected_page)


def show_focused_roxy_app() -> None:
    show_focused_sidebar()
    realtime = configure_realtime_refresh()
    hydrate_focused_page_state(st.query_params, st.session_state, st.session_state.get("command_symbol", "AAPL"))
    selected_page = render_focused_page_navigation()
    st.session_state["roxy_last_selected_page"] = selected_page
    persist_focused_page_query_param()
    context = load_focused_live_context()
    if selected_page != "Dashboard":
        render_focused_static_workspace(context, realtime)
        if selected_page == "Activo":
            selected_symbol = text_display(
                st.session_state.get("command_symbol")
                or first_query_param_value(st.query_params, "symbol")
                or "AAPL"
            )
            selected_market = normalize_command_market(
                st.session_state.get("command_market") or first_query_param_value(st.query_params, "market"),
                selected_symbol,
            )
            live_price_contract = live_price_data_contract(cached_live_price_snapshot(selected_symbol, selected_market))
            with st.expander("Diagnostico de datos del activo", expanded=False):
                st.caption("Contrato de datos live para el activo seleccionado")
                st.markdown(render_chart_data_contract(live_price_contract), unsafe_allow_html=True)
                render_active_data_source_strip(live_price_contract)
                active_table = focused_opportunity_table(
                    context.get("brief") if isinstance(context.get("brief"), dict) else {}
                )
                active_rows = (
                    active_table[active_table["symbol"].astype(str).str.upper().eq(selected_symbol.upper())]
                    if not active_table.empty and "symbol" in active_table.columns
                    else pd.DataFrame()
                )
                active_decision = active_rows.iloc[0].to_dict() if not active_rows.empty else {
                    "symbol": selected_symbol,
                    "market": selected_market,
                    "live_price_contract": live_price_contract,
                }
                render_trade_decision_card(active_decision)
                render_alpaca_active_diagnostic(cached_alpaca_market_data_diagnostic(selected_symbol, selected_market))
                render_alert_live_panel(context.get("brief") if isinstance(context.get("brief"), dict) else {}, compact=True)
    home_controls = None
    if selected_page == "Dashboard":
        brief = context.get("brief") if isinstance(context.get("brief"), dict) else {}
        confluence_df = (
            context.get("confluence_df") if isinstance(context.get("confluence_df"), pd.DataFrame) else pd.DataFrame()
        )
        options_df = context.get("options_df") if isinstance(context.get("options_df"), pd.DataFrame) else pd.DataFrame()
        home_controls = render_command_center_controls(confluence_df, brief)
        if bool(home_controls.get("command_center_only")):
            return
        home_controls = {**home_controls, "defer_command_analysis": True, "suppress_budget_summary": True}
        run_every = f"{normalize_realtime_refresh_interval(realtime.get('interval_seconds'))}s"

        def _trade_desk_live_controls(live_context: dict[str, Any]) -> tuple[dict[str, Any], pd.DataFrame, pd.DataFrame, dict[str, Any]]:
            live_brief = live_context.get("brief") if isinstance(live_context.get("brief"), dict) else brief
            live_confluence_df = (
                live_context.get("confluence_df")
                if isinstance(live_context.get("confluence_df"), pd.DataFrame)
                else confluence_df
            )
            live_options_df = (
                live_context.get("options_df") if isinstance(live_context.get("options_df"), pd.DataFrame) else options_df
            )
            live_controls = {**home_controls, "best": focused_opportunity_table(live_brief)}
            return live_controls, live_confluence_df, live_options_df, live_brief

        def _render_trade_desk_static(live_context: dict[str, Any]) -> None:
            live_controls, live_confluence_df, live_options_df, live_brief = _trade_desk_live_controls(live_context)
            render_command_center_live_panel(
                live_confluence_df,
                live_options_df,
                live_brief,
                live_controls,
                show_spinner=False,
                render_side_panel=False,
                chart_interactive=True,
                render_secondary_charts=False,
                render_decision_panel=False,
            )

        def _render_trade_lanes(live_context: dict[str, Any]) -> None:
            live_controls, _live_confluence_df, _live_options_df, _live_brief = _trade_desk_live_controls(live_context)
            st.markdown("### Oportunidades que siguen la estrategia")
            st.caption(
                "Roxy muestra primero las candidatas que caben en tu capital, tienen entrada/stop/target medible "
                "y respetan el modo paper/manual. No coloca ordenes reales."
            )
            live_best = live_controls.get("best") if isinstance(live_controls, dict) else pd.DataFrame()
            live_equity = float(live_controls.get("account_equity") or 100.0)
            live_risk_pct = float(live_controls.get("risk_pct") or 0.01)
            live_scope = text_display(live_controls.get("budget_market_scope") or "Todos")
            live_max_trades = int(safe_float(live_controls.get("max_daily_trades")) or 3)
            selected_symbol = text_display(live_controls.get("symbol_input") or live_controls.get("default_symbol") or "")
            if not isinstance(live_best, pd.DataFrame) or live_best.empty:
                live_best = deploy_watchlist_opportunity_seed(
                    selected_symbol=selected_symbol,
                    market_scope=live_scope,
                    limit=max(10, live_max_trades * 5),
                )
            budget_live_best = budget_filtered_opportunity_table(
                live_best,
                account_equity=live_equity,
                risk_pct=live_risk_pct,
                market_scope=live_scope,
                max_trades=live_max_trades,
            )
            if (not isinstance(budget_live_best, pd.DataFrame) or budget_live_best.empty) and selected_symbol:
                seed_best = deploy_watchlist_opportunity_seed(
                    selected_symbol=selected_symbol,
                    market_scope=live_scope,
                    limit=max(10, live_max_trades * 5),
                )
                if isinstance(seed_best, pd.DataFrame) and not seed_best.empty:
                    live_best = (
                        pd.concat([live_best, seed_best], ignore_index=True)
                        .drop_duplicates(subset=["symbol", "market", "timeframe"], keep="first")
                        .reset_index(drop=True)
                    )
                    budget_live_best = budget_filtered_opportunity_table(
                        live_best,
                        account_equity=live_equity,
                        risk_pct=live_risk_pct,
                        market_scope=live_scope,
                        max_trades=live_max_trades,
                    )
            has_budget_candidates = isinstance(budget_live_best, pd.DataFrame) and not budget_live_best.empty
            record_budget_filtered_paper_candidates(
                budget_live_best if has_budget_candidates else pd.DataFrame(),
                account_equity=live_equity,
                risk_pct=live_risk_pct,
                market_scope=live_scope,
                max_trades=live_max_trades,
            )
            render_budget_split_opportunities_panel(
                live_best,
                account_equity=live_equity,
                risk_pct=live_risk_pct,
                max_trades=live_max_trades,
            )
            display_live_best = budget_live_best if has_budget_candidates else live_best
            with st.expander("Panel avanzado: ranking, memoria y diagnostico", expanded=False):
                render_priority_trade_lanes(display_live_best)
                render_opportunity_ranking_panel(
                    display_live_best,
                    account_equity=live_equity,
                    risk_pct=live_risk_pct,
                )
                render_budget_strategy_allocation_panel(
                    display_live_best,
                    account_equity=live_equity,
                    risk_pct=live_risk_pct,
                )
                render_budget_wide_search_panel(
                    live_best,
                    account_equity=live_equity,
                    risk_pct=live_risk_pct,
                    market_scope=live_scope,
                    max_trades=live_max_trades,
                )
                render_small_account_learning_panel()

        _render_trade_desk_static(context)
        if realtime.get("enabled") and hasattr(st, "fragment"):

            @st.fragment(run_every=run_every)
            def _live_trade_lanes() -> None:
                _render_trade_lanes(load_focused_live_context())

            _live_trade_lanes()
        else:
            _render_trade_lanes(context)
        with st.expander("Resumen operativo y decision actual", expanded=False):
            render_launch_operator_shell(brief, home_controls, realtime)
        with st.expander("Estado live, salud de mercado y diagnostico de lanzamiento", expanded=False):
            render_living_market_pulse(home_controls, realtime, compact=True)
            render_dashboard_compact_header(context, realtime)
    if selected_page != "Dashboard":
        render_focused_page_content(context, selected_page, home_controls=home_controls)
    if realtime.get("enabled") and hasattr(st, "fragment"):
        run_every = f"{normalize_realtime_refresh_interval(realtime.get('interval_seconds'))}s"

        @st.fragment(run_every=run_every)
        def _live_workspace() -> None:
            live_context = load_focused_live_context()
            live_selected_page = current_focused_page_state(
                st.query_params,
                st.session_state,
                st.session_state.get("command_symbol", "AAPL"),
            )
            if live_selected_page == "Dashboard":
                with st.expander("Pulso live y diagnostico tecnico", expanded=False):
                    render_living_market_pulse(home_controls, realtime, compact=True)
                    render_focused_live_status_workspace(live_context, realtime)
            else:
                render_focused_live_status_workspace(live_context, realtime)

        _live_workspace()
        return
    if selected_page == "Dashboard":
        with st.expander("Pulso live y diagnostico tecnico", expanded=False):
            render_focused_live_status_workspace(context, realtime)
    else:
        render_focused_live_status_workspace(context, realtime)


